-- Poems batch 140
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('490a20f4-0b48-4154-b89a-f8d8ce4835ad','臨安道中見壁間書字云由左行者爲四川驛路','項安世','宋','宋诗','song-poetry','','[]','只道成都路八千，誰知從此便西川。',32,'全唐诗/poet.song.146000.json','["只道成都路八千，誰知從此便西川。", "行人一見成深省，大道多歧穩著鞭。"]'),
('78897f1c-3161-4717-b1a6-5b711ea61c34','牡丹初開','項安世','宋','宋诗','song-poetry','','[]','東君環轍百花間，次第行春到牡丹。',32,'全唐诗/poet.song.146000.json','["東君環轍百花間，次第行春到牡丹。", "蜂嘴噆花春不覺，一枝先破紫金盤。"]'),
('7b361d04-422d-4a06-b036-3a308515d3ed','天申節錫宴戴花','項安世','宋','宋诗','song-poetry','','[]','泥金撚鐵綴花枝，淺白深紅映酒卮。',32,'全唐诗/poet.song.146000.json','["泥金撚鐵綴花枝，淺白深紅映酒卮。", "回首瓊林真一夢，插花還似去年時。"]'),
('216f672a-269b-4f25-b820-bc71f598a96b','行香退過南湖主人未起','項安世','宋','宋诗','song-poetry','','[]','夢裏敲門報五更，雨中行轎到天明。',32,'全唐诗/poet.song.146000.json','["夢裏敲門報五更，雨中行轎到天明。", "若爲得似張公子，卧聽穿林打葉聲。"]'),
('69450999-788f-4116-a8db-58bd40423705','晚荷','項安世','宋','宋诗','song-poetry','','[]','僛僛翠袖舞寒塘，無復當時婉婉妝。',32,'全唐诗/poet.song.146000.json','["僛僛翠袖舞寒塘，無復當時婉婉妝。", "蕩子遊娃俱不到，倚風摇月自生香。"]'),
('224db42e-0f40-4298-83a4-d052edbdf7da','留別南湖二首  其一','項安世','宋','宋诗','song-poetry','','[]','老夫夢識南湖路，水檻山堂處處通。',32,'全唐诗/poet.song.146000.json','["老夫夢識南湖路，水檻山堂處處通。", "若有新篇無告訴，不妨題寫寄江東。"]'),
('93ff1659-31bb-4908-96d3-3170cdc83764','留別南湖二首  其二','項安世','宋','宋诗','song-poetry','','[]','九重城裏塵如海，只有南湖一片霜。',32,'全唐诗/poet.song.146000.json','["九重城裏塵如海，只有南湖一片霜。", "若向南湖談世事，老夫只得去池陽。"]'),
('90d7d469-65ae-42a1-9150-5d492615d927','蘭溪道中二首  其一','項安世','宋','宋诗','song-poetry','','[]','征人頰熱共占霜，忽報冬溫是雨祥。',32,'全唐诗/poet.song.146000.json','["征人頰熱共占霜，忽報冬溫是雨祥。", "正向愁邊聞吉語，三霜兩假是尋常。"]'),
('fdf5b530-ea15-4ac8-9d74-bf995dadd2dc','蘭溪道中二首  其二','項安世','宋','宋诗','song-poetry','','[]','一夜清霜逗曉晴，桑林脫葉似灘聲。',32,'全唐诗/poet.song.146000.json','["一夜清霜逗曉晴，桑林脫葉似灘聲。", "雲邊恰有驚鴻過，直作灘頭細櫓鳴。"]'),
('b8e64d50-e916-4b4f-a4c3-288f910b6753','轎中聽雨','項安世','宋','宋诗','song-poetry','','[]','急雨淙琤打轎簷，綠荷聲裏下湖船。',32,'全唐诗/poet.song.146000.json','["急雨淙琤打轎簷，綠荷聲裏下湖船。", "時時更把山礬嗅，岩桂香中八月天。"]'),
('858298e8-dae2-4fc0-a58c-37730d1b7079','順風過湖二首  其一','項安世','宋','宋诗','song-poetry','','[]','帆影如酲左右傾，水聲似戰聒天鳴。',32,'全唐诗/poet.song.146000.json','["帆影如酲左右傾，水聲似戰聒天鳴。", "傍人只道船行快，不道船中客更驚。"]'),
('efd01968-65f6-4e00-853e-b9607a87ad9b','順風過湖二首  其二','項安世','宋','宋诗','song-poetry','','[]','維舟六日傍明山，待得風來始破顔。',32,'全唐诗/poet.song.146000.json','["維舟六日傍明山，待得風來始破顔。", "一抹平湖三十里，聽渠微橫未須關。"]'),
('ab1326ca-2208-45a6-9503-904fb69b7896','玄蝶','項安世','宋','宋诗','song-poetry','','[]','腰肢可愛紅娘子，面目無情黑老婆。',32,'全唐诗/poet.song.146000.json','["腰肢可愛紅娘子，面目無情黑老婆。", "世上但知憐少艾，雙雙飛舞奈渠何。"]'),
('aa1c1450-f3a0-4d1c-b524-769ab5c01977','入湖北界','項安世','宋','宋诗','song-poetry','','[]','丹楹白扁照人開，湖北封疆直面來。',32,'全唐诗/poet.song.146000.json','["丹楹白扁照人開，湖北封疆直面來。", "入得界頭歡喜倒，恰如身已到荆臺。"]'),
('aaac6286-c909-4a62-ba21-b68be1271ace','曹橋','項安世','宋','宋诗','song-poetry','','[]','聽得鳴鳩逐婦聲，行人相顧各心驚。',32,'全唐诗/poet.song.146000.json','["聽得鳴鳩逐婦聲，行人相顧各心驚。", "夜闌雲散天如洗，乞得曹橋一路晴。"]'),
('0854f587-0740-4aa0-b09f-341639a4b3fc','上鄂州黄鶴磯','項安世','宋','宋诗','song-poetry','','[]','黄鶴磯頭水似油，趙陀埽上石如鈎。',32,'全唐诗/poet.song.146000.json','["黄鶴磯頭水似油，趙陀埽上石如鈎。", "舟人上得休誇客，曾過人間百仞流。"]'),
('3b90ca5a-fb80-4cb9-a677-81fb69632a17','黄州赤壁下','項安世','宋','宋诗','song-poetry','','[]','杜牧談兵語未公，都將事業付東風。',32,'全唐诗/poet.song.146000.json','["杜牧談兵語未公，都將事業付東風。", "三江不見劉玄德，已覺曹瞞在掌中。"]'),
('9bf1fabc-e1d0-4920-ae4e-b2113b2e8a77','武陵江上漁舟','項安世','宋','宋诗','song-poetry','','[]','家居堤下土平簷，人在江中尺許船。',32,'全唐诗/poet.song.146000.json','["家居堤下土平簷，人在江中尺許船。", "正爾平生事方足，有人狂夢欲登仙。"]'),
('40ca3ce8-1ddb-4f3c-b7ae-8707fed6e835','次韻羅郢州送別','項安世','宋','宋诗','song-poetry','','[]','江上相留不肯留，渡江沿岸却回頭。',32,'全唐诗/poet.song.146000.json','["江上相留不肯留，渡江沿岸却回頭。", "漢江東去人西去，不見高城始是愁。"]'),
('f931a409-274d-4eac-a52c-e614eec18bf5','壕頭入衡山界','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','亂木林中微有路，兩山峽裏欲無天。',32,'全唐诗/poet.song.146000.json','["亂木林中微有路，兩山峽裏欲無天。", "前頭似向夔州去，應有西川未了緣。"]'),
('f3853936-5788-492f-a227-b9cb404948b5','次韻衡山徐監酒同考府學試八首  其一','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','詩裏無悰久自知，意來聊復寄於斯。',32,'全唐诗/poet.song.146000.json','["詩裏無悰久自知，意來聊復寄於斯。", "要知風節高多少，萬事如今總似詩。"]'),
('f9d31ce8-354c-482d-8975-d7290e57f200','次韻衡山徐監酒同考府學試八首  其二','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','少時亹亹著新功，老去蕭蕭漸禿翁。',32,'全唐诗/poet.song.146000.json','["少時亹亹著新功，老去蕭蕭漸禿翁。", "辜負平生好師友，納湖雲谷兩仁翁。"]'),
('62c695b4-bf9f-425d-bf15-9af8038b9d8c','次韻衡山徐監酒同考府學試八首  其三','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','世間無事可關心，只有豐年願最深。',32,'全唐诗/poet.song.146000.json','["世間無事可關心，只有豐年願最深。", "春旱惱人頭欲白，朝來一雨萬黄金。"]'),
('cec12148-5def-4bef-beea-51f9054a3d1f','次韻衡山徐監酒同考府學試八首  其四','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','欲濃還淡雲容碎，似見如藏日影微。',32,'全唐诗/poet.song.146000.json','["欲濃還淡雲容碎，似見如藏日影微。", "賺得鳩聲長又短，不知雨意是耶非。"]'),
('4d533d0a-cbd1-44ef-9b3f-2c9d52ac2744','次韻衡山徐監酒同考府學試八首  其五','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','燭灺燈枯夜漏殘，眼眵腰折吻聲乾。',32,'全唐诗/poet.song.146000.json','["燭灺燈枯夜漏殘，眼眵腰折吻聲乾。", "上床一覺江南夢，放艇高歌七里灘。"]'),
('badd6d7e-860a-47c3-96be-33adf1c09a9a','次韻衡山徐監酒同考府學試八首  其六','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南州門戶到雲來，猶有詩情出九垓。',32,'全唐诗/poet.song.146000.json','["南州門戶到雲來，猶有詩情出九垓。", "憐我風簾鑽故紙，借君月露洗黄埃。"]'),
('299906e2-7d7a-499b-a460-9d576b719709','次韻衡山徐監酒同考府學試八首  其七','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','夜久看書眼倍明，春來覓句思偏精。',32,'全唐诗/poet.song.146000.json','["夜久看書眼倍明，春來覓句思偏精。", "不嗔科舉遺佳士，更把時文教後生。"]'),
('015c8a44-040f-4eef-b0c9-d989770887e9','次韻衡山徐監酒同考府學試八首  其八','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','祝融峯下築糟邱，此段輸君第一流。',32,'全唐诗/poet.song.146000.json','["祝融峯下築糟邱，此段輸君第一流。", "誤到塵中踏塵土，却思江上駕漁舟。"]'),
('48e937d7-69be-4ecc-9b8f-1f3b51d89351','郢州道中見刺玫瑰花','項安世','宋','宋诗','song-poetry','','[]','酴釄雨後飄春雪，芍藥風前散晚霞。',32,'全唐诗/poet.song.146000.json','["酴釄雨後飄春雪，芍藥風前散晚霞。", "一路繁香伴行客，只應多謝刺玫花。"]'),
('14699bbd-4b56-4c88-8658-70aa149b6e02','二十三日阻雨鴨陂驛因寫道中詩寄羅郢州','項安世','宋','宋诗','song-poetry','','[]','橫吹逆洒斷人行，破驛孤眠又一程。',32,'全唐诗/poet.song.146000.json','["橫吹逆洒斷人行，破驛孤眠又一程。", "寫得吳箋寄長壽，無情風雨却多情。"]'),
('b2991615-2aac-43d1-9e46-83e36c1aeca9','善謔驛淳于髠墓上有木斜出口占','項安世','宋','宋诗','song-poetry','','[]','秦人磨斧闖山東，七澤青邱入夢中。',32,'全唐诗/poet.song.146000.json','["秦人磨斧闖山東，七澤青邱入夢中。", "齊楚君臣正行樂，辟宮除道送金籠。"]'),
('8c83c7f8-98b4-43e0-a81b-124223a6ce0c','題鹿門山絕頂升雲亭','項安世','宋','宋诗','song-poetry','','[]','上到山頭十八盤，貪高不計足心酸。',32,'全唐诗/poet.song.146000.json','["上到山頭十八盤，貪高不計足心酸。", "年來學力荒唐甚，羞向升雲頂上看。"]'),
('3b1d15ea-b352-469d-b1ee-d7b59714d31b','步上黄羆嶺','項安世','宋','宋诗','song-poetry','','[]','牛頭鶴弄漫虛傳，未抵黄羆路刺天。',32,'全唐诗/poet.song.146000.json','["牛頭鶴弄漫虛傳，未抵黄羆路刺天。", "曳杖徐行吾自樂，世間何地不平田。"]'),
('075eb333-cd47-4aa1-a112-6ef0c71b3980','入普州','項安世','宋','宋诗','song-poetry','','[]','過盡昌州無數山，山開地辟見平田。',32,'全唐诗/poet.song.146000.json','["過盡昌州無數山，山開地辟見平田。", "田中有麥元無米，比自昌州却可憐。"]'),
('db9d52dd-db71-4d70-a0cc-604744b5fc8b','七月二十日被檄考試出門  其一','項安世','宋','宋诗','song-poetry','','[]','阿婆少也不如人，更說秋來白髮新。',32,'全唐诗/poet.song.146000.json','["阿婆少也不如人，更說秋來白髮新。", "欲按新聲忘舊譜，畫鸞歌扇久生塵。"]'),
('b1b748a8-7cdd-4d5b-85ae-36a1b48d7a59','七月二十日被檄考試出門  其二','項安世','宋','宋诗','song-poetry','','[]','瓊林花底散遊鞭，回首長安十八年。',32,'全唐诗/poet.song.146000.json','["瓊林花底散遊鞭，回首長安十八年。", "羞把文章對年少，老夫衣缽不堪傳。"]'),
('919f6cfc-f50c-45d4-a355-434a98990d38','次韻黔陽王令論詩五絕句  其一','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭五百里巨浸，衡岳七十二高峯。',32,'全唐诗/poet.song.146000.json','["洞庭五百里巨浸，衡岳七十二高峯。", "不是公家椽樣筆，個中施手若爲容。"]'),
('fa9acec9-148e-41fb-a1cd-4124ad19be29','次韻黔陽王令論詩五絕句  其二','項安世','宋','宋诗','song-poetry','','[]','舊日輞川圖上翁，而今孫子尚家風。',32,'全唐诗/poet.song.146000.json','["舊日輞川圖上翁，而今孫子尚家風。", "如何寂寞黔陽去，五兩青綸一畝宮。"]'),
('7a20e196-1748-4d64-81a7-39a4d68ac4ee','次韻黔陽王令論詩五絕句  其三','項安世','宋','宋诗','song-poetry','','[]','驪珠一百二十六，落紙輕圓字字同。',32,'全唐诗/poet.song.146000.json','["驪珠一百二十六，落紙輕圓字字同。", "怪得春來全少雨，烟雲都在錦囊中。"]'),
('e3c7d840-17dd-4ba2-b8ae-d3414e4481b2','次韻黔陽王令論詩五絕句  其四','項安世','宋','宋诗','song-poetry','','[]','見說吟哦三十載，從來此事一生功。',32,'全唐诗/poet.song.146000.json','["見說吟哦三十載，從來此事一生功。", "勸君莫用雕鎸得，只恐今人晚更窮。"]'),
('b1453e42-c70c-41f6-a531-6726f0761dc2','次韻黔陽王令論詩五絕句  其五','項安世','宋','宋诗','song-poetry','','[]','我亦童年學露蛩，老來留眼送歸鴻。',32,'全唐诗/poet.song.146000.json','["我亦童年學露蛩，老來留眼送歸鴻。", "自從謝絕曹劉後，浩蕩春光滿太空。"]'),
('d55848b1-f467-481a-ba55-72e1701c961b','亭午熱甚過石子澗','項安世','宋','宋诗','song-poetry','','[]','一掬兒童數樹凉，兩三桅子野花香。',32,'全唐诗/poet.song.146000.json','["一掬兒童數樹凉，兩三桅子野花香。", "荒山赤日相逢處，便是天台見石梁。"]'),
('d0b1b6c6-1e90-4468-a119-87ef9e4c18f6','澗上居人','項安世','宋','宋诗','song-poetry','','[]','跨澗作橋兼作屋，行人初到已泠然。',32,'全唐诗/poet.song.146000.json','["跨澗作橋兼作屋，行人初到已泠然。", "全家寢食淙琤上，韶頀聲中過百年。"]'),
('b98f009f-f360-4cd4-ba0a-125c0e8112bf','四月五日解維成都連日行淺灘中或遲或速如在東中遊湖甚以爲樂初九日過龍爪灘兩江合流江始深舟人至此歌呼鳴櫓作發船離岸之聲余始愴然覺身是行客頗有離索之念','項安世','宋','宋诗','song-poetry','','[]','青林淺瀨密縈洄，喚作蘭亭載酒來。',32,'全唐诗/poet.song.146000.json','["青林淺瀨密縈洄，喚作蘭亭載酒來。", "忽聽江深發鳴櫓，始知身是罷官回。"]'),
('007f424f-cbda-4b3b-a145-39bd5a01c42f','峽內三絕句  其一','項安世','宋','宋诗','song-poetry','','[]','峽內爲生絕可憐，那知世上有平川。',32,'全唐诗/poet.song.146000.json','["峽內爲生絕可憐，那知世上有平川。", "生身未識三冬雪，仰面惟看一席天。"]'),
