('f2c4dcc6-73cb-4841-b160-f78efa67fdd6','荆江漁父竹枝詞九首和夔帥□侍郎韵爲荆帥范侍郎壽  其九','項安世','宋','宋诗','song-poetry','','[]','九歌漁父好思量，願得壽星朝帝鄉。',32,'全唐诗/poet.song.146000.json','["九歌漁父好思量，願得壽星朝帝鄉。", "壽十二廟寸關尺，演億萬年元蔀章。"]'),
('681e20f5-08f1-40dd-aadf-ceb8cee7fab7','盤居六章  其一','項安世','宋','宋诗','song-poetry','','[]','寶峰之陰，其山深深。',20,'全唐诗/poet.song.146000.json','["寶峰之陰，其山深深。", "有美一人，瓊弁玉簪。"]'),
('fbef05ed-6d5d-4e3e-a022-9cc46158d38a','盤居六章  其二','項安世','宋','宋诗','song-poetry','','[]','雲居之陽，其水洋洋。',20,'全唐诗/poet.song.146000.json','["雲居之陽，其水洋洋。", "有美一人，霞衣月裳。"]'),
('63fff20a-3a62-4c28-b800-f258bf6a576f','盤居六章  其三','項安世','宋','宋诗','song-poetry','','[]','山之紆紆，密雲所廬。',20,'全唐诗/poet.song.146000.json','["山之紆紆，密雲所廬。", "彼盤之人，亦豐厥儲。"]'),
('79c2bdfd-5f3c-49d9-bb23-89a37f178f62','盤居六章  其四','項安世','宋','宋诗','song-poetry','','[]','山之營營，衆流所經。',20,'全唐诗/poet.song.146000.json','["山之營營，衆流所經。", "彼盤之人，亦溥厥成。"]'),
('4b85971e-1e8e-4918-a278-17977a604b8f','盤居六章  其五','項安世','宋','宋诗','song-poetry','','[]','漸以中上，屯以正行。',20,'全唐诗/poet.song.146000.json','["漸以中上，屯以正行。", "匪盤之異，惟物之情。"]'),
('2b31aeaf-0b72-4402-b34b-15ee965e754f','盤居六章  其六','項安世','宋','宋诗','song-poetry','','[]','行止盤盤，其樂孔多。',20,'全唐诗/poet.song.146000.json','["行止盤盤，其樂孔多。", "請以是居，子如之何。"]'),
('4079b257-4604-4049-837b-6732318ed795','送鄭尚書罷帥歸福州','項安世','宋','宋诗','song-poetry','','[]','共惟漢從官，三仕屈吾指。',228,'全唐诗/poet.song.146000.json','["共惟漢從官，三仕屈吾指。", "前輩有鄭公，後來王趙耳。", "更生初去國，玉色欣共理。", "我時見一葉，已識秋風起。", "明年孔戣去，零落真復爾。", "王師凜孤鶴，獨叫青雲裏。", "下有萬伏弦，開雲看白雉。", "前年鄭公來，初論差可喜。", "謂當上聯璧，共舉漢綱紀。", "三年越山中，不使度此水。", "低頭用朱墨，得去真晚矣。", "况當少天官，風木赴淮涘。", "一時東都空，物理固如此。", "此行關世運，特可慰閭里。", "下有賢寓公，上有名刺史。", "想見閩父老，懽喜屐折齒。", "雖然廟朝舊，迹遠心自邇。", "公行見趙公，此語式舉似。", "有事當驛聞，毋忘漢天子。"]'),
('6d0950c2-deeb-4cb3-bf6a-186814b144c6','次韻儲檢法送行','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','別去動經年，相過但旬日。',120,'全唐诗/poet.song.146000.json','["別去動經年，相過但旬日。", "會心能幾何，歡意忽已失。", "何年峴山頭，此主復此客。", "官回便重到，我齒已半百。", "侍立四顔紅，豈有今日色。", "坐中六七子，星散那再得。", "念之意已動，况此真遠役。", "秋風洞庭岸，落日賈傅宅。", "主人九霄上，悵望雲雨隔。", "回首叫蒼梧，知予正愁寂。"]'),
('36212b0c-dbf2-422e-a83c-b94c047aa7a9','中秋不見月','項安世','宋','宋诗','song-poetry','','[]','重雲閟佳月，世謂天公慳。',120,'全唐诗/poet.song.146000.json','["重雲閟佳月，世謂天公慳。", "一年待一夕，一夕阻開顔。", "持此窺大爐，何如管中斑。", "兩輪駕宇宙，萬世浩相關。", "不知幾中秋，來往于其間。", "中間一晦明，瑣細不足刪。", "惟應一樽酒，慰此清夜閒。", "閒譏月姊懶，醉駡雲師頑。", "客去我自寐，悠然夢高攀。", "斫却婆娑林，永斷寒蟾跧。"]'),
('5b59891d-42ae-4b64-82b8-2ab0b9dd3e75','次韻謝資州侯巡撫','項安世','宋','宋诗','song-poetry','','[]','學道或五窮，談兵有三顧。',192,'全唐诗/poet.song.146000.json','["學道或五窮，談兵有三顧。", "人情市門朝，世態狙公暮。", "坐令直躬人，稍作折腰步。", "侯郎器如此，可使終不遇。", "奇文鏤周鼎，妙質反商輅。", "忽辭魯諸生，去學漢都護。", "應憐世高低，强逐時好惡。", "卞璞獻逾三，顔瓢空已屢。", "回看枝木冠，嘆息半生誤。", "一朝著戎服，萬里志橫騖。", "漢庭多巨公，文武且千數。", "胡爲滄海頭，有抱不往訴。", "投暗枉明璣，發蒙勞善喻。", "光芒隘蓬蓽，黼黻滿縑素。", "鵬扶會高舉，蜩翼安足附。", "似聞資水涯，已有鶴書赴。"]'),
('e5dd3d3e-2d63-4e1d-b2c6-deea1798dc2b','陶淵明醉石','項安世','宋','宋诗','song-poetry','','[]','石君匪招陶，陶子豈知石。',120,'全唐诗/poet.song.146000.json','["石君匪招陶，陶子豈知石。", "偶然一醉間，成此千年迹。", "當時素心人，鄰里今誰宅。", "悠然獨君在，入我晦翁室。", "翁去三十年，伊余復來客。", "山甿道之前，崖路久以塞。", "攀緣出藤蘿，指點見顱蹠。", "想當酣卧時，不記苔蘚泐。", "無論牛馬後，况說有刀尺。", "持盃薦寒泉，嘆息書此墨。"]'),
('4812aa9e-8989-4a69-8a7d-279023676b71','二十六日下山觀勝業寺禹柏偃卧地上分爲九枝','項安世','宋','宋诗','song-poetry','','[]','人言禹時柏，是否何必研。',132,'全唐诗/poet.song.146000.json','["人言禹時柏，是否何必研。", "要知是古物，少亦逾千年。", "盤盤九龍子，脊尾何蜿蜒。", "疎髯挾雷雨，瘦骨含風烟。", "居然負世望，淡苦依老禪。", "紛披苔蘚中，偃息魚鼓邊。", "不知億萬人，饑餓長呼天。", "我欲箋上帝，六丁呼使前。", "九龍分九州，各值所治田。", "膏澤皆要足，陰晴無敢愆。", "如此豈不善，天心應謂然。"]'),
('51aabc8e-a054-4345-9937-27dd1d8427b4','江陵爲瀏陽柳氏作雲山書院歌','項安世','宋','宋诗','song-poetry','','[]','山中何所有，雲氣長悠悠。',290,'全唐诗/poet.song.146000.json','["山中何所有，雲氣長悠悠。", "院中何所有，書冊滿高樓。", "登樓看雲復看書，千古萬古同卷舒。", "子於其間樂有餘，我今爲子言其粗。", "陰闔兮陽開，乾蓋兮坤輿。", "白衣兮皎皎，蒼狗兮須臾。", "崩騰兮龍見，消散兮尸居。", "如臂之屈伸，如足之疾徐。", "實理諒不昧，顯微同一初。", "呼吸爲雅頌，吁俞爲典謨。", "支支離離兮萬物散□，翕翕繹繹兮天地交孚。", "三百八十有四爻兮奇與耦，二百四十有二年兮褒與誅。", "目目自有條，葉葉自有株。", "子以爲一兮粲然而萬有，子以爲萬兮坦然而一途。", "吾是以見雲之書而書之雲，子又烏知書非雲而雲非書。", "以此壽子身，壯作老息神不枯。", "以此貽子後，博觀約守世不渝。", "大哉此院雲所儲，苟無其實名不虛。", "誰其任之非子歟，一翁二季相携扶。"]'),
('a99f16a5-9295-40c1-8de1-1780f495213d','題張以道寒綠軒','項安世','宋','宋诗','song-poetry','','[]','君家雪窗小溪曲，溪綠窗寒當家足。',192,'全唐诗/poet.song.146000.json','["君家雪窗小溪曲，溪綠窗寒當家足。", "如何拋却老師兄，別向天隨參杞菊。", "杞經言暖不言寒，菊譜聞黄未聞綠。", "君從何許得此奇，定是雪窗三十六。", "金英浮蟻我無分，玉犬吠根人所逐。", "只殘雨葉與風枝，給與詩人當田祿。", "困將冷艷洗眵眼，饑把芳鮮楦雷腹。", "招邀朋友最宜茶，犒設妻兒聊當肉。", "和軒喫却人不爭，吐出新詩更清穆。", "時時夢把密州印，千步毬場宴賓屬。", "吟魂正作蝴蝶飛，靜繞珍叢嘬寒玉。", "覺來拊几一欣然，何必窮閻減華屋。"]'),
('0adfd731-75f8-4e92-9347-c00a9cd2c9d6','自黄州赤壁拋過三江口危甚','項安世','宋','宋诗','song-poetry','','[]','直打磯頭上，橫拋江口開。',48,'全唐诗/poet.song.146000.json','["直打磯頭上，橫拋江口開。", "水將天共去，風與浪俱來。", "人壓船舷正，竿牽帆索回。", "長年誇好手，不道客心灰。"]'),
('729f8ecd-bbb3-492d-902a-c0c8f5954baf','送潭州陳運使二首  其一','項安世','宋','宋诗','song-poetry','','[]','薄命真如此，茲行如識公。',48,'全唐诗/poet.song.146000.json','["薄命真如此，茲行如識公。", "從來半生願，不畀數旬同。", "官事埋頭過，江舩轉眼空。", "可能傾蓋地，直作急流中。"]'),
('aa98d9ba-6f4b-4325-b7b1-5422d55a000f','送潭州陳運使二首  其二','項安世','宋','宋诗','song-poetry','','[]','惜分頻卜夜，此意我知公。',48,'全唐诗/poet.song.146000.json','["惜分頻卜夜，此意我知公。", "古事多疑信，今人足異同。", "何年操棐几，三月坐春風。", "但記匆匆字，深題大带中。"]'),
('7278b1d6-5722-465d-a00d-9c09521fef9e','瀝澗吳太皇廟','項安世','宋','宋诗','song-poetry','','[]','行間得子明，笑裏下茲城。',48,'全唐诗/poet.song.146000.json','["行間得子明，笑裏下茲城。", "好漢人難識，髯郎鑒獨精。", "溪巫薦村酒，舟子問江程。", "頗憶濡須否，風旛作戰聲。"]'),
('1bcecd28-49b1-4177-8b00-13e4bcfec299','小塘道中小雨二首  其一','項安世','宋','宋诗','song-poetry','','[]','元日暄如許，新春氣未齊。',48,'全唐诗/poet.song.146000.json','["元日暄如許，新春氣未齊。", "懸知當作雨，多謝不成泥。", "頭有高低坂，人如上下梯。", "更晴三四日，可以到湘西。"]'),
('136f529b-25ca-4a55-bfed-abdbd8c5e98b','小塘道中小雨二首  其二','項安世','宋','宋诗','song-poetry','','[]','隠隠輕雷動，昏昏野市迷。',48,'全唐诗/poet.song.146000.json','["隠隠輕雷動，昏昏野市迷。", "嫩雲時綻日，暖雨半含凄。", "時節新裝束，人家小鼓鼙。", "晚來扶路看，往往醉如泥。"]'),
('9885d511-5b24-4f9a-84d6-33a080544bc9','小雨','項安世','宋','宋诗','song-poetry','','[]','小雨散炎毒，微風生早秋。',48,'全唐诗/poet.song.146000.json','["小雨散炎毒，微風生早秋。", "清凉人意足，厭浥草光浮。", "夜枕夢新熟，曉窗梳不收。", "茅欄聽好語，香稻起西疇。"]'),
('e4315b2e-dc88-4f08-b554-7553e9f4423d','陳信民求詩','項安世','宋','宋诗','song-poetry','','[]','子合陳平甫，吾當項信求。',48,'全唐诗/poet.song.146000.json','["子合陳平甫，吾當項信求。", "食兵吾不媿，門轍子方貧。", "老眼觀斯世，多情尚若人。", "相過無遠近，元不計冬春。"]'),
('f652650f-5523-4e17-b80b-dd65c181a4e4','次韻鄭檢法與胡教授論詩','項安世','宋','宋诗','song-poetry','','[]','古詩亡狗曲，新樣入桑間。',48,'全唐诗/poet.song.146000.json','["古詩亡狗曲，新樣入桑間。", "論稍經坡谷，人方敬杜顔。", "天機轉杼軸，僧衲忌斕斑。", "妙處無多洩，從來造物慳。"]'),
('fa14ab73-9c10-4741-a700-d6b8f59b5f8c','謝張堯巨秀才惠詩','項安世','宋','宋诗','song-poetry','','[]','□□□□古，不要世人憐。',48,'全唐诗/poet.song.146000.json','["□□□□古，不要世人憐。", "碧甃千尋綆，朱緪五十絃。", "鼎來三影句，印脫一心傳。", "依約雲門路，寒馿兀瘦肩。"]'),
('f5575070-f62b-4e64-bdfb-d760d845c630','次韻送應秀才往池舒二州','項安世','宋','宋诗','song-poetry','','[]','瑶琴彈古曲，何事有哀音。',48,'全唐诗/poet.song.146000.json','["瑶琴彈古曲，何事有哀音。", "客子道途遠，棘人霜露深。", "齊山同雁宿，天柱共猿吟。", "二牧高人問，歸來滿孝心。"]'),
('1e47f951-3a03-4eda-b7cf-d834913748be','挽善化沈令  其一','項安世','宋','宋诗','song-poetry','','[]','十八年前夢，宜都簿即君。',48,'全唐诗/poet.song.146000.json','["十八年前夢，宜都簿即君。", "沙頭能遇我，客裏暫論文。", "久別欣同事，方驩嘆失群。", "隔宵猶一見，千古遂相分。"]'),
('e4bb760d-bd0f-437a-ac0b-f0acef5ebced','挽善化沈令  其二','項安世','宋','宋诗','song-poetry','','[]','夔門逢令季，湓浦接賢兄。',48,'全唐诗/poet.song.146000.json','["夔門逢令季，湓浦接賢兄。", "幸甚交三沈，茲焉共一城。", "解詩談到髓，聽訟筆如傾。", "豪快今安有，哀哉不久生。"]'),
('e392c8a4-6e73-40d3-8876-c17a414368b6','挽枝江朱學諭','項安世','宋','宋诗','song-poetry','','[]','身受傃軒詩，兒修涑水儀。',48,'全唐诗/poet.song.146000.json','["身受傃軒詩，兒修涑水儀。", "百年生也直，三嘆古之遺。", "處易疑孤峭，因難見惠私。", "此風今遠矣，吾涕自漣洏。"]'),
('adf086da-1e08-4c0e-a86d-02e40507fdce','善謔驛淳于髠墓上有木斜出','項安世','宋','宋诗','song-poetry','','[]','辟彊老去重堪嗟，千里堂堂表海涯。',64,'全唐诗/poet.song.146000.json','["辟彊老去重堪嗟，千里堂堂表海涯。", "取士但能籠自鵠，諫王安用學蚳鼃。", "祗言魯國賢無補，豈識齊卿實未加。", "不見只今墳上木，多年老幹尚傾斜。"]'),
('b53d0122-c4fa-4c53-bf8b-442ae6e8f1d2','次韻張部門直廬觀梅','項安世','宋','宋诗','song-poetry','','[]','不是生前有俗緣，等閑拋得傍湖園。',64,'全唐诗/poet.song.146000.json','["不是生前有俗緣，等閑拋得傍湖園。", "多情省戶寒梅色，爲洗朝靴曉凍痕。", "頗記高堂金字榜，曾陪居士癭藤尊。", "花前歛板談官事，知犯新條第幾門。"]'),
('f76a9926-5ea5-4a35-8beb-71316392593f','休日值晴張園觀梅同舍不期而集','項安世','宋','宋诗','song-poetry','','[]','玉照堂前富貴梅，倚春驕臘未輕開。',64,'全唐诗/poet.song.146000.json','["玉照堂前富貴梅，倚春驕臘未輕開。", "費他一月春風了，催得五分花意回。", "恰是佳晴難放過，偶然勝士得追陪。", "君看好景天還吝，一夜輕雲带雨來。"]'),
('ae2d1b8e-f69c-468f-94c4-ba9a0cdfa054','次韻潘都幹水晶菊二首  其一','項安世','宋','宋诗','song-poetry','','[]','幕中安得野人園，種此晶熒白玉丹。',64,'全唐诗/poet.song.146000.json','["幕中安得野人園，種此晶熒白玉丹。", "冷淡雖無九春分，風流還得一冬看。", "銀盃共色深宜酒，紙帳圍香未怕寒。", "只向河陽種桃李，今時潘勝舊時潘。"]'),
('0c204c68-7256-4611-9d32-c9f0bac4831c','次韻潘都幹水晶菊二首  其二','項安世','宋','宋诗','song-poetry','','[]','莫遣秋霞到晚園，怕將鉛臉照成丹。',64,'全唐诗/poet.song.146000.json','["莫遣秋霞到晚園，怕將鉛臉照成丹。", "落英但可和冰嚼，□色惟宜带月看。", "清似雪霜仍耐久，老於籬落不言寒。", "一枝合是閑人插，四海知儂鬢已潘。"]'),
('09886c26-f0c6-4dda-827c-6eee0c221534','又次王醇甫聞人主簿二首  其一','項安世','宋','宋诗','song-poetry','','[]','眄柯陶令喜歸園，瑩玉靈均恨變丹。',64,'全唐诗/poet.song.146000.json','["眄柯陶令喜歸園，瑩玉靈均恨變丹。", "朝飲夕餐和露摘，東籬南岫带雲看。", "仙方舊說南陽壽，異色新添霅水寒。", "誰道王郎偏愛竹，也來同枕效今潘。"]'),
('3d334550-a080-4d1b-b2f0-855039bd433e','又次王醇甫聞人主簿二首  其二','項安世','宋','宋诗','song-poetry','','[]','花莖枯槁陋東園，蕊葉蕭疎笑井丹。',64,'全唐诗/poet.song.146000.json','["花莖枯槁陋東園，蕊葉蕭疎笑井丹。", "環面釵頭人服媚，盃脣盤口客爭看。", "照筵冰膾光同潔，飣坐戎鹽色並寒。", "誰道仇香但棲棘，也吟時菊繼江潘。"]'),
('fae86af1-cf5f-443c-8317-d15fe488e1f0','次韻王醇甫藏禿筆三首  其一','項安世','宋','宋诗','song-poetry','','[]','鼻祖有功平水土，耳孫無宅寄邱陵。',64,'全唐诗/poet.song.146000.json','["鼻祖有功平水土，耳孫無宅寄邱陵。", "蚤因蒙氏收微效，晚向秦皇謝不能。", "逸少憑渠取舒鴈，阿思爲爾逐飛蠅。", "王郎世契真如此，莫訝爲儒却愛僧。"]'),
('32694cef-aa6f-4d02-99b1-c8ee2517e42d','次韻王醇甫藏禿筆三首  其二','項安世','宋','宋诗','song-poetry','','[]','黑頭期汝作東亭，短髮愁予對杜陵。',64,'全唐诗/poet.song.146000.json','["黑頭期汝作東亭，短髮愁予對杜陵。", "髠者此時今守積，穎乎平日爾誠能。", "屢題秀句文如鳳，幾注仙經細似蠅。", "可是詩人偏愛惜，詩人雙鬢漸成僧。"]'),
('252b7c74-d639-4216-951a-80b466c0bd79','次韻王醇甫藏禿筆三首  其三','項安世','宋','宋诗','song-poetry','','[]','剡剡蘭臺綴不亭，翩翩鸚鵡健相陵。',64,'全唐诗/poet.song.146000.json','["剡剡蘭臺綴不亭，翩翩鸚鵡健相陵。", "少時鋒穎先毛遂，晚歲頭顱嗣祖能。", "杜老壁間留掃馬，符王宮裏罷棲蠅。", "莫欺貧士無檀施，時向文房度一僧。"]'),
('cc118b62-f8e6-4611-8847-738f0a550a1a','五月七日乞池州添倅得請','項安世','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','羣玉峯前罷校書，九華山下試題輿。',64,'全唐诗/poet.song.146000.json','["羣玉峯前罷校書，九華山下試題輿。", "三年飽共鉛黄語，一日去從朱墨居。", "秋浦謫仙臨賦後，齊山小杜醉吟餘。", "薄才漸愧風流地，繭紙新抄雪不如。"]'),
('3a90d5ae-0cef-430c-b9f1-62cfa268cae0','讀程仁秀才淳熙奏稿','項安世','宋','宋诗','song-poetry','','[]','孝皇當宁納髦英，志士擔簦入鳳城。',64,'全唐诗/poet.song.146000.json','["孝皇當宁納髦英，志士擔簦入鳳城。", "直犯睟顔知主聖，敢譏當路見時清。", "文章不用施花草，情實都如告父兄。", "老向窮簷知不恨，曾披閶闔吐崢嶸。"]'),
('e12561ce-fd0f-4e4c-8be2-a21b387764b7','都下送外舅任知縣赴茶馬司辟','項安世','宋','宋诗','song-poetry','','[]','皇華萬里赴臨洮，親向君王乞騎曹。',64,'全唐诗/poet.song.146000.json','["皇華萬里赴臨洮，親向君王乞騎曹。", "合爲聖朝修馬政，可容窮邑試牛刀。", "橫驅旌節半天下，自許才名一世豪。", "早晚西來八千匹，九重何以答賢勞。"]'),
('b84db9e3-7f5f-4d3e-aaf5-d23b7a52b1c5','次韻李士衡失解送公衍赴調二首  其一','項安世','宋','宋诗','song-poetry','','[]','世事從來亦偶然，何妨濁酒且中賢。',64,'全唐诗/poet.song.146000.json','["世事從來亦偶然，何妨濁酒且中賢。", "諸天入定憑誰問，五色迷人自古傳。", "謝客堂中勞夢草，謫仙市上且開船。", "飛鳴款作三年計，好在秋花晚更新。"]'),
('fad88acd-ba4a-4063-97db-369ee09a45ff','次韻李士衡失解送公衍赴調二首  其二','項安世','宋','宋诗','song-poetry','','[]','向來翰墨付群兒，直把行藏待主知。',64,'全唐诗/poet.song.146000.json','["向來翰墨付群兒，直把行藏待主知。", "風引去帆聲獵獵，手調焦尾意遲遲。", "遥知夜宿吹藜處，恰是春深造榜時。", "預恐阿婆愁見我，略須回馬避旌麾。"]'),
('bf6e99ca-5a74-4245-a336-990269ff0210','用前韻勉陳進之赴省','項安世','宋','宋诗','song-poetry','','[]','癡翁切莫强笞兒，之子勤勞我所知。',64,'全唐诗/poet.song.146000.json','["癡翁切莫强笞兒，之子勤勞我所知。", "但看匡衡穿壁苦，誰云甯越讀書遲。", "能來伴我滄浪艇，共看一年橙橘時。", "莫爲小喬淹壯志，千軍白羽坐堪麾。"]'),
('2f4682ae-f497-4d95-861f-d0412bd8bc64','送張子真還鄉待邵州闕','項安世','宋','宋诗','song-poetry','','[]','今年新拜李邕州，又見君爲邵郡侯。',64,'全唐诗/poet.song.146000.json','["今年新拜李邕州，又見君爲邵郡侯。", "可是朝廷憐遠俗，獨于湖廣用名流。", "南軒學待真傳繹，槃澗家須舊業修。", "瓜戍少賒元不惡，自因二事合歸休。"]'),
('959f0b4b-c3ef-4897-a331-24e3782bd16b','紗詩','項安世','宋','宋诗','song-poetry','','[]','芙蕖供色更供絲，緝就沙溪水面漪。',64,'全唐诗/poet.song.146000.json','["芙蕖供色更供絲，緝就沙溪水面漪。", "疎密整斜於雪似，香輕軟細與風宜。", "集裳妙得靈均意，織藕新翻蜀客詞。", "喚作似花還得否，只應花却似渠伊。"]'),
('b382d4fe-504e-4ab0-85ae-26fedf55748f','過王師嶺堠見荆門郢州山','項安世','宋','宋诗','song-poetry','','[]','七澤茫茫千里間，王師堠前初見山。',64,'全唐诗/poet.song.146000.json','["七澤茫茫千里間，王師堠前初見山。", "西子嵯峨高髻擁，東鄰嬌小秀眉彎。", "背襄阻郢開肩背，大野青天豁面顔。", "獨立東風看平楚，少年雙鬢欲成斑。"]'),
('5484de0a-58e3-4561-ba11-5a7fde7352c5','和王安撫六言十首  其一','項安世','宋','宋诗','song-poetry','','[]','堆案牛腰萬軸，消磨不盡詩情。',28,'全唐诗/poet.song.146000.json','["堆案牛腰萬軸，消磨不盡詩情。", "定應是我輩語，擲地當作金聲。"]'),
('699fabef-829a-4a99-b21f-a56211a5521e','和王安撫六言十首  其二','項安世','宋','宋诗','song-poetry','','[]','西牧村風流老，翰林裏供奉人。',28,'全唐诗/poet.song.146000.json','["西牧村風流老，翰林裏供奉人。", "去之雖五百載，斬新料敵堪親。"]'),
('f58c71c9-cff4-465c-8d8d-498dc140d064','和王安撫六言十首  其三','項安世','宋','宋诗','song-poetry','','[]','從來賜達由果，不說島瘦郊寒。',28,'全唐诗/poet.song.146000.json','["從來賜達由果，不說島瘦郊寒。", "政譽追還小范，詩名壓倒方干。"]'),
('cd0ac85b-78b1-4a3f-9ca0-8af13e6951e5','和王安撫六言十首  其四','項安世','宋','宋诗','song-poetry','','[]','脫腕流泉纚纚，忘懷大智閑閑。',28,'全唐诗/poet.song.146000.json','["脫腕流泉纚纚，忘懷大智閑閑。", "學蘇二李十二，笑山谷陳後山。"]'),
('1ed5f1d5-744a-4f34-97d0-9dda23bda13b','和王安撫六言十首  其五','項安世','宋','宋诗','song-poetry','','[]','雅頌意久不聞，周孔業將遂堙。',28,'全唐诗/poet.song.146000.json','["雅頌意久不聞，周孔業將遂堙。", "若要興滅繼絕，不妨動地驚人。"]'),
('273c2f1e-fa90-47b7-9200-252b3ff13f56','和王安撫六言十首  其六','項安世','宋','宋诗','song-poetry','','[]','詩聲長甬則震，筆陣戰功曰多。',28,'全唐诗/poet.song.146000.json','["詩聲長甬則震，筆陣戰功曰多。", "自抽天上機杼，不落人間臼科。"]'),
('12309a02-0c04-4fc0-9673-1ce1af6b7184','和王安撫六言十首  其七','項安世','宋','宋诗','song-poetry','','[]','玄思上窺姚姒，後塵肯逐梁齊。',28,'全唐诗/poet.song.146000.json','["玄思上窺姚姒，後塵肯逐梁齊。", "誰言今世第一，我自古人與稽。"]'),
('1628f018-e1be-45c6-8502-76d2748aad0b','和王安撫六言十首  其八','項安世','宋','宋诗','song-poetry','','[]','小人區釜升斗，明公鐘鼎尊罍。',28,'全唐诗/poet.song.146000.json','["小人區釜升斗，明公鐘鼎尊罍。", "難學將軍競病，且隨寒士敲推。"]'),
('fc5b2524-dc49-49ee-a988-88bc07b80bf3','和王安撫六言十首  其九','項安世','宋','宋诗','song-poetry','','[]','苦心自在阿堵，聖處誰知寧馨。',28,'全唐诗/poet.song.146000.json','["苦心自在阿堵，聖處誰知寧馨。", "佳句忽來天外，恰能當當亭亭。"]'),
('b2e98915-58f4-4b0c-9b27-bc5fa4ca19db','和王安撫六言十首  其一○','項安世','宋','宋诗','song-poetry','','[]','朅來此事盡廢，少日論功未深。',28,'全唐诗/poet.song.146000.json','["朅來此事盡廢，少日論功未深。", "欲覓仙人一指，要看月脇天心。"]'),
('a859deb1-04d1-4080-ac7a-998a2d779cb0','再和  其一','項安世','宋','宋诗','song-poetry','','[]','湖海崢嶸老氣，風雲慘淡高情。',28,'全唐诗/poet.song.146000.json','["湖海崢嶸老氣，風雲慘淡高情。", "可惜元龍雙鬢，江南江北詩聲。"]'),
('d0a49005-6592-4387-8fb6-97290596725b','再和  其二','項安世','宋','宋诗','song-poetry','','[]','聽說忠臣孝子，不論往事今人。',28,'全唐诗/poet.song.146000.json','["聽說忠臣孝子，不論往事今人。", "衣上淋浪清淚，一生長爲君親。"]'),
('92e9c07f-42d1-4b63-9831-7258072bbf42','再和  其三','項安世','宋','宋诗','song-poetry','','[]','望海亭前句遠，蓬萊閣上詩寒。',28,'全唐诗/poet.song.146000.json','["望海亭前句遠，蓬萊閣上詩寒。", "老子向來椽筆，要題吉日斯干。"]'),
('1eef934a-e762-464f-8ca3-fe58860c90a5','再和  其四','項安世','宋','宋诗','song-poetry','','[]','少日心隨鶚上，長年身伴鷗閑。',28,'全唐诗/poet.song.146000.json','["少日心隨鶚上，長年身伴鷗閑。", "昨夜松聲到枕，夢魂踏破天山。"]'),
('badbbcef-fb49-4608-a8ad-450c09583748','再和  其五','項安世','宋','宋诗','song-poetry','','[]','嘆息五陵翁仲，春來草路長堙。',28,'全唐诗/poet.song.146000.json','["嘆息五陵翁仲，春來草路長堙。", "鉅鹿空懷故將，海山空著詩人。"]'),
('869dfe91-593c-4fdb-8439-99dd0c75ce68','再和  其六','項安世','宋','宋诗','song-poetry','','[]','豐年官事無何，梅月詩情最多。',28,'全唐诗/poet.song.146000.json','["豐年官事無何，梅月詩情最多。", "白水暗添漚界，青苔亂長松科。"]'),
('be23f066-5c19-4af0-8c66-3852c7f2e9eb','再和  其七','項安世','宋','宋诗','song-poetry','','[]','文命生輕癸甲，祖龍死惑燕齊。',28,'全唐诗/poet.song.146000.json','["文命生輕癸甲，祖龍死惑燕齊。", "矗矗秦山易識，茫茫禹穴難稽。"]'),
('14b4a936-0aa0-44db-9d84-a57dd2b6bb61','再和  其八','項安世','宋','宋诗','song-poetry','','[]','廣文已荒茆屋，彭澤浪耻虛罍。',28,'全唐诗/poet.song.146000.json','["廣文已荒茆屋，彭澤浪耻虛罍。", "二頃平生幽願，一犁歸處深推。"]'),
('2b3bc0f2-4335-4cea-9fde-1a5ff2bbd820','再和  其九','項安世','宋','宋诗','song-poetry','','[]','麥熟啼聲未了，藕花醉魄還馨。',28,'全唐诗/poet.song.146000.json','["麥熟啼聲未了，藕花醉魄還馨。", "只麽跳丸日月，何年檢玉云亭。"]'),
('4421f52b-2fa0-4368-a3ee-f207d1f4998f','再和  其一○','項安世','宋','宋诗','song-poetry','','[]','聖處耘耔日淺，俗間葑淤年深。',28,'全唐诗/poet.song.146000.json','["聖處耘耔日淺，俗間葑淤年深。", "蚤歲襟期何許，如今翻愧初心。"]'),
('d6b00d97-ac28-452c-8268-571581df35e6','三和  其一','項安世','宋','宋诗','song-poetry','','[]','易簡乾坤正理，寬平雅頌真情。',28,'全唐诗/poet.song.146000.json','["易簡乾坤正理，寬平雅頌真情。", "何處如今更有，壁間牀下秋聲。"]'),
('7760198c-6c2e-438c-b8da-699ba1711f94','三和  其二','項安世','宋','宋诗','song-poetry','','[]','某良士某良士，古之人古之人。',28,'全唐诗/poet.song.146000.json','["某良士某良士，古之人古之人。", "名利坐中讎敵，詩書千載交親。"]'),
('526e0910-6007-45df-931b-a11c8a9caf30','三和  其三','項安世','宋','宋诗','song-poetry','','[]','義不作進學解，分應有坐客寒。',28,'全唐诗/poet.song.146000.json','["義不作進學解，分應有坐客寒。", "自省開斯未信，何言顓祿須干。"]'),
('0fbbab8b-323f-4f5d-bfb3-1beaf08c792a','三和  其四','項安世','宋','宋诗','song-poetry','','[]','作者向來十數，名隨草木俱堙。',28,'全唐诗/poet.song.146000.json','["作者向來十數，名隨草木俱堙。", "聖賢生世不數，文章何代無人。"]'),
('6e9f0a24-2f96-4057-8e3d-c4e1bbf21b89','三和  其五','項安世','宋','宋诗','song-poetry','','[]','萬古垂名豈敢，三年費俸長閑。',28,'全唐诗/poet.song.146000.json','["萬古垂名豈敢，三年費俸長閑。", "有酒似陶元亮，無愁學庾子山。"]'),
('bbacb5f7-60a5-4aa3-96c4-e646a1d1e777','三和  其六','項安世','宋','宋诗','song-poetry','','[]','公詩百戰萬選，人才三少兩多。',28,'全唐诗/poet.song.146000.json','["公詩百戰萬選，人才三少兩多。", "若許追攀及格，稍容積漸盈科。"]'),
('24d13a50-fd20-4c96-aeef-304f2b110422','三和  其七','項安世','宋','宋诗','song-poetry','','[]','典誥殘于勝建，聲詩失自韓齊。',28,'全唐诗/poet.song.146000.json','["典誥殘于勝建，聲詩失自韓齊。", "一言蔽思無邪，三萬解曰若稽。"]'),
('05b38266-e30a-401e-b562-d387152339f2','三和  其八','項安世','宋','宋诗','song-poetry','','[]','大國并吞江漢，小家垂罄缾罍。',28,'全唐诗/poet.song.146000.json','["大國并吞江漢，小家垂罄缾罍。", "賁育但叉手揖，沮溺漫窮年推。"]'),
('c406f0aa-1e92-466b-9ceb-87d6b322efd8','三和  其九','項安世','宋','宋诗','song-poetry','','[]','族望與淮俱遠，時名似蘭斯馨。',28,'全唐诗/poet.song.146000.json','["族望與淮俱遠，時名似蘭斯馨。", "投老誤期懷祖，作公定類東亭。"]'),
('25d58658-d4d3-4846-a1eb-c96d441ffb9c','三和  其一○','項安世','宋','宋诗','song-poetry','','[]','老子於此不淺，先師教我資深。',28,'全唐诗/poet.song.146000.json','["老子於此不淺，先師教我資深。", "但使發乎情性，何愁嘔出肝心。"]'),
('05adc7d3-d63b-4f12-88c8-45678c97fa62','四和  其一','項安世','宋','宋诗','song-poetry','','[]','此世方當出手，君侯渠得忘情。',28,'全唐诗/poet.song.146000.json','["此世方當出手，君侯渠得忘情。", "莫麽買山高論，行哉破竹邊聲。"]'),
('5790c2ce-ee9e-4647-8bab-57e7c18d7a63','四和  其二','項安世','宋','宋诗','song-poetry','','[]','百年可惜幾見，一代何能數人。',28,'全唐诗/poet.song.146000.json','["百年可惜幾見，一代何能數人。", "下馬賦風雅頌，上馬看疾毒親。"]'),
('e747cb25-57ba-416b-a7d2-1dfaa16720ca','四和  其三','項安世','宋','宋诗','song-poetry','','[]','風節言言邁往，清詩字字高寒。',28,'全唐诗/poet.song.146000.json','["風節言言邁往，清詩字字高寒。", "奇古珊瑚碧樹，英明玉戚朱干。"]'),
('a72d0f4e-9f17-4b89-b1e9-7211b6e8219c','四和  其四','項安世','宋','宋诗','song-poetry','','[]','考古飀飀似見，談王易易如閑。',28,'全唐诗/poet.song.146000.json','["考古飀飀似見，談王易易如閑。", "政爾盛之馨處，卧龍恰稱茲山。"]'),
('3200ca9e-b486-419c-978c-0fb16294e725','四和  其五','項安世','宋','宋诗','song-poetry','','[]','九澤導來無事，五行汩後徒堙。',28,'全唐诗/poet.song.146000.json','["九澤導來無事，五行汩後徒堙。", "但使民皆忘我，誰言州解勞人。"]'),
('0ea89d83-a09a-4bd8-9701-9b5f9a765917','四和  其六','項安世','宋','宋诗','song-poetry','','[]','周家石鼓嵯峨，從臣才藝心多。',28,'全唐诗/poet.song.146000.json','["周家石鼓嵯峨，從臣才藝心多。", "所期喚起雅頌，渠止鎸成隸科。"]'),
('d7ce91db-6b3e-4f6f-b0c8-add5bb7244b7','四和  其七','項安世','宋','宋诗','song-poetry','','[]','復讎萬古明義，寸刃終屠魏齊。',28,'全唐诗/poet.song.146000.json','["復讎萬古明義，寸刃終屠魏齊。", "簀裡誰知范叔，車中暗逐王稽。"]'),
('10d4103d-1e64-4bdd-ba09-fe2ee855b704','四和  其八','項安世','宋','宋诗','song-poetry','','[]','遺老玄黄漿食，內家卷耳觥罍。',28,'全唐诗/poet.song.146000.json','["遺老玄黄漿食，內家卷耳觥罍。", "長轂能行萬里，君王不憚親推。"]'),
('372a1b54-32fe-453c-a9fd-0a2de3bbea4c','四和  其九','項安世','宋','宋诗','song-poetry','','[]','漢家樹業如許，君王神武能馨。',28,'全唐诗/poet.song.146000.json','["漢家樹業如許，君王神武能馨。", "夷吾可但江左，楚囚誰對新亭。"]'),
('e6682fee-cf5d-4431-855b-ea48166f323b','四和  其一○','項安世','宋','宋诗','song-poetry','','[]','一州如許斗大，四海望公則深。',28,'全唐诗/poet.song.146000.json','["一州如許斗大，四海望公則深。", "事業本無奇巧，聖賢只有虛心。"]'),
('b8c89146-b3de-4aeb-88b8-386cf66652a3','次韻葉教授小院室中瓶梅二首  其一','項安世','宋','宋诗','song-poetry','','[]','半瓻冰水一簪梅，的皪寒花數點開。',32,'全唐诗/poet.song.146000.json','["半瓻冰水一簪梅，的皪寒花數點開。", "疎影已從燈畔見，暗香時向夢中來。"]'),
('821e3114-9cec-427c-93f9-3409d63627f6','次韻葉教授小院室中瓶梅二首  其二','項安世','宋','宋诗','song-poetry','','[]','暖冰融雪浸疎梅，養住春風細細開。',32,'全唐诗/poet.song.146000.json','["暖冰融雪浸疎梅，養住春風細細開。", "相賞阿咸清到骨，風流元自竹林來。"]'),
('1e039c63-9a74-4b6d-8712-237a99dab440','祠山廟','項安世','宋','宋诗','song-poetry','','[]','方頤大目一髯士，百世廟食祠山宮。',32,'全唐诗/poet.song.146000.json','["方頤大目一髯士，百世廟食祠山宮。", "男兒生世不自立，死作餓鬼何時窮。"]'),
('f5de19ad-8c16-4c4a-97fe-f87cbaddb767','錢唐道中望越州山','項安世','宋','宋诗','song-poetry','','[]','隔江東望越州山，七載重來喜破顔。',32,'全唐诗/poet.song.146000.json','["隔江東望越州山，七載重來喜破顔。", "却數故人今幾在，一襟清淚濕潸潸。"]'),
('0116c4ca-d37e-4583-87ef-437b9da75617','晦日出長安閘','項安世','宋','宋诗','song-poetry','','[]','長安堰口長安閘，一度經行一斷魂。',32,'全唐诗/poet.song.146000.json','["長安堰口長安閘，一度經行一斷魂。", "不道秦川在何處，只驚行色近中原。"]'),
('4d48b75b-033c-45f7-9b70-92379c13d922','久雨','項安世','宋','宋诗','song-poetry','','[]','一春泥水斷前街，重閉柴門養綠苔。',32,'全唐诗/poet.song.146000.json','["一春泥水斷前街，重閉柴門養綠苔。", "惟有杏梁雙海燕，知人曾到十洲來。"]'),
('4fa91aba-5144-4605-aa2f-7e36f29167ea','偶作','項安世','宋','宋诗','song-poetry','','[]','草枯葉落四山童，萬里長天一目空。',32,'全唐诗/poet.song.146000.json','["草枯葉落四山童，萬里長天一目空。", "數點寒梢著紅蕊，人間驚喜見春風。"]'),
('31a0cc7b-c827-4f76-a2d3-715d4ccedb8c','次韻謝張安撫以詩送梅實  其一','項安世','宋','宋诗','song-poetry','','[]','此物從來作計疎，洛陽櫻笋正馳驅。',32,'全唐诗/poet.song.146000.json','["此物從來作計疎，洛陽櫻笋正馳驅。", "絕知不可時人口，只有微酸愜腐儒。"]'),
('dbc77b51-5e8b-425f-9f75-aaaf0f59ee82','次韻謝張安撫以詩送梅實  其二','項安世','宋','宋诗','song-poetry','','[]','水邊籬落數花疎，馬上行人且勿驅。',32,'全唐诗/poet.song.146000.json','["水邊籬落數花疎，馬上行人且勿驅。", "一墮冰盤永相望，故人憐我誤爲儒。"]'),
('1e6f38ab-08bd-45f7-822a-e1a6e056f642','次韻謝張安撫以詩送梅實  其三','項安世','宋','宋诗','song-poetry','','[]','葉間烟雨尚疎疎，桃李盤中怯並驅。',32,'全唐诗/poet.song.146000.json','["葉間烟雨尚疎疎，桃李盤中怯並驅。", "忽見使君憐此味，始知時世未輕儒。"]'),
('37f5f88c-2bcc-4eb5-9d2e-a0c5a3ce724a','次韻謝張安撫以詩送梅實  其四','項安世','宋','宋诗','song-poetry','','[]','夢隨清淺看扶疎，軍將敲門報疾驅。',32,'全唐诗/poet.song.146000.json','["夢隨清淺看扶疎，軍將敲門報疾驅。", "此解可辭兒女笑，使君風味似寒儒。"]'),
('02748bc0-23cd-4c80-99c9-b6e172a1ec3a','沈醫送苔梅自云恨不能詩','項安世','宋','宋诗','song-poetry','','[]','但能爲我送苔梅，何必新詩手自裁。',32,'全唐诗/poet.song.146000.json','["但能爲我送苔梅，何必新詩手自裁。", "若使能詩有奇句，無因送與冷官來。"]'),
('43ae60ae-19bb-4516-999b-30ba7c74dfea','雁汊望舒州山','項安世','宋','宋诗','song-poetry','','[]','歸帆拂掠皖公山，一路青峨立翠鬟。',32,'全唐诗/poet.song.146000.json','["歸帆拂掠皖公山，一路青峨立翠鬟。", "曾見劉郎射蛟日，插天旌旆照孱顔。"]'),
('e80e2d01-61e3-4993-aafb-40597a18ce32','自贊','項安世','宋','宋诗','song-poetry','','[]','將軍下筆枉施功，羽箭賢冠事不同。',32,'全唐诗/poet.song.146000.json','["將軍下筆枉施功，羽箭賢冠事不同。", "桐柏宮中狂道士，枚回洲上病漁翁。"]'),
('138c41e4-e5fd-4846-aca2-c84d7a9bd71f','題澹山巖二首  其一','項安世','宋','宋诗','song-poetry','','[]','自有宇宙來，迢迢澹家山。',144,'全唐诗/poet.song.146000.json','["自有宇宙來，迢迢澹家山。", "不知幾萬古，鬰鬰藏神姦。", "祖龍御宇宙，周子巢其間。", "事同商嶺遯，迹類桃源跧。", "湮淪向千載，太史來荆蠻。", "指點發天秘，提携出人寰。", "一日遍海內，流聲響潺潺。", "鎸劖滿石壁，新瞀不可刪。", "山靈反惆悵，俗駕紛往還。", "造物有奇寶，無怪陰工慳。", "不遭固可恨，遭世良亦艱。", "所以求志人，抱珍守蓬菅。"]'),
('a2d9e511-b65c-4fa0-8ef3-a94c76a83e81','題澹山巖二首  其二','項安世','宋','宋诗','song-poetry','','[]','此日縱自爾，此興不可闌。',136,'全唐诗/poet.song.146000.json','["此日縱自爾，此興不可闌。", "竹徑滑拳局，芒鞋側蹣跚。", "南窺下陰洞，北望升天關。", "鬼穴勇爭覷，仙扃誰得{枦/睘}。", "敷床憇明潔，酌酒休癡頑。", "幽處可僧磬，迴中堪舞鬟。", "樂極忽有念，相顧生愁顔。", "指點壁間字，其人多馬班。", "書蹟向昧昧，苔痕日斒斒。", "題名出門去，歲月如循環。", "何年復此來，三士同躋攀。"]'),
('6133c9b5-a703-4d88-af97-8bb9ab6c22c0','小隠莊別高教授','項安世','宋','宋诗','song-poetry','','[]','翳翳日景入，行行故人遠。',48,'全唐诗/poet.song.146000.json','["翳翳日景入，行行故人遠。", "故人萬里別，此去何當返。", "迨君歸禹穴，是我登邛阪。", "苦語難重陳，相期在加飯。"]'),
('dbb5177e-0dfe-4d19-a823-b9ec640a8d8b','次前韻餞高教授','項安世','宋','宋诗','song-poetry','','[]','餞者石與高，慶者徐與項。',120,'全唐诗/poet.song.146000.json','["餞者石與高，慶者徐與項。", "醵者鄭與蘇，張侯爲兼講。", "酒兵互劘壘，學植交刺䎧。", "時與優孟詞，間出德山棒。", "吻捷詫先鳴，途窮爭絕港。", "同聲暫諧昵，異論忽儱傋。", "百年能幾笑，莫作受錢缿。", "明朝會稽脚，已著邕州𦂌。", "饑驅自此去，擔遠無人耩。", "誰能告諸公，收取鏡湖𢗒。"]'),
('8d65a25d-b346-44e0-8355-3740334742f4','涉漢至隆中有感','項安世','宋','宋诗','song-poetry','','[]','曉渡漢水陽，平川去如掌。',192,'全唐诗/poet.song.146000.json','["曉渡漢水陽，平川去如掌。", "春深風日老，雨後桑麻長。", "麥田渺無際，竹墅清可賞。", "家家傍林落，往往成族黨。", "溪頭浣紗女，十五自來往。", "我來三月暮，甚作二浙想。", "愛此重躊躇，凄然復悵惘。", "邊頭兵未動，農事日以廣。", "只今烽火地，開闢無曠壤。", "緬思生人情，本自樂安養。", "每遭我輩誤，遂使汝曹枉。", "承平未災變，北地極豐穰。", "中間一喪亂，殺戮同草莽。", "赤子亦何知，淪胥受漂蕩。", "搢紳欲辭罪，世道終安放。", "歌罷叫葛公，英靈歘來享。"]'),
('99ea3fc7-3b5b-4fe4-9c36-87488bce7d2f','隆中次吳襄陽韻二首  其一','項安世','宋','宋诗','song-poetry','','[]','葛公未易談，佳處當自曉。',168,'全唐诗/poet.song.146000.json','["葛公未易談，佳處當自曉。", "輕身託人主，歲晚那得保。", "哀哉楊德祖，所恨機太早。", "文若豈不遲，萬變要難了。", "書生法當驕，正懼此身小。", "空桑視湯幣，不博一介草。", "向來磻溪人，所願直鈎老。", "孔明平生志，豈必書江表。", "但從德翁游，時和司馬好。", "胸中管樂事，本自不足道。", "所以劉葛交，終焉契魚藻。", "舊時耕鑿地，千歲跡未掃。", "客來訪遺事，淚落日杲杲。", "岡頭雙白鷺，飛去何渺渺。"]'),
('84d8b863-aea9-4453-aa40-1cf6e4e53630','隆中次吳襄陽韻二首  其二','項安世','宋','宋诗','song-poetry','','[]','古來建大厦，所貴楹桷崇。',144,'全唐诗/poet.song.146000.json','["古來建大厦，所貴楹桷崇。", "沛公得三士，折箠驅群雄。", "嗟哉漢諸孫，永負隆準公。", "表既憎禰衡，璋復輕張松。", "幽州小從事，苦諫不見從。", "頼有大耳兒，猶能過隆中。", "吾評四劉牧，三豕而一龍。", "景升最可笑，接士滿郊宮。", "坐看故人子，低頭混耕農。", "平生慕西伯，對面失飛熊。", "阿琦去梯策，尚識智士功。", "誰云豚犬愚，頗復勝乃翁。"]'),
('405bf267-9545-4478-b86d-66ed4e0ef404','和總領陳大卿告老二十韻','項安世','宋','宋诗','song-poetry','','[]','饑餐不願粱，渴飲不辭魯。',240,'全唐诗/poet.song.146000.json','["饑餐不願粱，渴飲不辭魯。", "我老乞吾身，無才固其所。", "豈有經世人，而當話高舉。", "朝爲一日留，暮有一日補。", "若令久其事，所補可勝數。", "周邦有憂嫠，漆室有嘯女。", "况居星月位，欲蹈烟霞侶。", "方今政和平，群彥日藻斧。", "稍稍起蒿萊，紛紛闖門戶。", "何嫌管蕭材，從事參井土。", "軍方徯喉命，民又惜基堵。", "通八十一難，調二十七齬。", "劬勞鴻赴澤，上下鵻尋栩。", "行行樂駰騏，役役悲兕虎。", "爲國充使臣，將身事人主。", "但憑心力去，肯用年華阻。", "不見密學翁，遺書耿如許。", "千林訪車材，九澤具舟樐。", "惟思起奔沉，詎說師稼圃。", "想公聞吾言，矍鑠還起舞。"]'),
('d31b9465-e809-4b06-8c6a-c1418f11cd1a','送妻兄任以道赴房州竹山尉四首  其一','項安世','宋','宋诗','song-poetry','','[]','山東貴公孫，門戶何巍巍。',48,'全唐诗/poet.song.146000.json','["山東貴公孫，門戶何巍巍。", "秦川列冠蓋，蜀道羅旌麾。", "亭亭白玉樹，煜煜黄金芝。", "産于階庭間，不種而自奇。"]'),
('85ecc1f8-ea5d-4de9-ad8d-ee01963397b7','送妻兄任以道赴房州竹山尉四首  其二','項安世','宋','宋诗','song-poetry','','[]','古來王謝家，生長習見聞。',48,'全唐诗/poet.song.146000.json','["古來王謝家，生長習見聞。", "人言不學問，楚楚自超羣。", "君侯妙質稟，博學而多文。", "如玉作璠璵，可以奉明君。"]'),
('9faa0b27-0799-483a-9598-65ca43a418ad','送妻兄任以道赴房州竹山尉四首  其三','項安世','宋','宋诗','song-poetry','','[]','少年有龍淵，不飾羞自售。',48,'全唐诗/poet.song.146000.json','["少年有龍淵，不飾羞自售。", "凝塵滿蒯緱，見者不知有。", "提携試拂拭，光采射牛斗。", "世人輕玉璞，諒非和氏偶。"]'),
('378c948c-8887-40ae-b8b0-c85f7606fde3','送妻兄任以道赴房州竹山尉四首  其四','項安世','宋','宋诗','song-poetry','','[]','凄凉怕折腰，彼蓋村夫子。',48,'全唐诗/poet.song.146000.json','["凄凉怕折腰，彼蓋村夫子。", "誰能九層臺，不用累土起。", "旌旗野色中，鉦鼓霜風裏。", "古來丈夫事，勿嘆百僚底。"]'),
('542ead98-e9f3-4544-95fd-d34b82354401','昌州寄永川趙尉','項安世','宋','宋诗','song-poetry','','[]','此州大如斗，此縣安得壯。',132,'全唐诗/poet.song.146000.json','["此州大如斗，此縣安得壯。", "官有少府君，斯須一軍張。", "此君少年日，弄筆戲天匠。", "能令枯樹榮，解使涸澤漲。", "歲晚天戲之，千山萬山瘴。", "不畀龜自靈，小兒能薄相。", "我于同辰游，拜君丈人行。", "得書日十反，有燭夜千丈。", "如何三命共，所設非所當。", "巽君在牀下，踞我著爐上。", "此意豈宜蒙，臨風願回向。"]'),
('ed2f36cf-9231-4d11-ab7d-9072d9947cc1','題張藥局退巖四十韻','項安世','宋','宋诗','song-poetry','','[]','大家習貴久，亦復閲儉多。',288,'全唐诗/poet.song.146000.json','["大家習貴久，亦復閲儉多。", "所習已厭飫，所閲方憂訛。", "食厭如食蠟，避憂如避戈。", "誰能飽更飯，脹洩自生疴。", "此理大可見，判若黝與皤。", "所以張公子，悠然願巖阿。", "退翁聞之喜，爲作退士歌。", "介邱自可樵，何必岷與嶓。", "汙池自可漁，何必江與河。", "擁腫爲我居，何必房千娥。", "款段爲我乘，何必駕六騾。", "但醉皆勝醒，但寢皆勝訛。", "晏起勝早朝，徐行勝前呵。", "筇以當魚須，褐以當羔紽。", "葛巾以當幘，草屩以當靴。", "巖頭有椶楠，巖下有薜蘿。", "東有百畝園，西有十里荷。", "香逕可游屐，石步可椓牁。", "俯樂莊生魚，仰眄淵明柯。", "行攀女兒柳，占坐老翁莎。", "月出竹效舞，風來松獻哦。", "天清掃木葉，雨潤移花窠。", "身閒少譏譽，氣靜無昏瘥。", "居然勝趙孟，奚用封蕭酇。"]'),
('1a802ecc-e726-4c39-96f0-c518b825d942','賦莊賢良招隠樓三首  其一','項安世','宋','宋诗','song-poetry','','[]','樓居入闤闠，不受闠中塵。',96,'全唐诗/poet.song.146000.json','["樓居入闤闠，不受闠中塵。", "闠中豈無樓，無此招隠人。", "昔者小山篇，非我招隠意。", "吾今已隠矣，更欲招同志。", "同志不易得，徘徊竟誰招。", "長風一萬里，車馬極喧囂。", "安得世上人，共此樓中客。", "時時喚南山，相與共朝夕。"]'),
('d1b5b679-852b-4591-81e1-9e1f8c3a77ce','賦莊賢良招隠樓三首  其二','項安世','宋','宋诗','song-poetry','','[]','主人湖海士，有策欲平戎。',96,'全唐诗/poet.song.146000.json','["主人湖海士，有策欲平戎。", "入朝見天子，可以揖三公。", "客來忽相驚，見此招隠號。", "語客且勿驚，洗耳非我好。", "女豈不願家，鑽穴乃貽罹。", "深閨日夜藏，恐辱傅與師。", "世態溱洧中，欲挽無此力。", "解逅同志人，相招事蠶績。"]'),
('793d93ce-c643-43bb-b850-b59923b388c8','賦莊賢良招隠樓三首  其三','項安世','宋','宋诗','song-poetry','','[]','士憂不能晦，不患名不章。',96,'全唐诗/poet.song.146000.json','["士憂不能晦，不患名不章。", "垂老有降志，當年寡身藏。", "古來經世人，皆抱邱壑志。", "王官待罪耳，敢有欲爲意。", "細兒詎如許，謂是詭與崖。", "吾豈鳥獸羣，寶櫝義當懷。", "如作市門優，可作君子配。", "男兒補衮日，招隠意終在。"]'),
('073275af-a9d5-44f9-b3d0-b5326e1af9bf','次韻金陵掾屬登賞心亭十六韻','項安世','宋','宋诗','song-poetry','','[]','賞心淮水頭，樓觀岌以舉。',192,'全唐诗/poet.song.146000.json','["賞心淮水頭，樓觀岌以舉。", "下分漚鳥界，上入歸鴻許。", "登梯雲濕履，肆席星落俎。", "龍爭失孫馬，鯨戮空峻處。", "湖通晉代溝，草入吳時圃。", "長嘯動危闌，驚風散濛雨。", "君看柱間字，夭矯尚飛舞。", "身後豈不榮，生前固多齬。", "君看亭下人，古木冠黄土。", "猶應悔存日，剩不荒酒所。", "只今十九客，一笑集賓宇。", "却後三十年，重來共誰語。", "念此令人悲，鬢髮坐成古。", "忽憶少年時，勝具濟剛膂。", "前川問花柳，春半天色午。", "此樂今未央，寒藤進衰武。"]'),
('d3cd1d3e-4e01-4be9-abe2-697a7411f60e','擬送陳正己赴沅江令','項安世','宋','宋诗','song-poetry','','[]','一餐我無門，五斗君有祿。',108,'全唐诗/poet.song.146000.json','["一餐我無門，五斗君有祿。", "猶勝乞鄰僧，何必嗔郡督。", "江清芷無數，縣靜書可讀。", "素業傳二雛，清風散羣鶩。", "於焉善藏刀，可以待沽匵。", "所嗟吾過多，此去誰與告。", "提携到尊豆，笑語慣僮僕。", "隔日意猶凄，三秋間何酷。", "書來想憶外，無使德音玉。"]'),
('85863a39-1f47-4919-895c-f873d9692abd','擬感興二首  其一','項安世','宋','宋诗','song-poetry','','[]','日出羣動作，日入萬物休。',72,'全唐诗/poet.song.146000.json','["日出羣動作，日入萬物休。", "君看霄壤間，還有二本否。", "鬼神浩來往，一穟不可投。", "殺機甫毫芒，舉世極戈矛。", "將亡神已降，欲殺鬼先謀。", "所以君子心，不敢殊顯幽。"]'),
('0f1efef8-2c51-4bba-932b-a7cdceca6fbe','擬感興二首  其二','項安世','宋','宋诗','song-poetry','','[]','吾心本虛直，萬象同一流。',72,'全唐诗/poet.song.146000.json','["吾心本虛直，萬象同一流。", "坐遭雲沙矇，次序失九疇。", "習空徒妄想，致察在勤修。", "學問日以廣，思辨日以周。", "行行重行行，馬迹遍九州。", "始知億萬葉，一幹本同抽。"]'),
('45f244f2-a905-4d63-baa4-678c0c8437cd','送黄司戶改官東歸','項安世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江西黄郎中，有聲滿天宇。',264,'全唐诗/poet.song.146000.json','["江西黄郎中，有聲滿天宇。", "於菟老巖穴，晚出彪更怒。", "三十補州掾，勇往不辭苦。", "首尾庚申年，所事七府主。", "不惟吏事知，競以文學許。", "飛章不停剡，禮幣爭羅取。", "前年開科場，小試便更舉。", "四海張南軒，人訾公獨與。", "平生中庸篇，口誦心復睹。", "官滿貰金歸，囊無一錢處。", "傳家有風烈，真不愧此父。", "阿戎更奇俊，邂逅得佳侶。", "三年下陳榻，內省愧參魯。", "出言每不忌，逆耳終無拒。", "反茲號畏友，不獨赦狂瞽。", "乃知君子心，未易見涯滸。", "若令到天闕，定合簉鵷羽。", "爲邦固常法，有用必超補。", "人情重離別，臨路各凄楚。", "遠客見歸人，驚心念鄉土。", "秋風楚江岸，吾亦辦歸櫓。", "期公父子來，同看西湖雨。"]'),
('95be777a-79d5-42a5-94fd-00ae9d982fc0','送程道輝之廣濟','項安世','宋','宋诗','song-poetry','','[]','昂昂天馬駒，志豈甘伏櫪。',216,'全唐诗/poet.song.146000.json','["昂昂天馬駒，志豈甘伏櫪。", "虓虓巖下虎，平生肯求食。", "可憐百鍊鋼，繞指化爲席。", "丈夫有不遇，此事今猶昔。", "程侯西南來，氣若朱絃直。", "寶劍光出爐，銛鋒凈如拭。", "蕭蕭萬里足，矯矯九秋翮。", "君看吳楚越，何處無行跡。", "歲晚賦歸來，天寒倦游役。", "海鶴願鷄栖，榆鳩困鵬翼。", "人間竟如此，使我三太息。", "雖然聊戲君，萬事多所歷。", "巧定不如癡，言真短于默。", "世路危山蹊，人情險矛戟。", "從來菱上刺，不若芡中實。", "但學幽冀推，穩爲郊廟璧。", "行矣無多言，此事君已識。", "冷暖今日知，勿受豪士惑。"]'),
('8b3717f0-2239-4d7a-8d2d-5eaad6edd735','三山磯答漁父歌','項安世','宋','宋诗','song-poetry','','[]','我行如轆轤，西上復東下。',288,'全唐诗/poet.song.146000.json','["我行如轆轤，西上復東下。", "觸熱泝江船，迎霜歸越舍。", "齊山至禹穴，百六十長亭。", "江頭磯上叟，嗤我太營營。", "朝見上江來，暮見下江去。", "君爲何物官，拜罷乃爾遽。", "語叟且勿嗤，我本寒鄉士。", "三年饕漢粟，中秘仍太史。", "爲親乞左官，得貳江南州。", "人淳土物美，官暇餐錢優。", "心歡親意足，家喜朋戚賀。", "犯炎束去擔，凌漲理征柂。", "心力困奔走，性命脫痁痎。", "及郊始相慶，有命從天來。", "天恩一何厚，別駕升太守。", "州名太府尊，地望潜藩舊。", "父母愛則深，未諒赤子心。", "公榮私養迫，外美內愁侵。", "問戍當幾時，列宿兩經天。", "問去當幾程，更西行五千。", "荆南居其中，此去猶百舍。", "回艫指東越，半月可休駕。", "瓜時幸未忙，况有婚會急。", "女弟歸越人，季秋迨其吉。"]'),
('249cacfa-fa43-4841-88b5-1f1fc4bc09b0','與鄭檢法莊賢良往三山訪陸提舉不值','項安世','宋','宋诗','song-poetry','','[]','好客漢內史，著書蒙漆園。',108,'全唐诗/poet.song.146000.json','["好客漢內史，著書蒙漆園。", "肯從一先生，共訪三神山。", "行循古塘上，步入青林間。", "不見荷篠人，但與二子言。", "非干海風引，意足我自還。", "古來剡溪上，興盡明月天。", "亦有好事人，稽山回酒船。", "茲游雖不逢，頼古多此賢。", "作詩解嚴鄭，相視各欣然。"]'),
('7e00c8b0-7995-47fe-a3b6-69926f0b6a72','九月十日獨遊鍾山','項安世','宋','宋诗','song-poetry','','[]','天時少佳日，人事多嬰懷。',180,'全唐诗/poet.song.146000.json','["天時少佳日，人事多嬰懷。", "選勝難兩遇，卜征非一乖。", "平生夢鍾阜，一月榜秦淮。", "半世迹方近，三旬心始諧。", "允哲茲游艱，果諒此日佳。", "高秋凈平麓，暖景融陰崖。", "時丁酬酢暇，心適煩紆排。", "出郭玄筍輿，陟巘青芒鞋。", "誌塔湧重屋，竺水環方階。", "木末但塵壁，定林堆斷柴。", "誰爲好事者，尚丁雙詩牌。", "相見廊廟姿，騎馿渡松釵。", "玄思入秋骨，高情渺天涯。", "儻無經世迹，勝韵誰得偕。", "因觀夔禹難，始悟巢許儕。"]'),
('0357976a-e397-4238-8460-5be67c79c044','再過溧陽縣見李侍御二首  其一','項安世','宋','宋诗','song-poetry','','[]','中朝文字家，獨嘆仁公門。',96,'全唐诗/poet.song.146000.json','["中朝文字家，獨嘆仁公門。", "時時落人間，欬唾如雲奔。", "歲月坐成晚，今爲隣里尊。", "向來崔魏徒，十九歸邱原。", "宛在水中央，靈光兀孤蹲。", "庭空鳥雀入，日晏烟塵昏。", "我來重太息，心事與誰論。", "丈人笑謝客，久矣欲忘言。"]'),
('e15a92c3-0940-4629-bb04-fb3e22b400d4','再過溧陽縣見李侍御二首  其二','項安世','宋','宋诗','song-poetry','','[]','憶昔兒子時，仁公兩朱轓。',96,'全唐诗/poet.song.146000.json','["憶昔兒子時，仁公兩朱轓。", "吟篇與醉墨，零落遍湘沅。", "少長聽鳴騶，清霜粲華軒。", "風流故多奇，欲說非一言。", "但聞天下士，擾擾向龍門。", "豈知千丈髮，著此三家村。", "周餘喬木盡，始見邯鄲孫。", "茲行亦奇偉，可以詫仍昆。"]'),
('02d12598-1b4a-4243-9755-6f04f7f0c58a','後樊','項安世','宋','宋诗','song-poetry','','[]','後樊百君子，相對兩玉人。',48,'全唐诗/poet.song.146000.json','["後樊百君子，相對兩玉人。", "酴醾三月暮，篠簜四時春。", "俱懷冰雪姿，不競桃李辰。", "何以樹之背，恐受俗子塵。"]'),
('b01065a0-fa1b-4687-a3f0-4515080cd426','二十二日步上方廣寺觀蓮華峰雲氣異甚','項安世','宋','宋诗','song-poetry','','[]','曉發名溪莊，午飯馬跡庫。',264,'全唐诗/poet.song.146000.json','["曉發名溪莊，午飯馬跡庫。", "下車著芒鞋，扶杖陟岡路。", "碾槽深側足，石磴高舉步。", "初登黄茅嶺，稍入青箬霧。", "苔深灑綦偪，露重濕袍袴。", "水聲浩呼湧，山氣汩馳騖。", "傍傾眩欲落，上滑危屢仆。", "尋幽不憚險，已倦寧得住。", "荒程迷遠近，雜徑惡叉互。", "喜經茶園頭，漸見蓮岳處。", "喘汗扇方乾，驚魂招始駐。", "引領煩山僧，鞺鞳開閣戶。", "尖峯岌前陳，鳴水橫下注。", "浮嵐出奇巧，頃刻紛異趣。", "憧憧行市人，梟梟上烟炷。", "濃敷步障青，淡抹輕紈素。", "昏然俱晦冥，粲若忽陳露。", "穿窗來有情，掃迹去如怒。", "旋觀不忍捨，留宿當至暮。", "誰傳西嶺書，贈我碧雲句。", "云當上封頂，共看扶桑樹。", "棄置且行行，妙高臺上去。"]'),
('bc60da93-741d-42eb-85ce-1742ae99ffe9','高臺寺','項安世','宋','宋诗','song-poetry','','[]','高臺夫如何，山後此爲最。',72,'全唐诗/poet.song.146000.json','["高臺夫如何，山後此爲最。", "手摩白雲頂，足躡飛鳥背。", "我從樟樹來，上上八十里。", "向來所歷峯，下視皆積塊。", "空中聞夜雨，聲若萬馬潰。", "却問山前人，天晴正收刈。"]'),
('ac47de29-e363-428d-bf13-b492edfb8e3e','福巖寺','項安世','宋','宋诗','song-poetry','','[]','三日行東山，今朝度西嶺。',96,'全唐诗/poet.song.146000.json','["三日行東山，今朝度西嶺。", "山前福巖寺，高下得要領。", "下通赤帝廟，上徹祝融頂。", "回環生氣勢，開闢見光景。", "湘江獻五曲，嶽市陳萬井。", "青林間香稻，一一辨疆頃。", "頗憐東山隘，對此意方逞。", "居高能盡下，熟玩令人省。"]'),
('33e6ebfc-87d7-4623-889b-ca28812bedc6','六日坐法華寺東廊攬秀亭','項安世','宋','宋诗','song-poetry','','[]','西亭有名字，未若東亭寬。',72,'全唐诗/poet.song.146000.json','["西亭有名字，未若東亭寬。", "東亭攬秀者，一目萬峯巒。", "雲興勢浩浩，海立波漫漫。", "左見桂陽路，右見舂陵灘。", "入山恨不早，行路良獨難。", "晚來無頼處，渺渺送歸翰。"]'),
('468c30e4-803a-47f4-ac4d-381a35fde521','跋羅商卿守黑銘','項安世','宋','宋诗','song-poetry','','[]','大江從西來，傲岸有矜色。',240,'全唐诗/poet.song.146000.json','["大江從西來，傲岸有矜色。", "日與峽爭雄，百戰無虛刻。", "行逢天闊處，漭沆四無壁。", "始知向來事，何啻蝸兩國。", "泯然從此逝，到海不逢敵。", "居平吾語子，無與世爲的。", "我高人肯下，己勝誰甘北。", "孰謂饒人癡，未聞開殿擊。", "吾非若溪水，寧與世爭皙。", "卿言皆好好，吾見甘棫棫。", "老子邑中黔，諸公天下白。", "加我任纁緇，推渠作圭璧。", "君看千載下，人數孟之側。", "當時爭功人，枉被螻蟻食。", "之子真吾徒，敏捷流輩百。", "昔我惟子憂，教子孔氏克。", "隔宿不見之，已作老聃黑。", "快哉吾阿蒙，非復吳下客。", "瞥然見鞭影，千里纔一息。", "酌酒可賀我，正傳今有嫡。"]'),
('2e0dbc22-fbe3-4d36-8d53-faca043bec28','次韻趙領示先世石刻十四韻','項安世','宋','宋诗','song-poetry','','[]','天葩富奇芬，龍種多異姿。',168,'全唐诗/poet.song.146000.json','["天葩富奇芬，龍種多異姿。", "歆向妙經術，白賀工文詞。", "飄飄翰墨間，耿耿名字垂。", "哀哉趙延康，忠義反見疵。", "文工俗易愛，節苦人誰知。", "洪濤覆乾坤，赤手當路歧。", "剖心奉鵷雛，血面攘魖夔。", "至今陳宋間，凜凜英氣遺。", "飄零見諸孫，髣髴瞻舊儀。", "手澤皦如日，廟碑辭頗枝。", "談仙事滿紙，大節無一辭。", "想當施手日，俗論猶爭馳。", "一讀淚如雨，再讀還自思。", "古來盡如此，何獨爲君悲。"]'),
('0939f93c-67fc-4b84-96d9-b528fb92e7f9','次韻呈楊秘書','項安世','宋','宋诗','song-poetry','','[]','杞人懼天壓，夸父追日走。',96,'全唐诗/poet.song.146000.json','["杞人懼天壓，夸父追日走。", "智微思遠道，力小扶戾斗。", "豈非志士節，猶在君子後。", "恭惟魯東家，用大無不有。", "憂時甚援溺，慕主工自牖。", "時難亦勇退，義合豈株守。", "高第多偉人，言仕輒遭否。", "嗟予本何能，過涉欲濡首。"]'),
('2c0e404c-6863-49c9-abc3-c12cc39fd38e','呈陳正己十四韻','項安世','宋','宋诗','song-poetry','','[]','相識十五年，未有今日談。',168,'全唐诗/poet.song.146000.json','["相識十五年，未有今日談。", "沉沉千丈綆，窈窈太古潭。", "靈關乍掣鎖，寶藏初抽函。", "爲於萬億秭，出此一二三。", "戢戢騎無數，津津飴正甘。", "天驅遠色冥，日墮西暉酣。", "言歸澣垢澤，少俟收炎惔。", "凉風轉右桷，好月來東菴。", "聽君十日語，飫我平生貪。", "毫釐得細數，窾隙容周諳。", "萬象斗維北，八方車指南。", "明明繩尺陳，皎皎星月參。", "外物復何有，此懽誠可耽。", "願推輕財心，慷慨傾籝甔。"]'),
('fe26cac4-53f5-40ff-8018-2beeee805fa2','月硯屏','項安世','宋','宋诗','song-poetry','','[]','雲從林末起，水遶山根發。',144,'全唐诗/poet.song.146000.json','["雲從林末起，水遶山根發。", "古道無行人，疎星伴明月。", "不知幾千年，寶畫閟岩穴。", "鬰盤不可耐，飛入蒼崖骨。", "春霆震陰洞，斧首快一劃。", "鏗然墮人間，與世瑞文籍。", "自從歐公來，百載今又獲。", "當時硯屏歌，謫仙傾坐客。", "前人儻可驗，此美未易測。", "吾叔舊不癡，根蒂厚所殖。", "定爲子孫慶，可但几案飾。", "恨無大蘇手，對之有慙色。"]'),
('5c36f69f-dad3-4066-bdc4-ab398e0f6618','濯足萬里流','項安世','宋','宋诗','song-poetry','','[]','將子無涉水，水深下無極。',120,'全唐诗/poet.song.146000.json','["將子無涉水，水深下無極。", "鯈魚舞浮陽，螭首闖陰碧。", "弱去一羽沉，惡來萬波激。", "子兮何所求，快此蛟蜒滴。", "諫議起陽城，拾遺招李渤。", "望子子不來，羊裘號逋客。", "踞坐山石粗，晞髮朔風急。", "亂流兩白足，何日踔疎逸。", "子兮寧不悲，饑甿徯唐稷。", "豈其洛之涯，而可溫與石。"]'),
('74e0126c-10a4-498d-9928-c55fe3476954','嶺上見大江及匡廬諸峰','項安世','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','背立梧桐嶺，面對匡廬峯。',108,'全唐诗/poet.song.146000.json','["背立梧桐嶺，面對匡廬峯。", "江流過其下，渺渺去朝宗。", "萬山左右衛，如陣復如墉。", "壯哉天地間，偉觀人所鍾。", "自有此山來，來往嘗憧憧。", "豈是千載人，無有此心胸。", "定應出聖宅，山鬼閟其蹤。", "茲行亦奇事，突兀肯相供。", "多言恐怒我，急下扶吾筇。"]'),
('46f17e50-6795-4a01-8a64-fc44a28decd1','次韻重九','項安世','宋','宋诗','song-poetry','','[]','淵明平生意，豈但專一壑。',120,'全唐诗/poet.song.146000.json','["淵明平生意，豈但專一壑。", "心事如於菟，赤手未易縛。", "平陸多江湖，政恐失雙脚。", "竟携東籬花，歸伴南山鶴。", "千載得斯人，此道有郛郭。", "肝膽鬰輪囷，襟期渺磅礴。", "西風萬物表，洗醆與更酢。", "木落山勢高，江空水痕約。", "時來萸菊尊，日暮烏鳥樂。", "物理正可娛，新詩且勤作。"]'),
('1be77d2b-b778-4adf-945e-3314d635295c','有感','項安世','宋','宋诗','song-poetry','','[]','翹翹蔞楚中，名字或行世。',48,'全唐诗/poet.song.146000.json','["翹翹蔞楚中，名字或行世。", "當時在人口，既久漸湮廢。", "能于汗簡上，千萬見一二。", "想當無恙時，掀揭滿天地。"]'),
('9386d0c5-a317-44a0-ba96-1dd39dde3dfe','度周卿携司馬公送蒲中舍詩小程先生謁傅長官刺求跋','項安世','宋','宋诗','song-poetry','','[]','馬公首丹籍，程子亦其次。',60,'全唐诗/poet.song.146000.json','["馬公首丹籍，程子亦其次。", "大書天九門，凜凜見名字。", "度君獨何心，葅歜而剝芰。", "艓子大於匙，可卧不可跂。", "中有兩同行，馬詩與程刺。"]'),
('c15e3374-1487-434c-b1f4-84a32ad828ac','耕讀堂詩','項安世','宋','宋诗','song-poetry','','[]','朝騖兮吾疇，象舒兮鴉疾。',85,'全唐诗/poet.song.146000.json','["朝騖兮吾疇，象舒兮鴉疾。", "暮諷兮吾帷，風喧兮雨密。", "蓑衣兮臺冠，雪炬兮螢袟。", "田丁兮學子，耦歌兮儕習。", "米甘兮蔬旨，道腴兮仁實。", "養送兮無憾，俯仰兮有適。", "堯湯兮吾辟，豈吾欺兮伊稷。"]'),
('5914dbaa-2c0a-4c9c-a8e5-87b476c70af0','北窗詩','項安世','宋','宋诗','song-poetry','','[]','天高吾廬卑，南風不肯辱。',84,'全唐诗/poet.song.146000.json','["天高吾廬卑，南風不肯辱。", "頼有北鄰富，垣墉岌高矗。", "轔轔飈車來，欲去泥其軸。", "回轅乃臨臣，北戶清以穆。", "時時喚笙奴，一枕共清熟。", "向來北窗人，此秘當已獨。", "持我無絃琴，千載賡此曲。"]'),
('4ac2609d-e45b-4098-8cb8-da873a02d405','題袁才舉明景軒詩','項安世','宋','宋诗','song-poetry','','[]','孤竹兩高人，不止一清字。',288,'全唐诗/poet.song.146000.json','["孤竹兩高人，不止一清字。", "平生不念惡，和氣滿天地。", "後來展禽氏，但以和得聲。", "至其不易介，耿耿秋旻清。", "達人蓋存我，不與外物較。", "冥觀瑩方寸，隨俗等喧閙。", "由其有內外，所以立二名。", "要知出處間，何往非通明。", "入與神明居，如月出秋水。", "出與塵坌交，如蓮在泥滓。", "蓮雖不拒泥，終不與泥同。", "月豈必在水，亦在潢汙中。", "由然與之俱，餔糟汩其泥。", "退而省其私，炯若清廟圭。", "昔者吾先師，不拒中牟費。", "所貴不磷緇，不貴作同異。", "當時解此轉，惟有顓孫生。", "於人無不容，自有嘉與矜。", "嗟哉道不明，智過愚不及。", "清爲水底魂，濁爲瓜上集。", "鄉愿乘間起，遂處二者間。", "不夷亦不惠，以此容其姦。", "吾道大明鏡，皎皎當空垂。", "物來無揀擇，隨爾多妍媸。"]'),
('a1b7ee31-f1de-4d30-b752-868c394e816c','所見','項安世','宋','宋诗','song-poetry','','[]','客從岷山來，發棹江水頭。',48,'全唐诗/poet.song.146000.json','["客從岷山來，發棹江水頭。", "江水去無時，客子行復休。", "朝餐同一壑，歲宴隔九州。", "所以闕里翁，平生愛東流。"]'),
('b79afd09-9bef-43df-bb18-d0f0fae1f348','楊侍郎之姪有文劉左史之婭靖之携文見過','項安世','宋','宋诗','song-poetry','','[]','藍田鮮頑玞，鄧林無曲莖。',108,'全唐诗/poet.song.146000.json','["藍田鮮頑玞，鄧林無曲莖。", "春宗九秋月，性靜所燭精。", "柱史顔如春，和風蓄驚霆。", "兩家各有子，突過阮始平。", "忽念笭箵翁，淹劇卧漳城。", "興來枉華裾，情深出英瓊。", "沉疴爲之起，不覺語至暝。", "眄懷薛仲章，剛腸久逾清。", "吾衰俟三賢，潜心牧修程。"]'),
('1c4ebaf5-02f5-4514-ae67-5aa4b0215f0b','別陳監庫見磨玉璞者宋衡','項安世','宋','宋诗','song-poetry','','[]','吾愛陳元年，書生有英氣。',48,'全唐诗/poet.song.146000.json','["吾愛陳元年，書生有英氣。", "語戇人不嗔，酒失心自記。", "庭前有奇石，細滌復粗磨。", "我有淇澳詩，願與子同歌。"]'),
('8fb4cbf6-b369-4a55-8845-e8caa21b53c3','咏雪次鐸字痛字韵二首  其一','項安世','宋','宋诗','song-poetry','','[]','水官不能神，經歲無此作。',96,'全唐诗/poet.song.146000.json','["水官不能神，經歲無此作。", "春風一回首，風花散雲箔。", "飛來忽滔天，掃去不盈握。", "蒼茫大千界，歛散一圭角。", "似是絮無鹽，人情只輕薄。", "懷哉我來玉，小棹山陰泊。", "空江蓑笠中，此段有前約。", "扣舷歌商聲，黄鍾震牛鐸。"]'),
('40e05b2b-da1b-41f5-83b8-2f6dca4c4cc4','咏雪次鐸字痛字韵二首  其二','項安世','宋','宋诗','song-poetry','','[]','我詩已巴歈，曲短不成弄。',120,'全唐诗/poet.song.146000.json','["我詩已巴歈，曲短不成弄。", "君詩如郢人，白雲渺雲夢。", "天公震而矜，大地作一供。", "封姨不自惜，紛紛管迎送。", "須臾萬象滅，此世無與共。", "惟餘滄江水，不止亦不動。", "聳渠縞带袴，等用麻衣諷。", "寒梅自生香，古井亦受凍。", "松髯老不脫，歲晚見梁棟。", "此事且勿言，惟知飲當痛。"]'),
('40e22269-5b20-4f4f-9358-97d2ae50aaf3','小潏','項安世','宋','宋诗','song-poetry','','[]','鑿苔欲爲沼，乃得數仞坻。',48,'全唐诗/poet.song.146000.json','["鑿苔欲爲沼，乃得數仞坻。", "盈虛有相乘，川實而邱夷。", "誰云人功爲，天理固有之。", "向來小學師，此道渠得知。"]'),
('f485719a-89b1-4b6b-8fe4-3f2461b1811e','盧智子衡州親迎','項安世','宋','宋诗','song-poetry','','[]','初聞永嘉叟，招喚作師生。',48,'全唐诗/poet.song.146000.json','["初聞永嘉叟，招喚作師生。", "又見金華伯，扳聯作弟兄。", "雙峯真有子，二老總關情。", "所願勤詩禮，無令負甲庚。"]'),
('a3580cb9-46b2-43c5-83fa-7357672cfd67','次韻江陵張書記送行','項安世','宋','宋诗','song-poetry','','[]','行行得好辭，忽忽疑晝夢。',288,'全唐诗/poet.song.146000.json','["行行得好辭，忽忽疑晝夢。", "朝餐手不釋，夜卧心屢誦。", "皎若朱絲弦，清于玉壺凍。", "美人家三世，有筆修五鳳。", "詩從周漢學，不記梁與宋。", "深沉大招賦，汗漫長楊諷。", "玄機捩天關，遠思彌禹貢。", "詩人例空言，此士有實用。", "經權粲衡石，事物森紀統。", "上官畏爭執，疲俗感哀痛。", "情雖到真核，法必任寬縱。", "有才人所難，既老心不動。", "藴玉諱求沽，韜弦耻爭中。", "自言州縣久，差勝市朝鬨。", "歲晚無萬牛，江空偃孤棟。", "今年何因緣，諸使忽倥傯。", "倒海覓珊瑚，搜山出銀甕。", "似聞二星來，約與元帥共。", "推君上周行，爲國選湯衆。", "薦員每如此，物論寧不衷。", "泛水拔紅蕖，騰雲上青鞚。", "所悲賤子遠，不及諸賢送。", "投身伴鴞鵬，矯首瞻洛雍。", "天乎禍吾宗，伯也困淹訟。"]'),
('6e4fa65e-1edb-4eae-ae40-576ce97ef648','次韻江陵曹令祈雨','項安世','宋','宋诗','song-poetry','','[]','吾嘗言封侯萬里不直錢，不如洛陽負郭二頃田。',282,'全唐诗/poet.song.146000.json','["吾嘗言封侯萬里不直錢，不如洛陽負郭二頃田。", "清風午枕睡初熟，明月一甌吾自煎。", "門前䆉䅉新酒熟，丈夫肯受兒女憐。", "非不知鳴鐘與鼎食，雨蓑風笠性所便。", "有如北人事鞍馬，不信世間乃有萬斛之樓舩。", "老農對我忽三嘆，此事樂矣今無年。", "忍饑死待一啜菽，又見赤日懸青天。", "高田尺寸破龜兆，下田杪忽生針氈。", "𩖡風抒水乾七澤，火雲熾空炮百川。", "掘殘草實到黄壤，踏盡藕根傾碧圓。", "得錢買飯不及夕，豈復一飽期安眠。", "田家活計遽如許，苦語一聽雙潸然。", "天河誰能挽壯士，甘露更忍談高禪。", "紛紛官吏走香火，往往聚落無炊烟。", "雲雷虛無空霹靂，老稚失喜真狂顛。", "欲賡噫嘻頌祈穀，安得好語來愁邊。", "我詩窮悴不足錄，晴日叫號如饑鳶。"]'),
('df1438d8-7ceb-4cf1-b175-caf68376e01a','賀楊樞密新建貢院三十韻','項安世','宋','宋诗','song-poetry','','[]','楚囿七澤荒南雲，三江五湖同吐吞。',384,'全唐诗/poet.song.146000.json','["楚囿七澤荒南雲，三江五湖同吐吞。", "杞梓橘柚杶幹柏，芷蘺椒桂蘼蘭蓀。", "天英地靈聚爲人，魁壘詭異難具論。", "屈原離騷二十五，句句字字皆瑶琨。", "六朝弼亮胡伯始，學士登瀛劉季孫。", "恭惟火德據天統，翼軫正值鶉賁賁。", "質肅聲名海山動，諫議才氣淮湖奔。", "日中則昃固其理，城復于隍吁忍言。", "生聚教訓五十載，昔無萌孽今輪轅。", "堯湯立賢遍天下，九重科詔如春溫。", "州家不辦一椽屋，往往盛之給孤園。", "鵠袍竹笥合羞死，况欲開口人其髠。", "關西夫子楊伯起，後身把鉞來西門。", "荆棘之藪瓦礫場，一日汗礎千猊蹲。", "翼飛革棘不可狀，鐵畫怒起翔鸞鵷。", "日者稽山始開闢，已有大策當臨軒。", "吾州故事有元祐，追配詎肯慙東藩。", "晚生科第愧前轍，考室誤使當罍樽。", "向來氣習今未已，猶夢裹飯趨晨閽。", "一官却恨大早計，不得掉鞅驂鵬鵾。", "明年珍産入包貢，琳琅璀磊堆金盆。", "蓬萊弱水三十萬，借以鼓吹看橫鶱。", "吾儕小人科舉士，一朝出守忘其源。", "臺池崇深學校廢，况此贔屭楹梁尊。"]'),
('c7af48c9-7276-41be-92fe-44d657a1e11d','次韻吳襄陽寄示遊楚山詩','項安世','宋','宋诗','song-poetry','','[]','漢江南北何縈紆，千山萬山肩相扶。',176,'全唐诗/poet.song.146000.json','["漢江南北何縈紆，千山萬山肩相扶。", "中間偉然一丈夫，峴山之楚鹿門蘇。", "我行一舍到蘇嶺，憶與許子同奔趨。", "楚山只在城南隅，一月不到何其迂。", "遠求白傅近舍湜，人情未怪瑟與竽。", "梯飈自到絕徑處，使君定是昌黎徒。", "想當伐山開道時，野鳥驚去窮猿呼。", "獨携千古兩耆舊，卧龍鳳雛與之俱。", "下看海內無所見，淚落漢水心長吁。", "我雖不得從公輿，誦公之詩讀公書。", "掛之高堂心目舒，便是居士遊山圖。"]'),
('8b0e0c6a-5a09-48fa-b509-f7abbf582401','高風臺歌','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','臺之高不知其幾仞兮，但見燕雀仰視如冥鴻。',320,'全唐诗/poet.song.146000.json','["臺之高不知其幾仞兮，但見燕雀仰視如冥鴻。", "風之來不知其幾里兮，但見南海北海聲逢逢。", "我時醉卧洞庭之北巴山東，耳邊澒洞呼洶怖殺儂。", "起來欠伸拍鴻蒙，問誰作此狡獪變化驚盲聾，乃是清江江上盤園翁。", "翁本自與時人同，袍带靴笏從兒童。", "亦嘗隨牒作小史，亦嘗建纛稱元戎。", "偶然興盡自返盤園中，意行倦止由心胸，豈與郢中小兒論雌雄。", "兒曹顛倒鷄著籠，金朱瞇眼視夢夢。", "仰見騄驥脫鞅行青空，便欲俎豆老子配食蜚廉宮。", "紛紛俗論安足窮，二三君子人中龍。", "南安太守科甲高，袖有桂館之香風。", "廬陵相公名位高，筆有造化之春風。", "雨巖居士卧榻高，句有湖海之英風。", "三君合謀奏天公，急羈此老勿使慵。", "國於羊角九萬里，奄有九霄寒露之空濛。", "封師巽伯爲附庸，不許抗表辭官封。", "向來挂冠冠愈穹，老子一笑朱顔紅。"]'),
('5e758e51-5d0d-417a-8523-90755e48a1c8','寄題荆南王君行牧齋','項安世','宋','宋诗','song-poetry','','[]','千斤黑牸將黄犢，八歲山童手堅竹。',320,'全唐诗/poet.song.146000.json','["千斤黑牸將黄犢，八歲山童手堅竹。", "呵牛行前童御之，坤艮爲謙直初六。", "夷山入地山已庳，微陰更在山之麓。", "觀爻玩象謙復謙，不待占辭意先足。", "姬公作繇更何言，利用直堪航四瀆。", "雖然用著體未明，後學相尋誰與告。", "拳拳魯叟重抽關，此路欲行須自牧。", "有如子稚母更柔，弭耳阿童惟所逐。", "曉隨鞭影上岡巒，暮載歌聲返茅屋。", "不知身大童子小，但覺氣和情性熟。", "王郎於我丈人行，少秉謙爻晚尤篤。", "自稱身是牧牛人，不向天家請官粟。", "書來蜀道告我言，牧事年來有條目。", "成時直到東家矩，造端先自西鄰牿。", "邪閑誠存定章程，石確龍潜防反覆。", "已將四語了卿法，更用一言從我卜。", "我生冉冉向無聞，此事駸駸下喬木。", "三年道路寡師友，萬里奔馳妨誦讀。", "角羈聞道老無成，此語最悲那可復。", "急須水落下夔門，走向牧齋聽一曲。"]'),
('9a938583-5f66-4828-abdf-2a900f1848dd','次韻蘇主管大礬山歌','項安世','宋','宋诗','song-poetry','','[]','我昔典司群玉峯，中有一峯如此雄。',224,'全唐诗/poet.song.146000.json','["我昔典司群玉峯，中有一峯如此雄。", "層珪累璧以億計，垂棘懸黎知幾重。", "瑶墀日上光煜爚，琪樹風過聲冬瓏。", "依稀西母翳白鳳，彷彿波神驅玉龍。", "自從失脚墮塵土，無復有夢登芙蓉。", "扁舟獨釣秦淮月，忽見當年眼中雪。", "蘇郎那得便欺人，云是來從武都穴。", "春深猶在玉皇家，秋杪却安淮海宅。", "誰歟有力負之走，夜半贔屭群鼇力。", "自是蘇郎有仙骨，造物向君難久嗇。", "遂令仙聖役鬼工，預割雲根分半席。", "亦知客子是前官，送與新詩合消得。", "客今跛鱉行步慳，無復鰲背觀鯨瀾。", "何如舉此爲客壽，却送蘇郎登道山。"]'),
('f2f32074-5d5d-45bb-9a39-c0d31021939a','次韻蘇主管小礬山歌','項安世','宋','宋诗','song-poetry','','[]','大字崢嶸如石柱，小字參差似釵股。',256,'全唐诗/poet.song.146000.json','["大字崢嶸如石柱，小字參差似釵股。", "醉中寫出礬山歌，夢中飛入礬山路。", "恍然身在家林間，壺公八柱橫當前。", "并州剪刀色如水，剪取一半壺公煙。", "袖歸閣置晴窗著，相伴匡牀閒企脚。", "渾家驚喜看不休，一拳寒雪春未收。", "但怪長身成縮瑟，不見當年倚天立。", "昔如四輔朝帝鄉，今如侏儒欄楯旁。", "元是山靈有詩癖，要來丈室親詞客。", "帝令費老下教之，千仞高崖縮盈尺。", "又怪素髮垂冰膚，不見當年青玉腴。", "昔如婑媠春風髻，今如點滴銀盤酥。", "元是山靈生老思，時世梳妝非所喜。", "帝令河漢下濯之，洗盡烟嵐見雲子。", "四翁相對凜不他，正味森森酸齒牙。", "更著瑒花成五友，同名共色相輝華。"]'),
('ed214be2-4a02-4fcb-8cd9-380c200b2ab3','次黄司戶紅糟韵四首  其一','項安世','宋','宋诗','song-poetry','','[]','督郵面上多赬紅，如此娬媚非真容。',64,'全唐诗/poet.song.146000.json','["督郵面上多赬紅，如此娬媚非真容。", "向來清白不受采，正氣本自天和鍾。", "爾來施朱學時樣，調羹亦復資醲豐。", "急須破甕覆殘滓，勿以軟美宜新菘。"]'),
('cee108b1-6734-4e24-a018-91fba05bde5c','次黄司戶紅糟韵四首  其二','項安世','宋','宋诗','song-poetry','','[]','江南水作桃花紅，釀成十五女兒容。',64,'全唐诗/poet.song.146000.json','["江南水作桃花紅，釀成十五女兒容。", "眉山先生忽驚見，一曲便欲拚千鍾。", "誰傳春信過江北，小槽殘滴何能豐。", "相逢但欲覓苴滓，杯羹爲薦霜畦菘。"]'),
('71fc9996-1e1f-4313-b8cf-e4f18c42af9e','次黄司戶紅糟韵四首  其三','項安世','宋','宋诗','song-poetry','','[]','主人厨中魚尾紅，把酒一笑相爲容。',64,'全唐诗/poet.song.146000.json','["主人厨中魚尾紅，把酒一笑相爲容。", "燕脂煉就玉雪汁，琥珀光透琉璃鍾。", "酒酣萬事忽驚散，捽耳頓足歌年豐。", "連缸拗倒同一醉，尺鐵爲我髠園菘。"]'),
('3f6833b5-509a-49cf-81e8-9ae6188bf5b8','次黄司戶紅糟韵四首  其四','項安世','宋','宋诗','song-poetry','','[]','世人兩眼迷青紅，百憂一笑無歡容。',64,'全唐诗/poet.song.146000.json','["世人兩眼迷青紅，百憂一笑無歡容。", "仙官美祿不肯受，白首世路誇龍鍾。", "高人箕踞得所籍，焦柈不羨天厨豐。", "我欲從君覓羹法，有田種秫園栽菘。"]'),
('b65d2d99-479b-463f-9f26-c8eb544ea730','贈張術人','項安世','宋','宋诗','song-poetry','','[]','霅川張姓彪其名，惠而過我古津亭。',288,'全唐诗/poet.song.146000.json','["霅川張姓彪其名，惠而過我古津亭。", "自言有術通心靈，西庚北壬甲與丁。", "配以十二珠躔經，水火木金相孕刑。", "錯綜三五命與星，參鈎互鞠窮年齡。", "劇談娓娓如反瓴，又言兩眼能白青。", "疈析聲氣區神形，窮達壽夭分渭涇。", "善而藏之不露型，但見瞳子光晶熒。", "衆中諦視若有聆，猶以幹支鳴說鈴。", "參錯開解紛相訂，我生之歲劍發硎。", "我生之月神玄冥，二陽隠隠升泉扃。", "天階熠熠舒六蓂，正值玉兔開雲屏。", "兩凡跳擲不暫停，此身於世如浮萍。", "擾擾萬事通醉醒，死生禍福輕晨暝。", "更用剡折篿與筳，况復骨相真伶俜。", "安得雙鱗懸萬釘，荷君好語空叮嚀。", "斥鷃傅以雙鳳翎，衣十二翮蹌堯庭。", "此語恐是俳與伶，豈有大藥須豨苓。", "他時遇我眠寒廳，君莫諱世赬而頩。"]'),
('971c5c58-707e-4db7-ac3f-48955e426615','有感','項安世','宋','宋诗','song-poetry','','[]','大江千里從西來，憑陵三峽喧如雷。',96,'全唐诗/poet.song.146000.json','["大江千里從西來，憑陵三峽喧如雷。", "自矜萬頃臨一杯，湧起雪浪吞崔嵬。", "一過荆門楚天闊，七澤茫茫如滅沒。", "波神潜聲不敢發，汩汩安流到吳越。", "世間驕吝亦等耳，未見大方俱有已。", "藩籬决破定無他，令人爲賦江之水。"]'),
('f7c83400-16d2-4456-aef3-31d14a78bf5c','次韻答席蕃秀才論春秋','項安世','宋','宋诗','song-poetry','','[]','北冀之土南交州，瓜戎直西東泗浮。',240,'全唐诗/poet.song.146000.json','["北冀之土南交州，瓜戎直西東泗浮。", "中間代霸若桃梗，列國聚散同夫不。", "史編斷爛雜蟲鼠，野記紛綸充馬牛。", "驚雷破聵目開瞽，上起蔑歃終麟遊。", "玄鉛書字亦刀削，如木遇扁金逢歐。", "不同釋子付泡幻，肯信蒙叟判浮休。", "妍皮醜骨區萬態，大川小港條千洲。", "年深未免成伯帛，聲亂已復還邾鄒。", "崛興啖趙倚天斧，嗣有陳胡橫海舟。", "群言一劃露初意，後學平濟無千憂。", "當時豈爲題目計，此日寖成場屋流。", "橫穿異義作同體，立取貴綬驅雄騶。", "席君吾倩好兄弟，蜀郡此學多聲猷。", "得來三歎出詩本，昉此一笑同茶甌。", "願披一十九萬字，與子斟酌更獻詶。"]'),
('daf2c450-c7a2-4a94-9bf5-eb26c2e2b125','歸州女','項安世','宋','宋诗','song-poetry','','[]','歸州女兒雙髻丫，手提酒瓶頭戴花。',147,'全唐诗/poet.song.146000.json','["歸州女兒雙髻丫，手提酒瓶頭戴花。", "左手持盃右手瀉，灘頭勸客爭邀遮。", "灘頭一船百夫挽，欲上未上頭捽沙。", "呼聲半竭力欲盡，粟米一釂勝流霞。", "腰間五錢豈足惜，釧中十指如春芽。", "顔行屬目百丈縱，三老發怒雙槌撾。", "頩然相顧各分散，頃刻捩柂如輕槎。", "君不見世間勇怯皆如許，意根一斷前無禦。", "多少功名蓋世人，一點依違笑千古。"]'),
('f41d6980-511b-41a1-8419-41e2a05252c9','士師詩','項安世','宋','宋诗','song-poetry','','[]','畫邱置學明如星，頑民殄戮何可矜。',64,'全唐诗/poet.song.146000.json','["畫邱置學明如星，頑民殄戮何可矜。", "井田一變鄉校廢，斯民何往非干刑。", "三復名言子曾子，不獨陽膚當守此。", "未經師傅兒猶癡，盡在哀矜君勿喜。"]'),
('925f3128-e19b-4652-ad72-36d9ffa93b52','三十日過班竹賦玉州之木一首','項安世','宋','宋诗','song-poetry','','[]','玉州之南土當木，玉州之北木爲竹。',67,'全唐诗/poet.song.146000.json','["玉州之南土當木，玉州之北木爲竹。", "以土築室土則榮，以木編籬木應辱。", "無木用土固其宜，有木何忍賤用之。", "嗚呼，玉州之木最可悲，不爲楹桷爲藩籬。"]'),
('d71f2d09-555b-4197-8d20-5c1c2a0329e4','十月初還潭州題王氏瑞竹圖','項安世','宋','宋诗','song-poetry','','[]','王君手持瑞竹圖，要我作詩仍自書。',172,'全唐诗/poet.song.146000.json','["王君手持瑞竹圖，要我作詩仍自書。", "我書不慳詩亦易，政坐此君難位置。", "我欲摇毫寫作雙竹吟，却教數節一幹非商參。", "我欲援琴撫作孤竹曲，又見二妙同升異煢獨。", "卜子夏，子可爲我謳，一桴二米秬黍秋。", "清人一韔攢雙矛，肥泉同本末異流。", "觀射父，子可爲我釋，一少二多何卦策。", "以奇承耦震初爻，以耦承奇兌三索。", "我爲二人書此言，請君持歸君家看。", "展卷一問青琅玕，是易是詩然不然。"]'),
('782a10ee-f496-4122-a0e8-dd2e489e3ae7','送李知縣赴蘄州廣濟','項安世','宋','宋诗','song-poetry','','[]','江頭雪霽冰河折，日照江光動春色。',128,'全唐诗/poet.song.146000.json','["江頭雪霽冰河折，日照江光動春色。", "青絲快馬踏香泥，畫鼓方舟送行客。", "已驚柳葉大如指，忽見梅花飛著額。", "草根青軟濕鍼氈，枝頭綠淡摇金碧。", "眼看客子過淮南，春逐檣竿起江北。", "客帆漸遠春漸深，一路濃香慰行役。", "懸知上日春更好，桃李漫山獻紅白。", "何時我亦下滄浪，把酒蘭亭訪今昔。"]'),
('2b51d65b-249e-4fad-bcfc-107d1996606b','賦運使張大監道州石山以張詩平地風瀾險於水此心鐵石聽之天爲韻','項安世','宋','宋诗','song-poetry','','[]','枚回洲邊春水生，日光照縠波文平。',386,'全唐诗/poet.song.146000.json','["枚回洲邊春水生，日光照縠波文平。", "繡衣使者何世上，綵舟喚客論交情。", "平生擇交不擇利，俗子紛紛卧之地。", "少年所識惟石君，晚歲相從不相棄。", "一官到處西復東，悲歡得失無不同。", "誰云我州大如斗，中有千岩萬壑含松風。", "邇來所得尤艱難，人力不到天爲剜。", "幽尋五嶺犯炎霧，裹送萬里穿狂瀾。", "十夫舁前一夫洗，落盡煨塵見雲巘。", "回首笑向道州守，此解未如人世險。", "頭顱已過羊腸車，不用更通丞相書。", "老來得此萬事足，摩挲蒼璧相倚於。", "玉簾嶄嶄何齒齒，質堅德重不可徙。", "要鎸𡊢口方玉池，更酌西嶺玻璃水。", "小却盛之數畝園，日夕與之同卧起。", "客來莫怪我自憐，老子心情正如此。", "大山嵯峨勢千尋，小山左右羅瑶簪。", "坡陀峭立各有態，面目雖異同肝心。", "叩之其聲清以越，如磬之石鐘之鐵。", "怕令去作清廟器，潜向江頭□□□。", "江頭之月今幾年，慣見東西南北客。", "凜然相對各無慙，惟此主人伴此石。", "主人說法石解應，夜深哦詩使之聽。", "垠崖劃斷聲雷硍，有語盤空如此硬。"]'),
('8b9536aa-dc82-4f56-82af-2e48259a3a91','宣帝','項安世','宋','宋诗','song-poetry','','[]','宣皇開口嫌俗儒，要知不是憎詩書。',64,'全唐诗/poet.song.146000.json','["宣皇開口嫌俗儒，要知不是憎詩書。", "多文少實果何取，國家棄爾如糞土。", "卓然高見亦大奇，懲羹不謂真吹虀。", "漢家德意自此盡，王業豈是元成衰。"]'),
('e9dbe439-b02a-4490-a969-58f8cbded9bf','衡州城下見蒸水來會','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我從沅湘到石鼓，既見蒸湘喜無度。',64,'全唐诗/poet.song.146000.json','["我從沅湘到石鼓，既見蒸湘喜無度。", "爲誰觸熱向零陵，更有瀟湘在前路。", "樂哉湘水是吾師，挹彼三川盡注茲。", "世人惟聞洞庭闊，誰知鏵觜但如絲。"]'),
('1e87a630-25ed-43e8-b1e4-9f30abb539f8','次韻鄂州吳少保南樓','項安世','宋','宋诗','song-poetry','','[]','武昌城頭起高閣，下見二江爭一壑。',160,'全唐诗/poet.song.146000.json','["武昌城頭起高閣，下見二江爭一壑。", "滔滔還作一江流，底用相遭苦相惡。", "庾公當日此登臨，拊髀北風思遠略。", "簷開歷歷漢陽樹，多少雄心入開拓。", "暮年出手竟搶攘，千丈濤頭空寂寞。", "何如乘月坐胡床，且共諸人跨鸞鶴。", "平生枉恨王公弱，要是王公高一著。", "古來經濟有包荒，憒憒故應强鑿鑿。", "只今遺址向千年，又見神州□□索。", "憑欄堪賞亦堪嗟，長使遊人望關洛。"]'),
('787be300-0517-4ca3-9ee4-b4add9f4ba34','次韻張安撫李侍郎同賦茯苓酥','項安世','宋','宋诗','song-poetry','','[]','山人採藥晞喬松，披雲扶石松根空。',224,'全唐诗/poet.song.146000.json','["山人採藥晞喬松，披雲扶石松根空。", "搗霜餌玉得不死，大藥真與神靈通。", "論功合在金石上，何意坐隨脂澤融。", "誰令千古玉環穢，涴此萬壑寒林風。", "煎膏桐乳彼何物，滑咽潤頰誇微功。", "嗟哉可弔不可賀，吾道至此寧非窮。", "梁公一生面如鐵，阿武家兒看花月。", "魯公言言秋霜烈，作文佞仙要仙訣。", "曲江翻愛軟美人，此理至今吾未徹。", "元忠獨立孟青時，晚歲脂韋事凄切。", "微之年少本不凡，老作瓜蠅豈非拙。", "精金和鉛怕先缺，脂麻煮茗那可說。", "千年妙質當珀化，一啜微甘差劍吷。", "作詩自警勿示人，同志相期在全節。"]'),
('f460b3a2-4c0b-40cf-a067-64bf4fe13027','凱歌','項安世','宋','宋诗','song-poetry','','[]','今年三月三，樂事今古稀。',222,'全唐诗/poet.song.146000.json','["今年三月三，樂事今古稀。", "嘉陵江到武昌口，此時此日同□□。", "北人不敢恃鞍馬，西人不敢憑山谿。", "德安有高悅，匹馬穿重圍。", "入城助守膽如斗，出城决戰身如飛。", "城中扶出王與季，城外逐出信與隨。", "襄陽有趙淳，默坐誰得窺。", "一日熏盡西山狐，二日網盡東津鯢。", "三日開門看江北，一人一騎無殘遺。", "興安有安丙，談笑戮吳曦。", "僞王亂領出深穀，長史捷布登前墀。", "銅梁玉壘見天日，瞿塘灧澦無蛟螭。", "鄂州有老守，頭白尚能詩。", "上言吾君善委任，下言吾相能指麾。", "國家九九八十一萬歲，璘雛褒孽休狂癡。"]'),
('86b2e193-322d-44b3-ba7a-899f082ea37c','和韻送方翔仲赴省  其一','項安世','宋','宋诗','song-poetry','','[]','無問其詳問其畧，奏牘於今祖誰作。',80,'全唐诗/poet.song.146000.json','["無問其詳問其畧，奏牘於今祖誰作。", "三年戍卒箭痍深，長夜破膽鐎銅音。", "文皇不共□□□，三五須從賈生說。", "曲江賜酒黄封瓶，仙韶度曲宮花明。", "江東六月歸來早，江西先拜梭山老。"]'),
('a8438e48-39a6-482e-bad8-eb8a4e23339d','和韻送方翔仲赴省  其二','項安世','宋','宋诗','song-poetry','','[]','蘇子書中撏策畧，葉家肆裏偷新作。',80,'全唐诗/poet.song.146000.json','["蘇子書中撏策畧，葉家肆裏偷新作。", "南宮卷子不須深，句順聲諧即好音。", "調古曲高雖句絕，辭嚴意密誰箋說。", "清泉白鹵貯銅缾，磨松展楮霜毫明。", "三題奏罷宮門早，行過郎闈驚閣老。"]'),
('a778ecce-c400-4e4e-a37a-69bce8fa7348','寄友','項安世','宋','宋诗','song-poetry','','[]','君爲閒客過登朝，我車日過南湖橋。',192,'全唐诗/poet.song.146000.json','["君爲閒客過登朝，我車日過南湖橋。", "聽君論詩發幽秘，問君索酒澆岧嶢。", "誰將君賦告天子，武皇夜喚相如起。", "明朝車馬滿街來，從此相望隔湖水。", "欲往從君足似攣，馬嘶僕顧不能前。", "時憑栩栩枝頭夢，往看娟娟池上蓮。", "詩盟掃地心如失，酒債無錢甘首疾。", "綠楊門巷過春風，粉籜園林空夏日。", "半年不奈此悲凉，無計挽君歸野塘。", "不如我自解章紱，却爲閒客來君傍。", "飲竭君家酒千斛，吟盡君家紙千軸。", "醉中扶上木蘭舟，秋浦月明秋水綠。"]'),
('434659e9-f182-49e4-87b5-2c7404146d86','以法華寺爲試院擬題于子厚之西亭','項安世','宋','宋诗','song-poetry','','[]','三旬襆被西亭宿，卧對唐碑看不足。',48,'全唐诗/poet.song.146000.json','["三旬襆被西亭宿，卧對唐碑看不足。", "重闈鎖斷夕陽天，恰似當時萬竿竹。", "直須徹棘對愚瀟，始見西亭真面目。"]'),
('09068764-e63a-45ac-b022-36a8d6879658','爲建昌南城包顯道題光風霽月之閣','項安世','宋','宋诗','song-poetry','','[]','扁以槐堂之鉅筆，銘以雲谷之高辭。',96,'全唐诗/poet.song.146000.json','["扁以槐堂之鉅筆，銘以雲谷之高辭。", "鎮以平園之籤帙，照以太極之肝脾。", "千巖萬壑轉芳氣，青天碧海流清規。", "春晨畫出舞雩詠，夜景看成彭澤詩。", "勉哉此事要真積，昔者所聞無坐馳。", "願追策驥予陶子，勿但嘐嘐如牧皮。"]'),
('0bce8a9d-af74-42c3-8f39-148cc62b4a39','楊梅','項安世','宋','宋诗','song-poetry','','[]','吾家里曲修家木，葉如海桐實如穀。',147,'全唐诗/poet.song.146000.json','["吾家里曲修家木，葉如海桐實如穀。", "聞名謂是金作丸，見面恍驚珠奪目。", "直將甘軟換嚴酸，坐使筠籠薦金屋。", "越山五月垂垂雨，鼎實無聲渠甚武。", "雕盤供蜜漬中乾，犀筯下鹽蘇齒楚。", "蔗糖煎實茗煎仁，枯腊猶堪詫兒女。", "稜梅一種腰如束，歲歲年年官所錄。", "城中貴買誰得知，城外賤科人自哭。", "君不見瀘戎荔子翠眉須，從來尤物非人福。"]'),
('b2e40457-0789-4eb3-b960-eb55ee153dd9','和黄醇甫將行赴范侍郎海棠夜宴八韻','項安世','宋','宋诗','song-poetry','','[]','花鬮酒令不須探，但對此花須醉酣。',128,'全唐诗/poet.song.146000.json','["花鬮酒令不須探，但對此花須醉酣。", "花頭露重春的的，花樹雲暗天曇曇。", "美人醉後欲無力，小婦困來微带慙。", "蜀王宮畔客當去，召伯堂前人罷參。", "離歌未動酒如海，花徑漸昏雲作龕。", "急呼千炬夜光起，緩引百柂春波涵。", "照花莫睡共花飲，泥客作詩停客驂。", "詩成酒盡花亦落，客子一去天西南。"]'),
('8211e90c-6fb4-4719-98d4-358d837b166b','次韻周子問相勉求官詩','項安世','宋','宋诗','song-poetry','','[]','我纓却要滄浪清，我足但可雲門行。',96,'全唐诗/poet.song.146000.json','["我纓却要滄浪清，我足但可雲門行。", "頭顱四十中底用，阿婆縱好難爲新。", "强塗脂粉老自愧，旋學鬢鬟梳不成。", "憶初少日心自驚，蹙踏萬里長風生。", "昂藏天馬出西極，浩蕩河漢方東傾。", "老矣只今無許事，菰蒲深處一鷗輕。"]'),
('9f68f404-2d42-4941-afd9-0e2f2db9f83d','送承甫兄往長陽山從學詩','項安世','宋','宋诗','song-poetry','','[]','正月已暖春無寒，江深水淺沙觜乾。',256,'全唐诗/poet.song.146000.json','["正月已暖春無寒，江深水淺沙觜乾。", "東風日日送行客，我來踏遍江之干。", "昨日送客東入浙，今日送客西入灣。", "旁人但笑入灣拙，豈料此行人所難。", "吾宗豪俊自天賦，已有名字登春官。", "功名迫人不肯受，問官乞取三年閑。", "爾來政恐未能免，俛首却入樊籠間。", "揮金釃酒少時事，一笑昨夢何瀾翻。", "山中范蠡有孫在，老手未試人所嘆。", "幡然願執弟子禮，拏舟自入長陽山。", "人言此去幾百里，井里蕭索惟榛菅。", "度君自沮君不顧，學貴就道寧求安。", "聞猿莫起欲歸想，見山只作爲仁看。", "但令此志久不墮，九萬地里俱平寬。", "歸期已約槐花熟，努力加餐互相祝。", "今年看我亦高飛，明年上林兩黄鵠。"]'),
('e03c92de-438b-4efd-99a4-021061da13d6','次韵孫司戶黄堂觀醮遇雪','項安世','宋','宋诗','song-poetry','','[]','江陵舊識李謫仙，向來一夢今恍然。',144,'全唐诗/poet.song.146000.json','["江陵舊識李謫仙，向來一夢今恍然。", "依然斗酒詩百篇，鎪剔造化供清妍。", "妙意直到天皇先，長歌短曲何蟬聯。", "龍螭蛟鰐紛連蜷，黄冠作禮邀雲軿。", "珠幢玉節來蹁躚，玉川再拜瞻上玄。", "磬聲縹緲空中傳，僾然欲見非眇綿。", "水花冰葉來滿筵，清寒徹骨思嚙氈。", "蓬萊玉霄雲氣連，人間化鶴三千年。", "皎皎忽悟三生緣，當時誤讀青瑶箋。"]'),
('4de89d0d-ac6f-4d30-b425-51992b1cc942','跋林和靖手書所作三十聯','項安世','宋','宋诗','song-poetry','','[]','唐人作詩先作聯，一聯一句名幾年。',96,'全唐诗/poet.song.146000.json','["唐人作詩先作聯，一聯一句名幾年。", "後來作者如崩川，去千百里無洄沿。", "又如商鞅壞井田，夷封溝洫開陌阡。", "吟哦一變成號顛，秦張功甫出此編。", "我讀未竟心犁然，借歸手抄家自傳。", "藏之篋笥待後賢，庶萬有一唐風還。"]'),
('8297d1f0-cd5d-4191-9bda-73220449d905','寒食輿病上冢道中即事','項安世','宋','宋诗','song-poetry','','[]','二年不踏長隄路，十里春風只如故。',64,'全唐诗/poet.song.146000.json','["二年不踏長隄路，十里春風只如故。", "高高下下桃李坡，整整斜斜楊柳渡。", "花飛絮走君莫驚，燕語鶑啼方好聲。", "滿地綠陰無限句，際天幽草幾多情。"]'),
('18c9bf78-9fee-4c1a-b88e-c24773987d77','又寒食日見紫荆花有懷三館','項安世','宋','宋诗','song-poetry','','[]','東君老去梨花白，緋桃占斷春顔色。',64,'全唐诗/poet.song.147000.json','["東君老去梨花白，緋桃占斷春顔色。", "剩紅分付紫荆枝，回首千花盡陳迹。", "汗青庭外曲池濱，憶昔攢葩繞樹深。", "不解花枝緣底事，也來江上看閒人。"]'),
('fcdb5148-3563-4c4f-bba9-6e95bc24f345','題畫扇','項安世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','前舟半出垂楊港，兒子把篙翁撒網。',160,'全唐诗/poet.song.147000.json','["前舟半出垂楊港，兒子把篙翁撒網。", "後舟兒小未能篙，媼自哺雛斜刺舫。", "何處兩生來看魚，野服綸巾意森爽。", "路窮有叟獨施罛，短策驚魚水聲響。", "隔岸誰家蓋茆竹，軒楹閴寂無來往。", "臨溪曬網不知收，斜日欲歸天莽蒼。", "去年我作月宮遊，此景西湖恣探賞。", "歸來和月剪并刀，得此一泓寬夢想。", "日長弄扇忽成眠，第一橋邊蕩蘭槳。", "覺來風雨浪粘天，急喚小舟真欲上。"]'),
('9d12687e-134d-48a4-9661-a9346231a01a','小桃花曲','項安世','宋','宋诗','song-poetry','','[]','花如郁李枝如柳，小桃起得梅花後。',64,'全唐诗/poet.song.147000.json','["花如郁李枝如柳，小桃起得梅花後。", "柔柔冉冉不禁風，密密排排渾是繡。", "長瓶綠水短窗前，病客相依伴晝眠。", "夢跨玉驄花畔去，黄金絡腦紫籐鞭。"]'),
('d1ce220f-37a8-45e8-a8d8-f35d82a6523d','寄羅主管四首  其一','項安世','宋','宋诗','song-poetry','','[]','四海羅夫子，乾坤識此心。',48,'全唐诗/poet.song.147000.json','["四海羅夫子，乾坤識此心。", "貌真南似北，人是古居今。", "老大胸懷苦，優游歲月深。", "諸公用之武，莫待二毛侵。"]'),
('15aa2c26-03c5-482d-802a-684ffafb9863','寄羅主管四首  其二','項安世','宋','宋诗','song-poetry','','[]','把酒東南望，關心歙水邊。',48,'全唐诗/poet.song.147000.json','["把酒東南望，關心歙水邊。", "三君同別我，小友不論年。", "賈虎風行地，王珠月映川。", "州人亦驚倒，此客定能賢。"]'),
('9fd52ea1-c1a5-4a27-8ee3-2307dcbd5d53','寄羅主管四首  其三','項安世','宋','宋诗','song-poetry','','[]','可惜經年別，都能兩日留。',48,'全唐诗/poet.song.147000.json','["可惜經年別，都能兩日留。", "別來長似夢，書到暫忘憂。", "老子無公事，長安足俊遊。", "時時論人物，江漢有輕漚。"]'),
('c3a592d8-f90d-41ba-8861-cbca3ee00dcf','寄羅主管四首  其四','項安世','宋','宋诗','song-poetry','','[]','客有甄卿子，師行八面奇。',48,'全唐诗/poet.song.147000.json','["客有甄卿子，師行八面奇。", "談禪兼學道，愛酒更能詩。", "聞說今同事，長懷舊接辭。", "無人自娛戲，多病欠醫治。"]'),
('faea5948-61e3-4b08-a530-6404c40997bd','紹興送彭世昌歸應鄉舉','項安世','宋','宋诗','song-poetry','','[]','客有功名志，時平未急才。',48,'全唐诗/poet.song.147000.json','["客有功名志，時平未急才。", "淚臨淮水落，眼向越山開。", "且著萊衣去，仍隨桂子來。", "春明見天子，可以議雲臺。"]'),
('e28f2d5f-6d95-4ef6-875e-571fcfe505a9','晚晴','項安世','宋','宋诗','song-poetry','','[]','一雨草木潤，新晴天地明。',48,'全唐诗/poet.song.147000.json','["一雨草木潤，新晴天地明。", "山川未改色，鳥雀已歡聲。", "客子喜相語，田家憂未平。", "似聞陂偃拆，掘井得深坑。"]'),
('46234922-dd38-4475-8328-e12d9aa1cd44','徐一之從智子行','項安世','宋','宋诗','song-poetry','','[]','有士才如此，流光駛若何。',48,'全唐诗/poet.song.147000.json','["有士才如此，流光駛若何。", "筆端風雨快，胸次古今多。", "止止杯中物，嗚嗚耳後歌。", "低頭聊小忍，唾手即高科。"]'),
('8c08e54a-d4bb-4af4-84f3-a21605d1445d','盧似之從道子行','項安世','宋','宋诗','song-poetry','','[]','昔我爲行客，煩君作好詩。',48,'全唐诗/poet.song.147000.json','["昔我爲行客，煩君作好詩。", "今吾仍是主，送子得無辭。", "文賦須勤作，經書莫暫離。", "天資誠美矣，師道可無之。"]'),
('9c150778-7744-40a6-b934-9f1b96641adc','鹿鳴燕次韻和權帥湯提刑時二弟皆預鄉薦','項安世','宋','宋诗','song-poetry','','[]','使家親勸駕，賤子辱同升。',48,'全唐诗/poet.song.147000.json','["使家親勸駕，賤子辱同升。", "曉月鴒原聚，秋空雁字凌。", "燕山慚五桂，西海繼三鵬。", "况藉吹噓力，扶摇正可乘。"]'),
('c1b767e7-a796-4c2d-950b-0490d2e66297','盧道子赴銓試','項安世','宋','宋诗','song-poetry','','[]','高才真幹父，新渥繼難兄。',48,'全唐诗/poet.song.147000.json','["高才真幹父，新渥繼難兄。", "舟楫維湘岸，簪纓覲漢京。", "學雖工比興，科亦要刑名。", "書律三冬足，榮華一戰成。"]'),
('0ebf238c-5291-413d-9e10-de125fbd6960','李浦道中得家信','項安世','宋','宋诗','song-poetry','','[]','李浦江邊路，星沉日未生。',48,'全唐诗/poet.song.147000.json','["李浦江邊路，星沉日未生。", "逢人送家信，借火讀天明。", "上說兒曹健，中言客路晴。", "促歸仍勸緩，反覆見慈情。"]'),
('b0a98247-38c9-4cf6-8b5b-dddea40cf90d','新晴  其一','項安世','宋','宋诗','song-poetry','','[]','別岸連朝雨，登臺夜半晴。',48,'全唐诗/poet.song.147000.json','["別岸連朝雨，登臺夜半晴。", "殷懃見天意，反覆近人情。", "碑倚雙崖立，溪容一葦橫。", "昔吾今屬我，我醉亦呼卿。"]'),
('aa6f4c00-f96a-41fd-a08e-4deaff213fc6','新晴  其二','項安世','宋','宋诗','song-poetry','','[]','幸甚干逢甲，皤然雨變霜。',48,'全唐诗/poet.song.147000.json','["幸甚干逢甲，皤然雨變霜。", "綵衣雲漸近，紋線日初長。", "預想慈懷動，先憑喜信將。", "背人三數鵲，飛去覺匆忙。"]'),
('988d1d3e-8af3-4fe7-b2b5-2b05107ec104','次韻敘李提刑往臨先正治所併所聞先正論桃源事二首  其一','項安世','宋','宋诗','song-poetry','','[]','疇昔拜臞仙，桃源問果然。',48,'全唐诗/poet.song.147000.json','["疇昔拜臞仙，桃源問果然。", "洞非人世外，花在此心邊。", "寂寂蒸霞地，沉沉浴日天。", "南陽劉子驥，獨泛問津船。"]'),
('71de3cc0-ff4b-4175-a61d-7122ab76be63','次韻敘李提刑往臨先正治所併所聞先正論桃源事二首  其二','項安世','宋','宋诗','song-poetry','','[]','今日天香去，當時晝夢然。',48,'全唐诗/poet.song.147000.json','["今日天香去，當時晝夢然。", "試烘千歲鼎，如見一川田。", "潤带仙壇石，芳連古柏烟。", "靜中觀篆大，依約畫秦阡。"]'),
('7bf18596-5813-4080-9431-29b8e25add89','送襄陽成統制移建康','項安世','宋','宋诗','song-poetry','','[]','日日夢長干，真成下碧湍。',48,'全唐诗/poet.song.147000.json','["日日夢長干，真成下碧湍。", "雍郊辭鹿隠，鍾阜看龍蟠。", "百勝傳家學，三司踐世官。", "誰知弓劍裏，曾带腐儒酸。"]'),
('8cebb067-2a84-4246-8bb7-bc6efa7755d4','佛圖市','項安世','宋','宋诗','song-poetry','','[]','雨意陰連日，秋容淡滿溪。',48,'全唐诗/poet.song.147000.json','["雨意陰連日，秋容淡滿溪。", "水穿平野斷，雲截遠山低。", "客路朝昏畏，村墟卯酉齊。", "傳聞近湖北，漸喜脫江西。"]'),
('58534f45-0382-4eeb-9dba-2b1a3907855a','次韻蘇主管憶莊器之賢良','項安世','宋','宋诗','song-poetry','','[]','娟秀從牙茁，聲名奮角羈。',48,'全唐诗/poet.song.147000.json','["娟秀從牙茁，聲名奮角羈。", "人愁萬事早，誰料一官遲。", "憲也雖非病，桑乎可使饑。", "有窮難手援，無夢嘆吾衰。"]'),
('b43769be-ac2b-491c-94da-b3687fd85cc2','遊羅漢至開先寺','項安世','宋','宋诗','song-poetry','','[]','半世懷吾願，今年得此辰。',48,'全唐诗/poet.song.147000.json','["半世懷吾願，今年得此辰。", "朝廷用和議，疆埸有閒人。", "地噴雙龍沫，雲藏五老身。", "天寒林影薄，斜日照衣巾。"]'),
('e26f85de-02ba-433e-9064-ef7e45538a5c','宿東林寺','項安世','宋','宋诗','song-poetry','','[]','借宅星江上，山南已遍尋。',48,'全唐诗/poet.song.147000.json','["借宅星江上，山南已遍尋。", "猶餘湓浦路，未快白公心。", "屬國陳三表，歸帆拂二林。", "遠師堂上酒，可以恣狂吟。"]'),
('f2695a14-6903-479c-a101-043b52d096cc','送葉吉甫往建康  其一','項安世','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','同是匡廬客，匡廬又送君。',48,'全唐诗/poet.song.147000.json','["同是匡廬客，匡廬又送君。", "衣袍霜後薄，戈甲夜深聞。", "目斷甌溪月，心摇楚岫雲。", "東西各有慕，魂夢亦相分。"]'),
('50bbc368-42d6-4a4b-9757-fb92d5c6ab40','送葉吉甫往建康  其二','項安世','宋','宋诗','song-poetry','','[]','脚底東林路，船頭下白溝。',48,'全唐诗/poet.song.147000.json','["脚底東林路，船頭下白溝。", "所之仍作客，何日定歸休。", "眉爲鄉人蹙，心將世事謀。", "書生千古病，至竟欲誰瘳。"]'),
('c3990b53-0dde-4086-9933-2071402bf3c5','寄題鄭氏墳亭','項安世','宋','宋诗','song-poetry','','[]','不識亭前路，應知孝子情。',48,'全唐诗/poet.song.147000.json','["不識亭前路，應知孝子情。", "未甘黄壤隔，猶共白雲橫。", "好在當時意，端從苦處生。", "願言珍體髮，聖學待深評。"]'),
('9478684c-f812-42c6-a675-d86df5cebd9d','治裝將歸','項安世','宋','宋诗','song-poetry','','[]','又作瞿唐去，長爲道路行。',48,'全唐诗/poet.song.147000.json','["又作瞿唐去，長爲道路行。", "灘名暗可數，風浪飽曾更。", "僮僕般移慣，衣裝結束輕。", "別多難得淚，不是總無情。"]'),
('5483b5bc-42af-486c-b857-3ae5d992d260','丫頭巖','項安世','宋','宋诗','song-poetry','','[]','三十年前過，吾方似此山。',48,'全唐诗/poet.song.147000.json','["三十年前過，吾方似此山。", "山容今尚丱，吾鬢久成班。", "羞把娉婷嫁，長垂婑墮鬟。", "黄塵烏帽底，媿汝若爲顔。"]'),
('999ce854-ee05-44dc-a794-0c0c9775e248','遣悶','項安世','宋','宋诗','song-poetry','','[]','夜與影同宿，晝將書共談。',48,'全唐诗/poet.song.147000.json','["夜與影同宿，晝將書共談。", "虛凉惟稱暑，陰濕恐生嵐。", "眼有思家淚，心懷報國慚。", "更須辭命紱，身已住僧菴。"]'),
('316f873c-c8d6-433f-be19-9717a044e0d1','送江陵劉縣丞得多字  其一','項安世','宋','宋诗','song-poetry','','[]','一語動愁思，良朋能幾多。',48,'全唐诗/poet.song.147000.json','["一語動愁思，良朋能幾多。", "相持看鬢髮，容易隔山河。", "舊學紛疑信，新功廢琢磨。", "因君戒行李，令我悟蹉跎。"]'),
('c4a873c8-cd23-4b6a-a2be-626b258fb3b8','送江陵劉縣丞得多字  其二','項安世','宋','宋诗','song-poetry','','[]','吾事方如此，諸儒說更多。',48,'全唐诗/poet.song.147000.json','["吾事方如此，諸儒說更多。", "高明俄已竟，廣大日無何。", "意遠身仍近，人同已易訛。", "且當行故步，未敢赴殊科。"]'),
('479967c4-f20f-47e0-ac3f-fd7291085743','送查仲文三首  其一','項安世','宋','宋诗','song-poetry','','[]','靜甘明主棄，出爲故人書。',48,'全唐诗/poet.song.147000.json','["靜甘明主棄，出爲故人書。", "鄴下劉公幹，山中陶隠居。", "百年通醉醒，萬事付乘除。", "只有詩魔在，時能掣巨魚。"]'),
('d203671b-102d-49f1-85b2-b0d706db55b8','送查仲文三首  其二','項安世','宋','宋诗','song-poetry','','[]','先生江海士，使者水曹郎。',48,'全唐诗/poet.song.147000.json','["先生江海士，使者水曹郎。", "開絹印三道，懷人天一方。", "上江春水急，穿峽晚雲長。", "詩酒勤陶寫，中年屬易傷。"]'),
('21482323-3515-4347-83a0-c4fdccfd3275','送查仲文三首  其三','項安世','宋','宋诗','song-poetry','','[]','世味元無著，詩情自不閒。',48,'全唐诗/poet.song.147000.json','["世味元無著，詩情自不閒。", "撩人五字句，爲客萬重山。", "我已移文就，公能盡興還。", "歸來宋玉宅，作賦動江關。"]'),
('d9136bd7-a770-4cbd-af4f-85b6e5750426','送孫監酒','項安世','宋','宋诗','song-poetry','','[]','我已寒如水，君方冷似灰。',48,'全唐诗/poet.song.147000.json','["我已寒如水，君方冷似灰。", "有才誰肯惜，無力可相推。", "蒸水聞奇甚，糟邱亦旨哉。", "皇華重同姓，第一望歸來。"]'),
('cb84e635-5352-4890-84f4-54276e6a78ef','贈葉少敏','項安世','宋','宋诗','song-poetry','','[]','故國三千里，五行信偶然。',48,'全唐诗/poet.song.147000.json','["故國三千里，五行信偶然。", "丈夫天下志，兒女客中憐。", "荆鄂十守歲，衡潭三拜年。", "新正納殊祐，從此不孤眠。"]'),
('0c8b9fd1-b38b-4464-808f-5f021e40505c','贈周季隠','項安世','宋','宋诗','song-poetry','','[]','鐵面蒼髯士，金魚玉带家。',48,'全唐诗/poet.song.147000.json','["鐵面蒼髯士，金魚玉带家。", "園林閒富貴，花竹老生涯。", "世上名何用，尊中酒幸嘉。", "向來張長史，佳句足堪誇。"]'),
('06c89ad2-f7d3-48a4-aefb-4393a6d35cfa','次韻王少清見贈','項安世','宋','宋诗','song-poetry','','[]','王謝風流在，千年故不磨。',48,'全唐诗/poet.song.147000.json','["王謝風流在，千年故不磨。", "子孫奇俊甚，生長見聞多。", "容易三千首，鏗鍧十二和。", "故家文物盛，寒士得同科。"]'),
('bc9f62e3-1a13-449d-8319-b38abd4e62ef','送鄧制幹二首  其一','項安世','宋','宋诗','song-poetry','','[]','去國逢人避，書門斷客傳。',48,'全唐诗/poet.song.147000.json','["去國逢人避，書門斷客傳。", "聞知西嶺雪，忙上右襟船。", "未了青燈話，仍衝白鳥烟。", "江湖逢倚相，將夢寄渠邊。"]'),
('31f0521c-612a-4f6f-801f-c7ca9c02c2c6','送鄧制幹二首  其二','項安世','宋','宋诗','song-poetry','','[]','賦頌前朝愛，詩文內相傳。',48,'全唐诗/poet.song.147000.json','["賦頌前朝愛，詩文內相傳。", "九家潘岳鬢，萬里米家船。", "灧澦冬無雪，蓬婆晝不烟。", "未須臺閣上，迢遞佐三邊。"]'),
('8a805281-5762-48c2-887b-34b96302abba','送嚴童子','項安世','宋','宋诗','song-poetry','','[]','鳳歷開新統，鵷鶵降異姿。',48,'全唐诗/poet.song.147000.json','["鳳歷開新統，鵷鶵降異姿。", "入朝承重渥，還舍拜名師。", "楊晏皆模範，韓陳有訓辭。", "後生須靜實，切莫事奔馳。"]'),
('0be8ecf5-3c46-4388-a036-54413e7786a1','次韻自詠  其一','項安世','宋','宋诗','song-poetry','','[]','生意斷無幾，死灰難復然。',48,'全唐诗/poet.song.147000.json','["生意斷無幾，死灰難復然。", "世方尊臘臘，吾亦夢先邊。", "江水青無地，巖雲白似天。", "短蓑將鬢髮，聽唱謝郎船。"]'),
('1da9ba93-7d99-478a-ae16-90f47cae2331','次韻自詠  其二','項安世','宋','宋诗','song-poetry','','[]','雜劇只如此，古人誰不然。',48,'全唐诗/poet.song.147000.json','["雜劇只如此，古人誰不然。", "渭南尋竹塢，杜曲買桑田。", "石裂山銜羽，松明火带烟。", "夜深隨射虎，歸路恐迷阡。"]'),
('39301beb-f23f-4c0c-a516-6a722a462567','次韻贈劉正將','項安世','宋','宋诗','song-poetry','','[]','讀子風林集，懷吾里塾時。',48,'全唐诗/poet.song.147000.json','["讀子風林集，懷吾里塾時。", "道途今老大，人事幾推移。", "宮省知名久，君王識面遲。", "柳亭寒氣入，誰賞玉臺詩。"]'),
('286e566e-0111-4476-877a-76dade111138','送李憲權江陵帥雙轆轤格','項安世','宋','宋诗','song-poetry','','[]','表餌計已决，艱難人盡非。',48,'全唐诗/poet.song.147000.json','["表餌計已决，艱難人盡非。", "猶煩使者斧，往載帥臣旂。", "萬事本無事，一移無不移。", "因書漢三府，鳥盡未爲遲。"]'),
('0f7c2342-87f4-4e81-a950-10b38245f21e','方橋晚憩','項安世','宋','宋诗','song-poetry','','[]','歸路方橋晚，年年此月情。',48,'全唐诗/poet.song.147000.json','["歸路方橋晚，年年此月情。", "不知臨老去，更得幾番行。", "浩蕩東風闊，微茫遠水橫。", "每來心自愛，未要世人驚。"]'),
('95e17446-4ad7-48af-b39a-9794f4283130','還憩方橋','項安世','宋','宋诗','song-poetry','','[]','拂拂輕黄小，茸茸嫩綠蔫。',48,'全唐诗/poet.song.147000.json','["拂拂輕黄小，茸茸嫩綠蔫。", "柳條君莫折，草色我思眠。", "鬢髮從衰病，人情自少年。", "欄干一臨眺，春意滿坤乾。"]'),
('5966b142-b4ab-45e8-8743-d4bb6b6eff6a','清凉寺','項安世','宋','宋诗','song-poetry','','[]','楚甸延詩眼，臺城壯酒杯。',48,'全唐诗/poet.song.147000.json','["楚甸延詩眼，臺城壯酒杯。", "山連京口去，江自錦官來。", "百榼澆難下，千篇勇莫裁。", "非君湖海氣，誰禁此崔嵬。"]'),
('8253586f-2f36-491d-8d27-d94270e27ff2','新婦石','項安世','宋','宋诗','song-poetry','','[]','誰家醜新婦，臨水久徘徊。',48,'全唐诗/poet.song.147000.json','["誰家醜新婦，臨水久徘徊。", "月印脩眉嫵，風傳古曲哀。", "曉妝無粉黛，春服有梅苔。", "應恨周居士，逃秦更不回。"]'),
('52445205-3624-4c62-b4c3-f371ab476cc2','贈查仲文','項安世','宋','宋诗','song-poetry','','[]','諸老更推挽，先生定別留。',48,'全唐诗/poet.song.147000.json','["諸老更推挽，先生定別留。", "孰知廬阜趣，戰勝漢廷游。", "直自全高隠，寧當退急流。", "典刑前輩在，餘潤覓東邱。"]'),
('0f4bd903-d140-4c85-84a8-7857731d97af','丹陽感舊','項安世','宋','宋诗','song-poetry','','[]','東來復西去，却數十三年。',48,'全唐诗/poet.song.147000.json','["東來復西去，却數十三年。", "三過丹陽縣，俱乘萬里船。", "半生行役裏，兩鬢客愁邊。", "屬玉滄波上，清標倍炯然。"]'),
('86e4ab78-ec54-427f-a07e-7db8dba88493','次韻鄭檢法與張秘書論命','項安世','宋','宋诗','song-poetry','','[]','曹劉元易識，甘石况經云。',48,'全唐诗/poet.song.147000.json','["曹劉元易識，甘石况經云。", "五物時爲帝，三辰歲有君。", "平生信嚴子，今日得揚雲。", "兩手分忠孝，往承華與勳。"]'),
('18ea7e04-8c2c-4bf9-83e4-34e67da23b5a','寒食有懷楚都','項安世','宋','宋诗','song-poetry','','[]','北土重寒食，東風吹故都。',48,'全唐诗/poet.song.147000.json','["北土重寒食，東風吹故都。", "不知清野後，還有踏青無。", "荻笋烹魚美，萎蒿裹飯腴。", "異鄉悲節物，歸夢速檣烏。"]'),
('1e60f05b-20c6-4b96-97d3-42ab658d1ca3','對月','項安世','宋','宋诗','song-poetry','','[]','少日曾相識，重來有故情。',48,'全唐诗/poet.song.147000.json','["少日曾相識，重來有故情。", "殷勤前度月，依舊向人明。", "擾擾魄生死，區區輪滿盈。", "何如長半掩，萬古不西傾。"]'),
('0b79b152-9747-412b-a514-33186458d676','夜雨','項安世','宋','宋诗','song-poetry','','[]','夜帳不知雨，曉街初見泥。',48,'全唐诗/poet.song.147000.json','["夜帳不知雨，曉街初見泥。", "青方歸柳市，紅未到桃蹊。", "遠水牽歸纜，荒岡入杖藜。", "招呼舊僮僕，歡喜共鋤犂。"]'),
('d7e29852-d2a3-47a9-9340-46251bb02222','春暄','項安世','宋','宋诗','song-poetry','','[]','春來能幾日，臘裏未開年。',48,'全唐诗/poet.song.147000.json','["春來能幾日，臘裏未開年。", "物色已如此，風光何習然。", "半醒行似醉，微困坐成眠。", "欲寫融融意，都無句可傳。"]'),
('c53d0a4d-4f45-442c-aba3-53baf87b06db','二十八日行香即事  其一','項安世','宋','宋诗','song-poetry','','[]','曉市衆果集，枇杷盛滿箱。',48,'全唐诗/poet.song.147000.json','["曉市衆果集，枇杷盛滿箱。", "梅施一點赤，杏染十分黄。", "青李不待暑，木瓜寧論霜。", "年華緣底事，亦趁販夫忙。"]'),
('5979e04f-7fcc-40f9-ae71-b3f80248c6de','二十八日行香即事  其二','項安世','宋','宋诗','song-poetry','','[]','柳岸濛濛濕，溝波點點跳。',48,'全唐诗/poet.song.147000.json','["柳岸濛濛濕，溝波點點跳。", "窗槽斜溜湧，轎頂碎聲飄。", "村擔果爭市，山桅花滿橋。", "愁聽新使客，墟里說蕭條。"]'),
('77ee464e-a039-42d1-bd8d-2f470ef65977','偶吟','項安世','宋','宋诗','song-poetry','','[]','近市心如水，居貧道未窮。',48,'全唐诗/poet.song.147000.json','["近市心如水，居貧道未窮。", "關門度梅雨，欹枕受槐風。", "問學十年事，文章百世公。", "讀多書有味，吟少句無工。"]'),
('b4a72395-0ba7-4f37-ba7b-0a88108b4f64','鄭檢法重九病起送酒索詩','項安世','宋','宋诗','song-poetry','','[]','聞道臺參早，交親喜可知。',48,'全唐诗/poet.song.147000.json','["聞道臺參早，交親喜可知。", "猶能白衣酒，相勸菊花時。", "带剩如干眼，梳添幾寸絲。", "風騷足材料，何必項斯詩。"]'),
('0b1fe2be-867e-4505-9be1-10e59f38d5c1','張澧州挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','持橐中朝貴，餐氈異域留。',48,'全唐诗/poet.song.147000.json','["持橐中朝貴，餐氈異域留。", "人皆敬先德，我已識君侯。", "氣節傳三世，才猷著兩州。", "承家五男子，身後更何求。"]'),
('f259f046-0f70-48f9-a371-bd37902d8f02','張澧州挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','坦然無一物，此意極寥寥。',48,'全唐诗/poet.song.147000.json','["坦然無一物，此意極寥寥。", "生死東西魄，盈虛早晚潮。", "何人清夜省，舉世萬波摇。", "試把斯文誦，英魂或可招。"]'),
('78ee2d4e-6f4f-4fdb-9ec3-67b0ce3d1704','任安撫挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','已矣天難問，哀哉道竟孤。',48,'全唐诗/poet.song.147000.json','["已矣天難問，哀哉道竟孤。", "風流前輩似，膽畧世人無。", "緩急謀謨見，尋常尺寸拘。", "明時非不用，志士自多迂。"]'),
('5d391464-9219-4d99-a630-ad08664b33a0','任安撫挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','新息任夫子，東坡所父師。',48,'全唐诗/poet.song.147000.json','["新息任夫子，東坡所父師。", "只餘盤叟在，猶乃故家時。", "閒撫伊吾劍，吟成綠野詩。", "中原遺老盡，舊事有誰知。"]'),
('d5fff88c-b708-49c9-89f9-7125c387282b','挽陸運使詩  其一','項安世','宋','宋诗','song-poetry','','[]','爰自微官日，能令巨力摧。',48,'全唐诗/poet.song.147000.json','["爰自微官日，能令巨力摧。", "青蒭回使節，紅粟抗公台。", "淮右恩波闊，畿西禁網恢。", "平生希麴令，今得吏民哀。"]'),
('1cc6fbd5-b5d8-4823-8c79-ca6c9b37ab33','挽陸運使詩  其二','項安世','宋','宋诗','song-poetry','','[]','八秩公何憾，淋浪我自悲。',48,'全唐诗/poet.song.147000.json','["八秩公何憾，淋浪我自悲。", "向來淮士裏，最得阜陵知。", "故國人誰識，長身帝所思。", "竟隨龍馭去，應赴白雲期。"]'),
('d9b1bf98-32f3-4a42-bb84-5ffea22bb72e','尤尚書挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','今歲何遷次，乾坤失巨人。',48,'全唐诗/poet.song.147000.json','["今歲何遷次，乾坤失巨人。", "老生啼壞木，後學嘆迷津。", "四海人才譜，三朝禮樂臣。", "併將文獻去，誰與覺斯民。"]'),
('101d83c0-a21b-4862-a3a9-1e2a5b763f7a','尤尚書挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','舊學淵衷記，新阡玉色疑。',48,'全唐诗/poet.song.147000.json','["舊學淵衷記，新阡玉色疑。", "似聞形嘆慨，未忍失容儀。", "海道空齎志，西州只貯悲。", "平生謝公願，後世子雲知。"]'),
('e1571848-8df5-4b10-a44a-d059aecc39a1','武學蔡博士挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','人憐蔡慶遠，慶遠自悠哉。',48,'全唐诗/poet.song.147000.json','["人憐蔡慶遠，慶遠自悠哉。", "雖欠壽將位，非無時與才。", "諸生尊誼槩，明主識奇瑰。", "獨把平生去，何曾一語哀。"]'),
('64206320-2f80-4ce3-8155-6c712e6eb25e','武學蔡博士挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','天子昔好武，儒臣皆諱文。',48,'全唐诗/poet.song.147000.json','["天子昔好武，儒臣皆諱文。", "誰能有勝具，不肯建奇勳。", "半世觀行己，千年勸事君。", "底須登大耋，金印負前聞。"]'),
('0666ffcd-2afd-4698-9823-8359a888f4b7','司馬歸州挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','玉立氣如春，魁然長者人。',48,'全唐诗/poet.song.147000.json','["玉立氣如春，魁然長者人。", "三朝陳素業，兩郡駕朱輪。", "國幹須名族，吾衰倚大姻。", "那知沙步酒，一別遂終身。"]'),
('41a07390-0fc0-41aa-9578-1887e4415b4b','司馬歸州挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','矻矻秭歸山，長身困遠官。',48,'全唐诗/poet.song.147000.json','["矻矻秭歸山，長身困遠官。", "舊租無折變，新路有平寬。", "報以孫將子，森然玉與蘭。", "自隨梅福去，雲外跨飛鸞。"]'),
('3b6d46ee-3ddd-4d5c-8601-759869f4f2db','處州葉德共挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','屬厭多年所，歸來近月評。',48,'全唐诗/poet.song.147000.json','["屬厭多年所，歸來近月評。", "望之重十舍，已矣又平生。", "無復論鄉曲，猶能接舅甥。", "短章隨嘒管，凄斷不成聲。"]'),
('cd717ace-3b79-47d4-b17e-672c2a7f3e58','處州葉德共挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','儒服能軍事，人心以富行。',48,'全唐诗/poet.song.147000.json','["儒服能軍事，人心以富行。", "邑中無惡少，堂上有佳名。", "死得安仁誄，生經短簿評。", "哀榮有如此，何必漢公卿。"]'),
('5bc5a6c9-2ec5-4295-ae2b-a08d9f8b76cf','李萬州挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','仙李來南日，熙寧去國人。',48,'全唐诗/poet.song.147000.json','["仙李來南日，熙寧去國人。", "一身辭赤芾，四世尚朱輪。", "桑梓推前輩，葭莩接世姻。", "傷心挽耆舊，不獨爲情親。"]'),
('cc81ef3b-6996-4c9a-af38-a7b0bf2db533','李萬州挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','令子裒遺事，而翁亦大奇。',48,'全唐诗/poet.song.147000.json','["令子裒遺事，而翁亦大奇。", "治安真有策，經濟遂無時。", "黄壤人間恨，斯文我輩推。", "生傳漢中什，死著十哀詩。"]'),
('ac812632-9d2a-4c44-bc23-04f89cb97d61','李萬州挽詩  其三','項安世','宋','宋诗','song-poetry','','[]','靈輀朝出祖，屬綍淚爭揮。',48,'全唐诗/poet.song.147000.json','["靈輀朝出祖，屬綍淚爭揮。", "慕子啼玄草，慈親哭綵衣。", "敬齋書秩秩，退國物菲菲。", "華屋生存處，千年遂不歸。"]'),
('4d8e2dea-c464-4eda-b20c-0af7cfd40bf9','李萬州挽詩  其四','項安世','宋','宋诗','song-poetry','','[]','公今南面樂，我自涕滂沱。',48,'全唐诗/poet.song.147000.json','["公今南面樂，我自涕滂沱。", "十載還鄉社，三君逐逝波。", "樂郊荒水檻，巢室閟烟蘿。", "前輩風流盡，吾生奈老何。"]'),
('33c9e737-3bba-4278-a15b-3b3c6ad0b0bb','趙婺州挽詩','項安世','宋','宋诗','song-poetry','','[]','雪裏蕭山渡，花時楊子城。',48,'全唐诗/poet.song.147000.json','["雪裏蕭山渡，花時楊子城。", "八年如昨日，一夢隔平生。", "剖竹皆雄郡，刊碑有頌聲。", "傳家諸子在，早晚繼科名。"]'),
('d17d4341-6f74-45c0-b5c3-4feecdf08ece','張黎州挽詩','項安世','宋','宋诗','song-poetry','','[]','萬里沈黎徼，民夷雜戍屯。',48,'全唐诗/poet.song.147000.json','["萬里沈黎徼，民夷雜戍屯。", "金錢寬兩稅，水澤潤千門。", "肅肅猩鼯靜，潭潭壁壘尊。", "遠猷嗟未究，蕭瑟定安原。"]'),
('52d0f61a-09bc-4db9-abd4-0f48e0fa0fc0','代趙丞相作黄尚書挽詩三首  其一','項安世','宋','宋诗','song-poetry','','[]','劍閣重來日，瀛洲僅閲旬。',48,'全唐诗/poet.song.147000.json','["劍閣重來日，瀛洲僅閲旬。", "一從充保傅，五見易冬春。", "作聖工夫久，膺圖歲月新。", "九重深悼處，早晚付經綸。"]'),
('207ff1fb-de66-4062-b9c5-203475926b2a','代趙丞相作黄尚書挽詩三首  其二','項安世','宋','宋诗','song-poetry','','[]','講讀真無敵，忠誠素有孚。',48,'全唐诗/poet.song.147000.json','["講讀真無敵，忠誠素有孚。", "談經兼體用，論事極精粗。", "日已升暘谷，天方冒海隅。", "甘盤當保義，豈料歲年徂。"]'),
('fa24e435-3dae-407e-a212-4db7e6b3ca5b','代趙丞相作黄尚書挽詩三首  其三','項安世','宋','宋诗','song-poetry','','[]','力小慚形渥，心同傒棟隆。',48,'全唐诗/poet.song.147000.json','["力小慚形渥，心同傒棟隆。", "忠能當世事，信可沃宸衷。", "長往公何遽，孤鶱我最窮。", "老來難得淚，獨爲灑西風。"]'),
('2c3a8331-2fcb-42f1-ad42-587fa85bab83','黄尚書挽詩二首  其一','項安世','宋','宋诗','song-poetry','','[]','憤切身頻痏，憂多鬢早絲。',48,'全唐诗/poet.song.147000.json','["憤切身頻痏，憂多鬢早絲。", "有功裨聖主，無命佐清時。", "論事明於掌，披圖粲若棋。", "哀哉聽絕語，猶抱五年悲。"]'),
('1978b0b4-3395-4654-a8d0-4ae803f2ef25','黄尚書挽詩二首  其二','項安世','宋','宋诗','song-poetry','','[]','嗣對膺圖日，群生望治時。',48,'全唐诗/poet.song.147000.json','["嗣對膺圖日，群生望治時。", "忽聞公已病，相顧事堪疑。", "竟作堂堂去，空書咄咄詞。", "眼中衰剉盡，持底送靈輀。"]'),
('ea8329e0-2c24-40fa-9d46-31602424355a','馮元素挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','戎服開清洛，儒書謁阜陵。',48,'全唐诗/poet.song.147000.json','["戎服開清洛，儒書謁阜陵。", "一朝官御晚，平日壯心冰。", "此士歸來夜，何人說中興。", "秋來原上草，蕭索見風稜。"]'),
('25680b95-fc49-4d61-b02b-ac0b67a16eb4','馮元素挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','出塞千夫敵，還家一善人。',48,'全唐诗/poet.song.147000.json','["出塞千夫敵，還家一善人。", "閨門春穆穆，鄉黨晚恂恂。", "字畫清能謹，詩章秀以醇。", "畧無邊瑣氣，懷此最傷神。"]'),
('0f56b5e3-7407-43b6-afc3-aae02b71149f','荆南帥姚參政挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','壽相背三甲，暮齡腰十圍。',48,'全唐诗/poet.song.147000.json','["壽相背三甲，暮齡腰十圍。", "自陪初伏飲，竟作百年違。", "楚澤秋初動，洪都夢已非。", "向來千騎擁，悽惻片帆歸。"]'),
('549a2078-d443-4042-89d7-31dc2da9bc69','荆南帥姚參政挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','劍履三台亞，旌旄十國連。',48,'全唐诗/poet.song.147000.json','["劍履三台亞，旌旄十國連。", "春風迎上日，秋色送歸船。", "露泣千山月，雲愁萬里天。", "堂堂寧復有，玉立照人鮮。"]'),
('f4ac5b16-8192-473e-b231-9eb35d04c74c','撫州吳茂榮挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','當年郡博士，致此一先生。',48,'全唐诗/poet.song.147000.json','["當年郡博士，致此一先生。", "相見茂榮甫，似吾諸葛卿。", "姓名書帝府，文行最鄉評。", "終老君何恨，傷時淚自傾。"]'),
('38e94318-4363-40b9-ae13-b4490c020aa7','撫州吳茂榮挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','世已尊科舉，人多失老成。',48,'全唐诗/poet.song.147000.json','["世已尊科舉，人多失老成。", "行書周族黨，身欠漢公卿。", "猶藉千年潤，能傳萬壑清。", "愴懷非一士，何恨不知名。"]'),
('1e19580f-af03-493b-9190-1bbb35a9ee68','王君行丈挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','春末樂叟去，秋初仍牧齋。',48,'全唐诗/poet.song.147000.json','["春末樂叟去，秋初仍牧齋。", "無誰問天理，有底厭吾儕。", "簡易逢人樂，虛徐觸事諧。", "忽逢孤絕處，千丈崒高崖。"]'),
('59c90f28-6a62-4a90-80f6-5cae42b435a1','王君行丈挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','樂叟干將劍，鋒鋩凜不收。',48,'全唐诗/poet.song.147000.json','["樂叟干將劍，鋒鋩凜不收。", "之人獨和厚，與世極沉浮。", "淑氣長三月，高懷自九秋。", "洞門元不鎖，依舊少從游。"]'),
('ed727724-54ad-4e5d-84ba-19dc31e5ea0f','王君行丈挽詩  其三','項安世','宋','宋诗','song-poetry','','[]','房州迎主簿，惠我數行書。',48,'全唐诗/poet.song.147000.json','["房州迎主簿，惠我數行書。", "慟哭王郎死，凄凉楚澤虛。", "少將詩作劇，老共易同居。", "比似曾居士，規繩更不疎。"]'),
('ca202f76-6ff0-415d-be29-dbfa892c84a8','樂君啟文挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','荆州十萬戶，惟我獨知公。',48,'全唐诗/poet.song.147000.json','["荆州十萬戶，惟我獨知公。", "皓皓峣峣甚，凉凉踽踽中。", "平生尊骨鯁，到死諱雷同。", "此士埋黄壤，何人立素風。"]'),
('7307920d-bbc2-40b8-8034-a51a22ec68d8','樂君啟文挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','藝應天王拜，名高月旦評。',48,'全唐诗/poet.song.147000.json','["藝應天王拜，名高月旦評。", "一官娛晚暮，千載遇恩榮。", "未許行疇昔，猶應得久生。", "年來頻見此，老淚不禁傾。"]'),
('c0551383-fe53-48ba-97f4-07f745769290','高通直挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','赤手開荒徑，朱門照廣津。',48,'全唐诗/poet.song.147000.json','["赤手開荒徑，朱門照廣津。", "兩班通印紱，三桂襲簪紳。", "壽考尊鄉曲，光華勸邑人。", "我生當恨晚，猶及望靈椿。"]'),
('b2006588-7d5c-4f98-a59a-086beabb0339','高通直挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','甲子諸孫行，丁年北夢行。',48,'全唐诗/poet.song.147000.json','["甲子諸孫行，丁年北夢行。", "歸來古於越，友事晉參卿。", "旋展升堂拜，方瞻賜紱榮。", "故山耆舊少，蕭瑟更佳城。"]'),
('39bfe8bd-f60a-49d8-8e3a-3cf2a87ac6bc','曾著作之父文思判院挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','後有兒如許，前瞻祖自然。',48,'全唐诗/poet.song.147000.json','["後有兒如許，前瞻祖自然。", "詩書三世驗，鄉黨一辭賢。", "遂失升堂願，徒供相柩篇。", "吾衰真久矣，祇此亦關天。"]'),
('39d301e3-7ebc-45d5-bef6-c3f97405a909','曾著作之父文思判院挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','忍窮能到骨，何物可愁翁。',48,'全唐诗/poet.song.147000.json','["忍窮能到骨，何物可愁翁。", "守口雙奩靜，抄書萬卷空。", "朝天尊𣓨氏，勝地說壺公。", "脫屣俱無滯，斑衣淚自紅。"]'),
('71162f42-2fb5-4e8d-b112-c76f813461cb','黄寺丞挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','識面山陰道，論心德化堂。',48,'全唐诗/poet.song.147000.json','["識面山陰道，論心德化堂。", "後來俱罪籍，歸去各吾鄉。", "晚歲欣同寓，平生謂可償。", "來遲三兩月，淚落幾多行。"]'),
('42790cb8-f6ce-45a0-8dcb-2a38b18de824','黄寺丞挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','白鹿人先去，西坡事又非。',48,'全唐诗/poet.song.147000.json','["白鹿人先去，西坡事又非。", "客情何所向，老淚不禁揮。", "日短輀車急，山寒冢未腓。", "猶聞辭楚辟，來救越民饑。"]'),
('d77f1556-e8e9-4772-bc9e-f1bec10f0a62','司馬侍郎挽詩  其一','項安世','宋','宋诗','song-poetry','','[]','公之曾大父，昔者老先生。',48,'全唐诗/poet.song.147000.json','["公之曾大父，昔者老先生。", "日月扶丹扆，乾坤仗赤誠。", "詒謀三世重，謹始一言清。", "今日書生剉，臨風作雨傾。"]'),
('65780380-d778-467c-8850-0ef3afef9a01','司馬侍郎挽詩  其二','項安世','宋','宋诗','song-poetry','','[]','生身何恨晚，猶識孝曾孫。',48,'全唐诗/poet.song.147000.json','["生身何恨晚，猶識孝曾孫。", "姓字驚喬木，儀型想九原。", "百年餘父老，雙淚落軺軒。", "此意今誰領，憑高只斷魂。"]'),
('9c9289b5-c14f-45fb-8c02-c7e244868d26','挽荆南帥張左司詩  其一','項安世','宋','宋诗','song-poetry','','[]','霄漢占賢輔，乾坤失大儒。',48,'全唐诗/poet.song.147000.json','["霄漢占賢輔，乾坤失大儒。", "斯文斷命脈，識者嘆窮途。", "獨擁全名去，誰供一世須。", "空餘千載事，不盡惜良圖。"]'),
('57a67a1c-f5a6-4d68-89d5-fa8bdbbb1e2e','挽荆南帥張左司詩  其二','項安世','宋','宋诗','song-poetry','','[]','自古誰無死，斯人有重輕。',48,'全唐诗/poet.song.147000.json','["自古誰無死，斯人有重輕。", "諸生望模楷，吾道倚權衡。", "一髮千鈞挽，中流砥柱傾。", "平生憂國事，何意作身名。"]'),
('9fda51fd-a911-4069-a20d-546e89e06392','挽荆南帥張左司詩  其三','項安世','宋','宋诗','song-poetry','','[]','吾道竟如此，蒼生將奈何。',48,'全唐诗/poet.song.147000.json','["吾道竟如此，蒼生將奈何。", "名聲垂白日，身世逐滄波。", "宜世堂堂去，猶勝奄奄過。", "所嗟非一死，良願恐蹉跎。"]'),
('18950ff5-772a-4c38-b10f-8a6533e5771a','挽荆南帥張左司詩  其四','項安世','宋','宋诗','song-poetry','','[]','昔者登簾閣，先生病已瘳。',48,'全唐诗/poet.song.147000.json','["昔者登簾閣，先生病已瘳。", "從容當世事，反復萬端憂。", "力盡千家活，身疲十日留。", "向來天下士，端爲一城休。"]'),
('31615e14-2269-4a74-a987-c1433737578c','挽荆南帥張左司詩  其五','項安世','宋','宋诗','song-poetry','','[]','世已憎吾屬，天宜赦此賢。',48,'全唐诗/poet.song.147000.json','["世已憎吾屬，天宜赦此賢。", "忍教名百代，不使壽中年。", "蘭謝無傳業，蘋荒久絕絃。", "凄凉楚江上，鴻影獨翩翩。"]'),
('b9c117a8-1ff8-4d9e-b513-ca4c9f6aa7c3','挽湯丞相夫人二首  其一','項安世','宋','宋诗','song-poetry','','[]','冊府連天漢，恩榮四十年。',48,'全唐诗/poet.song.147000.json','["冊府連天漢，恩榮四十年。", "山河開象服，夙夜贊台躔。", "鸞鵠諸孫峙，箕裘令子傳。", "夫人無一恨，可以見重泉。"]'),
('512a9107-23bd-4149-aa35-18ae2ecae816','挽湯丞相夫人二首  其二','項安世','宋','宋诗','song-poetry','','[]','賤子無天幸，平生望六珈。',48,'全唐诗/poet.song.147000.json','["賤子無天幸，平生望六珈。", "偶然同斷梗，已復嘆悲笳。", "淚落升堂日，神馳送客車。", "空慚名義重，桂省近年家。"]'),
('eb56c687-3d73-4a0f-80b9-3b4ed8af8bf6','陰雨六韻','項安世','宋','宋诗','song-poetry','','[]','濱水地鍾濕，關門時過春。',72,'全唐诗/poet.song.147000.json','["濱水地鍾濕，關門時過春。", "讀書無氣力，看字費精神。", "陰雨便高枕，泥塗阻故人。", "小詩隨意就，情話與誰親。", "返照輕霞出，明朝霽色新。", "辛勤愧田父，江上晚耕勻。"]'),
('73b4ab91-2c84-438b-bd64-20094de05cc7','金陵紀遊百韻','項安世','宋','宋诗','song-poetry','','[]','艤棹秦淮日，中秋萬客船。',288,'全唐诗/poet.song.147000.json','["艤棹秦淮日，中秋萬客船。", "水門高夾岸，河道曲通廛。", "港對青林直，洲橫皓鷺鮮。", "會憐桃渡檝，離惜柳亭鞭。", "木誌嬋娟墓，香埋睥睨顛。", "賞心飛觀出，旌德舊題鎸。", "沙白寒籠月，波清暝宿烟。", "酒家知是否，商婦唱依然。", "兒病留三月，身閒近半年。", "遊山情亹亹，弔古筆翩翩。", "寺覓清凉邃，堂窺德慶懸。", "雉墉尋古址，虎踞出層巔。", "處峻生堪戮，袁劉死合甄。", "山腰舟萬竹，峯頂上千川。", "楚甸前開闢，吳山後接連。", "似垣環泰一，如陣擁中權。", "江觸崖根轉，潮衝石角旋。", "莫愁迷繫艇，王濬罷揚旃。", "離殿逃唐暑，精藍變竺乾。", "雖知悲李主，未免佞金仙。", "兌野情方倦，春墟興已遄。", "門經白下過，溝傍冶亭沿。", "舊驛分携處，新園欲餞邊。", "路趨鍾阜近，人畏谷靈專。"]'),
('dcb4b848-de28-4739-8854-7e26dc2c4d29','次韻王少清告歸七首  其一','項安世','宋','宋诗','song-poetry','','[]','蓮幕斑衣底，何因有旅愁。',60,'全唐诗/poet.song.147000.json','["蓮幕斑衣底，何因有旅愁。", "錦官城裏客，雲土澤邊州。", "夜夜還鄉夢，年年異縣秋。", "鶺鴒憐羽翼，鴻雁憶朋儔。", "便作刀頭去，關山亦阻脩。"]'),
('2795cba4-7a6c-4f60-8924-a3914eaa4785','次韻王少清告歸七首  其二','項安世','宋','宋诗','song-poetry','','[]','塞垣秋易覺，八月索衣裘。',60,'全唐诗/poet.song.147000.json','["塞垣秋易覺，八月索衣裘。", "露熟千株橘，風高百尺樓。", "人多宋玉賦，邊倚衛公籌。", "水落魚方賤，年豐酒易求。", "少留元不惡，三峽正幽幽。"]'),
('cbc1a796-b46c-4b36-a7d0-a15333e9764f','次韻王少清告歸七首  其三','項安世','宋','宋诗','song-poetry','','[]','何處秋光好，田園占一邱。',60,'全唐诗/poet.song.147000.json','["何處秋光好，田園占一邱。", "短鎌朝刈秫，長笛暮歸牛。", "酒熟邀人飲，鷄肥與婦謀。", "傍籬開竹徑，插竹護蔬疇。", "試上西郊望，翛然此興悠。"]'),
('cc208421-6442-49bf-b478-1fcf2f9526c6','次韻王少清告歸七首  其四','項安世','宋','宋诗','song-poetry','','[]','短檠今幸好，文社得同修。',60,'全唐诗/poet.song.147000.json','["短檠今幸好，文社得同修。", "何處撩鄉思，催君發棹謳。", "路經行雨峽，籤數報程郵。", "客路看如許，交情可耐不。", "慇懃江上水，長爲送離憂。"]'),
('c3aff55c-b4ab-4b6c-90b5-a71615a4ad56','次韻王少清告歸七首  其五','項安世','宋','宋诗','song-poetry','','[]','江陵雖未慣，已作一年留。',60,'全唐诗/poet.song.147000.json','["江陵雖未慣，已作一年留。", "料得到錦里，剩須談橘洲。", "楓櫧夾堤岸，荷芰匝城溝。", "南入湖湘櫓，北通襄漢舟。", "逢人問風土，說與話難周。"]'),
('329faace-e207-4445-985c-515d0694b898','次韻王少清告歸七首  其六','項安世','宋','宋诗','song-poetry','','[]','生平俱異縣，相與忽同矛。',60,'全唐诗/poet.song.147000.json','["生平俱異縣，相與忽同矛。", "鈍質鉛逢錯，蕪心草頼耰。", "每思難話別，却恨莫同遊。", "到日應殘臘，來時却順流。", "高才日千里，再見愈難侔。"]'),
('1ab7e824-eaaf-4833-bd8c-ed97cf1bbc9d','次韻王少清告歸七首  其七','項安世','宋','宋诗','song-poetry','','[]','有美不自嗇，相於常暗投。',60,'全唐诗/poet.song.147000.json','["有美不自嗇，相於常暗投。", "舂容驚巨軸，錯落眩雙眸。", "君已文如鳳，吾方拙似鳩。", "早知歸峽口，亦欲下沙頭。", "卒卒償詩債，慚無玉案酬。"]'),
('281877e5-d86b-4663-a126-6fc17b3f6794','送莊賢良赴召試','項安世','宋','宋诗','song-poetry','','[]','丙午陂當復，王春瑞習占。',216,'全唐诗/poet.song.147000.json','["丙午陂當復，王春瑞習占。", "龍樓上寶冊，鶴詔下窮簷。", "地脈通閩蜀，人才出老嚴。", "定羞新學曲，只守舊心潜。", "剩想堯眉樂，深垂舜目謙。", "有懷天變數，無計士風廉。", "庶證方如此，君行得滯淹。", "六題聊復爾，制策待韜鈐。", "久噎須詳吐，沈疴與痛砭。", "一扶媮意立，盡解結喉箱。", "人士回生氣，乾坤振絕燄。", "宏開九縣赤，永息萬方黔。", "治世吾何用，媸人影自嫌。", "弃荆宜入蜀，比素詎將縑。", "逐食俱隨雁，論心偶類鶼。", "雅懷欽粹淑，盛事愜窺覘。", "從此遲爲圃，它年說作監。", "因聲到邛僰，市肆覓疎簾。"]'),
('8953bdbe-5bc3-47b8-9717-704679db2c70','五月四日賀楊秘書知吉州五十韻','項安世','宋','宋诗','song-poetry','','[]','自識楊夫子，於今十二年。',288,'全唐诗/poet.song.147000.json','["自識楊夫子，於今十二年。", "甲辰來右淛，丁未向西川。", "逆旅初聞譽，摳衣亟致虔。", "未能情款款，已覺志拳拳。", "不謂攀天箐，仍逢汎水蓮。", "茲爲元禮御，始執晏平鞭。", "遠客心危甚，仁人教竭焉。", "精能嘉舊作，虛濫鄙新妍。", "贈送時三復，經行慮十全。", "趍隅殘臘月，判袂暮春天。", "度夏留巴國，開秋迓蜀船。", "追鋒承詔急，繫纜爲情牽。", "漕席尊同右，轅門謁並先。", "高登諸葛廟，朗詠少陵篇。", "歲月催行李，雲霄入峻躔。", "側聆參帝牒，俄見貳州權。", "進退朝紳竦，恩威俗珥悛。", "我分湘麓教，公返汝溪廛。", "城郭當來往，書題審食眠。", "誤恩叨給札，假道愜登筵。", "竟日留輸寫，憂時共涕漣。", "歲丁昭奮紀，律值夾姑旋。", "謬上鰲扉對，慚充玉府仙。", "急驚寒暑變，遐想鬢毛遷。"]'),
('82d66ef8-c03e-4782-a085-939523c98d75','餞周伯壽得枝字','項安世','宋','宋诗','song-poetry','','[]','分原內史界，世系出蒼姬。',72,'全唐诗/poet.song.147000.json','["分原內史界，世系出蒼姬。", "修貢長沙國，文章似楚辭。", "堵牆看獻賦，旗影照題詩。", "晝日三千字，春風第一枝。", "相公如父子，侍講是宗師。", "忍把直言策，輕爲阿世詞。"]'),
('cee1fc28-bc7c-41c4-9f5b-f935dcbeaa2a','送羅司理實之','項安世','宋','宋诗','song-poetry','','[]','衰病久忘情，相逢淚忽傾。',72,'全唐诗/poet.song.147000.json','["衰病久忘情，相逢淚忽傾。", "見君重娶婦，於我尚如兄。", "秩滿無人事，官卑有政聲。", "歸裝詩卷送，薦牘漕臺迎。", "二祖名俱重，孤身責詎輕。", "長將今仕看，勿遣後圖更。"]'),
('c06d43e4-537f-478a-8bba-9405f93ce424','次韻答潘監稅勉其小忍','項安世','宋','宋诗','song-poetry','','[]','舊日潘懷縣，長憐簿官卑。',96,'全唐诗/poet.song.147000.json','["舊日潘懷縣，長憐簿官卑。", "清秋一摇落，綠鬢兩衰遲。", "今代諸孫在，遺風百世知。", "四聲哦激烈，九折訴嶔𡼭。", "鍛鍊心成癖，磨礲句少疵。", "欲賡彭澤事，重和大蘇詩。", "得也聊三士，安之豈二宜。", "慇懃倩蠻素，唱我反騷辭。"]'),
('5dead323-1c21-4f2d-b592-cd609494e288','用韻爲十九弟壽','項安世','宋','宋诗','song-poetry','','[]','駟馬開華屋，祥羆降綺櫳。',96,'全唐诗/poet.song.147000.json','["駟馬開華屋，祥羆降綺櫳。", "嬰襦斑似錦，子珮綠於葱。", "好日逢重四，芳醪判一中。", "丰神春日柳，意氣雨天虹。", "未論龜巢藕，休言珀化楓。", "諸孫今遠大，吾祖舊沖融。", "努力名場近，收功鼎甲崇。", "但令賢弟貴，不怕老兄窮。"]'),
('ee844840-92bb-4497-99cf-316d346387e4','燎蚊','項安世','宋','宋诗','song-poetry','','[]','欲昏疑霧合，未暗已雷鳴。',228,'全唐诗/poet.song.147000.json','["欲昏疑霧合，未暗已雷鳴。", "驅逐無長策，紛紜劇亂兵。", "晝潜如設伏，夜嘯若先聲。", "喙慘戈矛利，身微坌𡏖輕。", "嘬膚來汗血，皤腹去朱櫻。", "壁以青油固，麾之白羽明。", "聞風聊讋息，得路即喧轟。", "婉婉工乘隙，騷騷故徹更。", "據經當烈澤，考傳合熸荆。", "耿耿銀缸動，熒熒爝火行。", "翼焦身尚奮，力盡勢還傾。", "壘合無逃虜，膏血可築京。", "周遭期勦絕，小大悉炮烹。", "爇左時驚合，禽縱或走橫。", "奔軍容蹔脫，搜諜靡餘生。", "走操華容道，追劉白帝城。", "周瑜方奏凱，陸遜遂成名。", "一覺華胥夢，千年戰國情。", "區區兩蠻觸，何足較踦贏。"]'),
('2e27c506-8398-46e2-b030-3535b18ee134','題狄彥哲雲溪隠居二首  其一','項安世','宋','宋诗','song-poetry','','[]','閑居郭內似村中，背市臨河一逕通。',64,'全唐诗/poet.song.147000.json','["閑居郭內似村中，背市臨河一逕通。", "案上漆書何世字，牆頭碧瓦古時宮。", "苦遭客子驚鷗鳥，閑在橋邊數釣筒。", "不是龐公怕城府，也來相就作漁翁。"]'),
('396659b2-c753-4536-9cec-acf38cb1d26d','題狄彥哲雲溪隠居二首  其二','項安世','宋','宋诗','song-poetry','','[]','江漢兵餘八十秋，後生誰及見前修。',64,'全唐诗/poet.song.147000.json','["江漢兵餘八十秋，後生誰及見前修。", "開元遺事無人說，正始諸賢何處求。", "此老尚堪矜式在，吾儕欲爲子孫謀。", "不嗔拱立煩鷄黍，時復敲門繫小舟。"]'),
('71481d50-5fa1-4f8e-9fe9-606cc02f4339','江陵送趙知縣二首  其一','項安世','宋','宋诗','song-poetry','','[]','萬壑千岩相送時，靈星小雪上豐頤。',64,'全唐诗/poet.song.147000.json','["萬壑千岩相送時，靈星小雪上豐頤。", "南雲北夢重分首，撲漉繁霜滿瘦髭。", "功業向來真自許，頭顱今日遂如斯。", "英雄老大無人識，足扣雙舷只自知。"]'),
('3cb6587e-10de-4b01-abae-bad011c87c3b','江陵送趙知縣二首  其二','項安世','宋','宋诗','song-poetry','','[]','別離底處最堪憐，君上吳船我蜀船。',64,'全唐诗/poet.song.147000.json','["別離底處最堪憐，君上吳船我蜀船。", "從此相思真萬里，重來何止又三年。", "司州刺史髭如戟，國子先生瘦似椽。", "二子有情須問訊，爲言重九向西川。"]'),
('ee7eff64-b322-4bec-aee2-44bdeddc7a7d','次劉子野送別韻','項安世','宋','宋诗','song-poetry','','[]','賈誼莫思行說背，陳湯空想郅支頭。',64,'全唐诗/poet.song.147000.json','["賈誼莫思行說背，陳湯空想郅支頭。", "子規枝上三更覺，白鷺山前萬事休。", "櫜矢戢戈歌四夏，带牛佩犢免防秋。", "一犂先向東郊去，稻滑蔬肥百不愁。"]'),
('dd8145e8-89d6-4e78-8fe8-37638cb63bd6','次曾宣幹煥送別韻','項安世','宋','宋诗','song-poetry','','[]','戎事急於翻白餠，人情難似塞黄河。',64,'全唐诗/poet.song.147000.json','["戎事急於翻白餠，人情難似塞黄河。", "誰能戴雪三千丈，更踏衝風十二波。", "父老共傾同社酒，兒童齊唱牧牛歌。", "煩君爲較田家樂，比似兵家孰少多。"]'),
('3387d622-fa54-4dec-90a9-a7264fe37d58','次韻','項安世','宋','宋诗','song-poetry','','[]','高沙白魝記天如，葵扇桃笙度日居。',64,'全唐诗/poet.song.147000.json','["高沙白魝記天如，葵扇桃笙度日居。", "詩裏燕蟲時漫與，醉中鷗鳥正于胥。", "忽遭喚起披金甲，自笑平生論石渠。", "身世萬端誰得料，一番江雨又成餘。"]'),
('d2c66b0a-3e94-464d-8088-0845a433bb56','伯父新園','項安世','宋','宋诗','song-poetry','','[]','屋後回堤可當山，屋前溝港轉清灣。',64,'全唐诗/poet.song.147000.json','["屋後回堤可當山，屋前溝港轉清灣。", "行人自笑高花外，倦客方吟積翠間。", "曲折故應憐窈窕，崎嶇未覺厭躋攀。", "小橋直下前村路，百頃平園錦繡斑。"]'),
('562664f5-9bfb-408a-b62d-610e765f02d4','憶宗道舊遊','項安世','宋','宋诗','song-poetry','','[]','十八年前勝共饒，兩青不借一枯焦。',64,'全唐诗/poet.song.147000.json','["十八年前勝共饒，兩青不借一枯焦。", "狂挑藥澗尋瓊闕，醉踏經臺問玉霄。", "華頂雲開千嶂露，赤城天近九霞飄。", "祇今只羨蒲團穩，坐看雙龍上石橋。"]'),
('d5eb8d2e-48bd-4c90-81e5-719b28f18c3c','用舍弟韻送妹婿鄭子仁湖南漕試','項安世','宋','宋诗','song-poetry','','[]','筆力追風內廐黄，詞源下峽九秋艎。',64,'全唐诗/poet.song.147000.json','["筆力追風內廐黄，詞源下峽九秋艎。", "經行帝子雲璈地，祓飾騷人月璐章。", "親老一生兒共婿，吾衰七見暑成凉。", "門闌正倚乘龍重，快踏層雲覲九陽。"]'),
('a56cd157-e099-410a-a309-649061f0df0e','送右史納官還鄉','項安世','宋','宋诗','song-poetry','','[]','去國無庸似葉輕，丈夫胡忍此收名。',64,'全唐诗/poet.song.147000.json','["去國無庸似葉輕，丈夫胡忍此收名。", "遲遲自罄臣心力，戀戀猶貪主聖明。", "正爾釣絲江上去，依然羽扇篋中情。", "平生詎作求田學，要與君王佐治平。"]'),
('75dd34a4-59c8-4bf1-a582-cef7dc58c1f3','金陵送左史','項安世','宋','宋诗','song-poetry','','[]','臨歧摻袂欲何言，罷酒開船色惘然。',64,'全唐诗/poet.song.147000.json','["臨歧摻袂欲何言，罷酒開船色惘然。", "萬里重逢儻無日，一杯相屬豈非天。", "修鱗去蟄三池浪，倦翼歸投萬壑烟。", "從此登臨只西首，美人家在夕陽邊。"]'),
('305713ee-14f9-4612-8021-2685bdeb8a90','次韻張以道苕溪','項安世','宋','宋诗','song-poetry','','[]','諸人鼎列更茵重，客子愁邊或酒中。',64,'全唐诗/poet.song.147000.json','["諸人鼎列更茵重，客子愁邊或酒中。", "雲縞弁山溪正碧，畫無名手句專功。", "年華若看蟻旋磨，世話何難龜蛻筒。", "明日一蓑苕霅去，與君相伴作漁翁。"]'),
('49de0b8c-81aa-4b3b-840f-e20c02d752e1','水仙花','項安世','宋','宋诗','song-poetry','','[]','意濃態遠十洲人，歲晏天寒七澤濱。',64,'全唐诗/poet.song.147000.json','["意濃態遠十洲人，歲晏天寒七澤濱。", "奕奕雲冠疑映月，僛僛翠带欲摇春。", "梅稍枉爲行人瘦，柳眼虛隨酒市新。", "林下水邊風味永，弄珠誰見漢臯神。"]'),
('c8523bf2-696c-4358-9c9d-5d12ce2bf10f','和胡撫幹水仙花韻','項安世','宋','宋诗','song-poetry','','[]','瑶池蓬島舊題名，歲晚江湖得此生。',64,'全唐诗/poet.song.147000.json','["瑶池蓬島舊題名，歲晚江湖得此生。", "水戰風摇疑體弱，雪欺霜壓見神清。", "佩衿濟濟賢師友，蘭玉詵詵好弟兄。", "笞鳳鞭鸞雲澤畔，向人懷抱十分傾。"]'),
('5992937f-4d99-469b-b1be-e270a6d8e453','次韻張直閣水仙花二首  其一','項安世','宋','宋诗','song-poetry','','[]','買得名花共載歸，春風滿眼豫章詩。',64,'全唐诗/poet.song.147000.json','["買得名花共載歸，春風滿眼豫章詩。", "銀臺挹月盃光瀲，翠被臨波韈影遲。", "山鬼湘娥通系牒，梅兄礬弟絕藩籬。", "我家正在江橫處，一笑相看更莫疑。"]'),
('b16e4398-35f8-4da2-a6ff-d842679cb175','次韻張直閣水仙花二首  其二','項安世','宋','宋诗','song-poetry','','[]','貝闕珠宮日月長，青鸞白鳳恣翺翔。',64,'全唐诗/poet.song.147000.json','["貝闕珠宮日月長，青鸞白鳳恣翺翔。", "試煩鍾子傳琴操，莫向田郎問國香。", "風裏翠鬟慵整頓，月中幽恨自凄凉。", "鷗波萬頃情何限，未羨春花占洛陽。"]'),
('fe7f6d82-31ff-4ed1-9881-5001128db6e5','登石頭山','項安世','宋','宋诗','song-poetry','','[]','山腰萬竹閟清寒，上徹山頭望始寬。',64,'全唐诗/poet.song.147000.json','["山腰萬竹閟清寒，上徹山頭望始寬。", "州渚東西分線路，臺城表裏見毫端。", "青開淮甸天空闊，紫覆鍾山氣鬰盤。", "城下秋江來萬里，獨能伸手障狂瀾。"]'),
('b94e2220-7a91-4e57-8583-6bba12987e79','過上海寨昔人於此潴水以限北方','項安世','宋','宋诗','song-poetry','','[]','原田漫漫不知津，春寨清明思殺人。',64,'全唐诗/poet.song.147000.json','["原田漫漫不知津，春寨清明思殺人。", "雨後燒痕無潤澤，烟中日色少精神。", "郢城南地溝隍古，海寨東西徑遂新。", "誰見當時經畫意，只今高浪化征塵。"]'),
('eb0c7c6b-9ac5-4dc1-bd75-cebb868340c3','次韻答胡季履復荆門故宅','項安世','宋','宋诗','song-poetry','','[]','鏡裏枯疎雪點毛，筆端凌亂雨浮膏。',64,'全唐诗/poet.song.147000.json','["鏡裏枯疎雪點毛，筆端凌亂雨浮膏。", "侵疆稍稍龜陰復，作堵渠渠鴻雁勞。", "喬木有孫關國體，故基能築是人豪。", "自言書就堪□□，誰謂先公論太高。"]'),
('74d46eb7-d14d-49be-a918-5bc9b81205e4','陪閻安撫觀開漕河','項安世','宋','宋诗','song-poetry','','[]','爲民行水不妨農，爲國憂民不費公。',64,'全唐诗/poet.song.147000.json','["爲民行水不妨農，爲國憂民不費公。", "肯趁好天招惡客，能於舊貫立新功。", "山頭石埭千年計，海上靈查八月通。", "只恐濟川舟楫快，使君難滯郢城中。"]'),
('038168d1-104d-4140-82b3-ef79db98d489','立春前一日書事','項安世','宋','宋诗','song-poetry','','[]','明日天車始建寅，今朝猶是去年人。',64,'全唐诗/poet.song.147000.json','["明日天車始建寅，今朝猶是去年人。", "江城半夜傳黄紙，嘉定新書下紫宸。", "山雪多情來送臘，湖波著色去迎春。", "旋烘寒餠纏生菜，想見家貧憶路貧。"]'),
('136e4ba5-219c-4098-810f-46a2207a4e51','丁教授家貓狗皆相乳二首  其一','項安世','宋','宋诗','song-poetry','','[]','周郊奉犬用刑樽，堯蜡迎貓似捕神。',64,'全唐诗/poet.song.147000.json','["周郊奉犬用刑樽，堯蜡迎貓似捕神。", "直是蘇公比臺諫，未知韓子喻家人。", "鷹鸇化作鸞將鳳，獬廌移成騶與麟。", "煦煦徐徐何必善，使知剛毅有深仁。"]'),
('3767bca3-459f-40f9-bb18-94f967a74f55','丁教授家貓狗皆相乳二首  其二','項安世','宋','宋诗','song-poetry','','[]','血人于牙犬政猛，殺鼠如邱貓事獰。',64,'全唐诗/poet.song.147000.json','["血人于牙犬政猛，殺鼠如邱貓事獰。", "鄰子忽如親子愛，人情何似物情平。", "再三仁者須存勇，萬一天資與習成。", "恐被麋麑邀作友，或遭鼠弟□爲兄。"]'),
('103426bc-4ee6-47e9-8f69-44b773bf6c2c','會葬外舅還過李萬州墓下','項安世','宋','宋诗','song-poetry','','[]','又送人間一古今，兩翁相望接雲岑。',64,'全唐诗/poet.song.147000.json','["又送人間一古今，兩翁相望接雲岑。", "屈伸固是乾坤用，惻愴豈非天地心。", "野迥茆風聲索索，山深松日影陰陰。", "平生來往風流在，應有幽人見苦吟。"]'),
('df1500e3-6215-4813-b507-0b852e11f2ab','次韻田將仕年八十八歲作詩自喜三首  其一','項安世','宋','宋诗','song-poetry','','[]','東坡來飯辯才師，元祐真人宥密時。',64,'全唐诗/poet.song.147000.json','["東坡來飯辯才師，元祐真人宥密時。", "生長太平經戰伐，浮沈薄宦寄喧卑。", "五朝遺老今誰在，萬事當時恨獨知。", "此世閲人如傳舍，吾人安更用名爲。"]'),
('19c7dd14-f392-4717-a77f-442813ecf217','次韻田將仕年八十八歲作詩自喜三首  其二','項安世','宋','宋诗','song-poetry','','[]','銅駝陌上少年時，走馬驅車遠四畿。',64,'全唐诗/poet.song.147000.json','["銅駝陌上少年時，走馬驅車遠四畿。", "又見伏符明漢道，曾傷小雅詠周微。", "一生世路高和下，何恨人情瘠與肥。", "老矣胸懷百無著，自梳朝夕鬢毛稀。"]'),
('a036c1f8-fe1d-4c19-aecd-0279e177d8f4','次韻田將仕年八十八歲作詩自喜三首  其三','項安世','宋','宋诗','song-poetry','','[]','茅簷桑戶落窮居，兩眼猶能讀細書。',64,'全唐诗/poet.song.147000.json','["茅簷桑戶落窮居，兩眼猶能讀細書。", "自說此生聊爾耳，亦知餘事竟何如。", "春雲入眼元無迹，秋竹刳心久更虛。", "天與精神自難老，會看千歲跨龍魚。"]'),
('91d6aa45-2d0a-4ae3-a7a8-b3af12b51ecf','查元信餉日鑄茶因用其韻感嘆舊遊','項安世','宋','宋诗','song-poetry','','[]','芒鞋衝雨上茶園，綠髮晞風正少年。',64,'全唐诗/poet.song.147000.json','["芒鞋衝雨上茶園，綠髮晞風正少年。", "重見靈光元好在，却循雙鬢已蒼然。", "芽生日鑄無多樹，瓶採千山自昔年。", "小碾芽心成雪後，微鋪瓶頂便天然。"]'),
('ec5cc622-1e11-4cd1-85b2-b8c2e16f8e01','次韻朱通判寄示盤龍山觀瀑詩','項安世','宋','宋诗','song-poetry','','[]','百尺山頭下玉龍，吾人到此得參同。',64,'全唐诗/poet.song.147000.json','["百尺山頭下玉龍，吾人到此得參同。", "河來積石崑崙頂，日出蓬萊碧海東。", "直自陰陽隨處有，强分泉火本來空。", "君看擊石還呵硯，燥濕先生一性中。"]'),
('3dfa4033-2212-4363-837c-f30cf14449f4','迓朱侍講','項安世','宋','宋诗','song-poetry','','[]','欲就前賢去不如，幾年功力在三餘。',64,'全唐诗/poet.song.147000.json','["欲就前賢去不如，幾年功力在三餘。", "終然覺我多金鑛，幸甚逢翁侍玉除。", "函丈中間親覓訣，殘編裏許細觀書。", "自憐舊習如塵汙，入髮成膠未易梳。"]'),
('33d023cc-afd0-48bb-b6ec-d98865d6ef4f','次韻路德章吳斗南同迓朱侍講','項安世','宋','宋诗','song-poetry','','[]','兩年京洛筆生埃，忽見清詩眼爲開。',64,'全唐诗/poet.song.147000.json','["兩年京洛筆生埃，忽見清詩眼爲開。", "蕭灑併將秋色寫，雄豪更带夜潮來。", "可憐拄腹五千卷，誰與澆愁三百盃。", "莫遺晦翁聞世事，怕教興盡却思回。"]'),
('e62adea9-de6b-48cc-964a-af2fef5a060d','觀瀾閣','項安世','宋','宋诗','song-poetry','','[]','先生高閣水之濱，一禿翁從衆主人。',64,'全唐诗/poet.song.147000.json','["先生高閣水之濱，一禿翁從衆主人。", "欲說觀瀾先自愧，况逢收潦更難陳。", "霜餘過瀨聲逾急，日落浮霞景轉新。", "千里迢迢春不斷，陶潜曾點是知津。"]'),
('025fc34b-ff70-403c-a4f1-2c3d7719fc9f','次胡仲方東湖送別韻','項安世','宋','宋诗','song-poetry','','[]','祇知白下棠花白，不記湖邊草色新。',64,'全唐诗/poet.song.147000.json','["祇知白下棠花白，不記湖邊草色新。", "鬰鬰樓臺籠戍柳，荒荒苔蘚畫遊舲。", "重來老子慚無恨，徉卧尊前醉不醒。", "投曉張帆順風去，怕遭民吏笑明廷。"]'),
('3077c362-851c-481d-9e39-5f748c77c803','鷄冠後庭花同賦','項安世','宋','宋诗','song-poetry','','[]','長日鷄冠短後庭，倚風邪佇不勝情。',64,'全唐诗/poet.song.147000.json','["長日鷄冠短後庭，倚風邪佇不勝情。", "宋宗窗畔親曾識，陳氏宮中舊得名。", "尚想蹁躚啼曉意，猶疑宛轉隔江聲。", "恓惶借與非常色，染出猩紅特地明。"]'),
('fca5f68f-48ab-4882-8408-32e476154398','衛州東湖','項安世','宋','宋诗','song-poetry','','[]','自笑知州百不知，近他池館未曾窺。',64,'全唐诗/poet.song.147000.json','["自笑知州百不知，近他池館未曾窺。", "主人正可今爲客，和議初成恰是時。", "草色茸茸花覆座，波光灧艷酒浮卮。", "留連枉是憑欄久，洗得當年了事癡。"]'),
('58df969d-ca0b-4e49-8b9e-fe76fa349d45','香海棠下會飲','項安世','宋','宋诗','song-poetry','','[]','近看成洞遠成林，紅綠參差作晝陰。',64,'全唐诗/poet.song.147000.json','["近看成洞遠成林，紅綠參差作晝陰。", "閑有工夫隨酒去，病無心力爲花吟。", "調朱弄粉年應小，倚困含嬌意却深。", "更向嫣然清淑外，一簷香氣入衣襟。"]'),
('dbfee31c-9a2b-47da-be8a-cbe08827748b','元夕劉知錄招飲','項安世','宋','宋诗','song-poetry','','[]','曾吹藜杖到蓬萊，親見銀潢鐵鏁開。',64,'全唐诗/poet.song.147000.json','["曾吹藜杖到蓬萊，親見銀潢鐵鏁開。", "析木津頭排列宿，鼇山脚下走輕雷。", "荒城夜雪欺行李，畫角晨霜送落梅。", "鄰舍相呼同酒盞，也教人道上元來。"]'),
('a21e1e76-7295-44c6-ae9e-6d46a0716542','崔成州將赴官招客劇飲次袁主管韻  其一','項安世','宋','宋诗','song-poetry','','[]','飲量詩才總不慳，一襟離緒竟難宣。',64,'全唐诗/poet.song.147000.json','["飲量詩才總不慳，一襟離緒竟難宣。", "橫行秦徼看飛將，流落巴山記散僊。", "較第賓朋勝酒盞，留連僮僕費金錢。", "更闌上馬情懷惡，髣髴滄江送畫船。"]'),
('a647427b-bf10-4533-bb3d-46d1d03acbd9','崔成州將赴官招客劇飲次袁主管韻  其二','項安世','宋','宋诗','song-poetry','','[]','段家池館已灰煙，更說江家六百年。',64,'全唐诗/poet.song.147000.json','["段家池館已灰煙，更說江家六百年。", "但有小橋通綠水，不妨高閣看青天。", "鍾山月到東城角，淮口潮來上閘邊。", "兩行紅旗射西日，明朝漢使點樓船。"]'),
('7116bec9-fbe7-4b80-bbea-e2d1b81d64f2','楊帥二首  其一','項安世','宋','宋诗','song-poetry','','[]','謝天增霸復留恂，又到當時繫袚辰。',64,'全唐诗/poet.song.147000.json','["謝天增霸復留恂，又到當時繫袚辰。", "寶带正看金芍藥，璽書重傅玉麒麟。", "上元新歷開千歲，作噩祥名冠六辛。", "恰用此年鍾此傑，便乘嘉泰轉洪釣。"]'),
('7c889181-feb5-4a6b-a624-662bf664c920','楊帥二首  其二','項安世','宋','宋诗','song-poetry','','[]','更須石叟共甘公，酌得民言帝自同。',64,'全唐诗/poet.song.147000.json','["更須石叟共甘公，酌得民言帝自同。", "四海人才容接裏，百城生聚撫摩中。", "似聞聖世開皇極，欲倚名賢鎮士風。", "看把璇璣扶大運，久於箕翼厚於嵩。"]'),
('633e7aec-e102-4221-8c54-812db5a34995','阻風','項安世','宋','宋诗','song-poetry','','[]','阻風多日飯無羹，病酒中年睡不成。',64,'全唐诗/poet.song.147000.json','["阻風多日飯無羹，病酒中年睡不成。", "撲面飛蚊來似鴨，閉船吹燭守如城。", "良朋處處愁分袂，遠客朝朝怕說兵。", "石首山頭逢一笑，白雲相望雨新晴。"]'),
('16356be0-e7fa-4ad4-92d7-d66959ae7d9c','順風至岳州危甚','項安世','宋','宋诗','song-poetry','','[]','黑雲將雨向巴邱，白浪奔雷送客舟。',64,'全唐诗/poet.song.147000.json','["黑雲將雨向巴邱，白浪奔雷送客舟。", "一路逆風纔得順，百年何日是無愁。", "神林浦外飛沙惡，道士磯頭亂石稠。", "繫纜南津聞笑語，船船鷄酒謝神休。"]'),
('1093ca8e-dadc-4e57-b8f5-bebe107c4376','別岳州','項安世','宋','宋诗','song-poetry','','[]','五更鼉鼓忽逢逢，舟子聞晴上北江。',64,'全唐诗/poet.song.147000.json','["五更鼉鼓忽逢逢，舟子聞晴上北江。", "推枕一兵辭畫戟，開門三騎到篷窗。", "鹿鳴厚意陳箱篚，伐木深情綴酒腔。", "小雅風流千古在，飛吟亭下此心降。"]'),
('03f2f4c3-f7f7-4637-ab8e-6538f568e8e9','送孫司戶秩滿東歸考試鄂渚二首  其一','項安世','宋','宋诗','song-poetry','','[]','千年把號趁朝班，猶著青衫候曉關。',64,'全唐诗/poet.song.147000.json','["千年把號趁朝班，猶著青衫候曉關。", "冷甚高僧禪榻畔，清於寒露玉壺間。", "文章奇古源西漢，詩律精深祖後山。", "師友平生能幾許，又隨征鴈看湘鬟。"]'),
('dac58358-616c-46a0-91e2-6dcc93447a79','送孫司戶秩滿東歸考試鄂渚二首  其二','項安世','宋','宋诗','song-poetry','','[]','秋風一舸下滄浪，想見占繇聽鵲忙。',64,'全唐诗/poet.song.147000.json','["秋風一舸下滄浪，想見占繇聽鵲忙。", "兩夏作僧猶有債，三旬爲客更須償。", "君才有用今千里，我拙無堪尚一方。", "好去玉霄雲海上，寄聲江漢永相望。"]'),
('d36635b2-775c-4130-ae0a-01f712276f1f','和高撫州用韻相招','項安世','宋','宋诗','song-poetry','','[]','能使邦人保里閭，不能一日自安居。',64,'全唐诗/poet.song.147000.json','["能使邦人保里閭，不能一日自安居。", "廢興何敢於人怨，溫飽從來作計疏。", "舊景陸公新景賀，大題詩句小題廬。", "慇慇喚我江西去，只用官船不用車。"]'),
('da92b850-6a9f-41cf-90cb-b48b0333c061','南康尉司射亭後軒盡見廬山爲取東坡覺來滿眼是廬山之句名曰覺軒','項安世','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','千堆白浪捲彭湖，一葉青帆映大孤。',64,'全唐诗/poet.song.147000.json','["千堆白浪捲彭湖，一葉青帆映大孤。", "夢裏東坡魂尚魘，岸傍梅福笑相呼。", "開門翠壁連天是，回首驚波一事無。", "推下黄紬見真意，的知陶令是賢乎。"]'),
('e3562a26-7c80-40d8-98de-02a25e46a32e','賦竟陵毛氏新港亭','項安世','宋','宋诗','song-poetry','','[]','倚東湖浪看西江，結小紅橋渡綠窗。',64,'全唐诗/poet.song.147000.json','["倚東湖浪看西江，結小紅橋渡綠窗。", "白水遶階人逕絕，青天入坐客心降。", "篔簹影外聞仙磬，菡萏香中見佛幢。", "從此竟陵城左右，陸泉毛港一雙雙。"]'),
('e1c54d40-403d-45ee-85db-a2245db4fcf3','重陽復晴再次前韻','項安世','宋','宋诗','song-poetry','','[]','一天雲物護輕寒，陣陣清風約雨乾。',64,'全唐诗/poet.song.147000.json','["一天雲物護輕寒，陣陣清風約雨乾。", "造物有情聊作戲，詩家無頼强尋歡。", "吾人已辦泥沾帽，曉色還教日照盤。", "咫尺龍山君莫負，草枯霜野正平寬。"]'),
('baa14b53-8a5f-405f-b643-4f6644f5a23d','宋帥移厨就市樓併飯胡黎州','項安世','宋','宋诗','song-poetry','','[]','天明喜氣滿沙頭，小隊行厨下楚樓。',64,'全唐诗/poet.song.147000.json','["天明喜氣滿沙頭，小隊行厨下楚樓。", "太白穩歸雲闕去，德星聊向雪山遊。", "澹翁不爲重溟怯，令子何辭九折愁。", "榮殺上官窮觀主，助公持酒記觥籌。"]'),
('8518808e-52ce-4a41-84e7-a64644220a06','次韻李著作送行二首  其一','項安世','宋','宋诗','song-poetry','','[]','羣居未信相從樂，要識相從是別離。',64,'全唐诗/poet.song.147000.json','["羣居未信相從樂，要識相從是別離。", "芸閣掩關當宿夜，江船吹火未眠時。", "無人見鴈同持酒，有客看猿自賦詩。", "詩墨酒痕隨處有，故人誰與寄將知。"]'),
('fdbdf7a4-d1d1-4fcc-b2a0-8eca38049e80','次韻李著作送行二首  其二','項安世','宋','宋诗','song-poetry','','[]','秋來定有池陽雁，飛過蓬萊報子知。',64,'全唐诗/poet.song.147000.json','["秋來定有池陽雁，飛過蓬萊報子知。", "天上舊遊今似夢，覺來追憶始堪悲。", "簷前日屋融融暖，閣下風廊細細吹。", "最愛石渠明月夜，清霜飛下老梅枝。"]'),
('e1228829-a6ed-4595-b317-5c6a97065126','和平江府倪教授送行','項安世','宋','宋诗','song-poetry','','[]','拜辭初下九天來，乞得斑衣學老萊。',64,'全唐诗/poet.song.147000.json','["拜辭初下九天來，乞得斑衣學老萊。", "六月火雲烘去艇，三山風露隔飛埃。", "多情送我詩盈軸，何意辭君酒一杯。", "後夜相思江雨黑，短檠寒焰錦囊開。"]'),
('c46fb4fe-7407-4b25-9fc8-b28470f92e19','又次韻沈告院送行二首  其一','項安世','宋','宋诗','song-poetry','','[]','前年倚席湘山下，曾得新篇勝玉葩。',64,'全唐诗/poet.song.147000.json','["前年倚席湘山下，曾得新篇勝玉葩。", "今日題輿秋浦上，又煩佳句溢瓊華。", "雲霄策足君方駛，風雨論心我未涯。", "正向齊山插黄菊，遥知已對紫薇花。"]'),
('5b5b9c7f-c3e7-4b31-b6d3-652021e069c2','又次韻沈告院送行二首  其二','項安世','宋','宋诗','song-poetry','','[]','江頭水落鴈初下，江上魚肥酒可中。',64,'全唐诗/poet.song.147000.json','["江頭水落鴈初下，江上魚肥酒可中。", "秋浦到時應正好，昔賢題後恐難工。", "三年禁直消長日，六月脩廊飫午風。", "天上素餐吾已媿，更來閑處理漁筒。"]'),
('6d98e187-ae02-4c88-a991-5a988b9f5887','又次韻鄧漢卿秀才送行','項安世','宋','宋诗','song-poetry','','[]','春風不療鬢邊霜，閑處輸君笑我忙。',64,'全唐诗/poet.song.147000.json','["春風不療鬢邊霜，閑處輸君笑我忙。", "衮衮懸河煩卒吐，疎疎冷銼頼于湘。", "去鑽芸帙翻成蠹，飛下芹泥只願頏。", "鑑水舊遊零落盡，相逢猶忍話髯郎。"]'),
('ef3f1e11-d51b-4d12-9595-201d2b15ea0b','又次韻楊祕書送行','項安世','宋','宋诗','song-poetry','','[]','設矩陳繩勸蹈中，雕龍炙輠戒多窮。',64,'全唐诗/poet.song.147000.json','["設矩陳繩勸蹈中，雕龍炙輠戒多窮。", "有誰心肯明斯語，無限人知敬此翁。", "信有德隅當並進，可能性地獨幽通。", "相分便作相逢計，此事它時驗庳崇。"]'),
('d49a7900-dfaf-488c-8388-ad04bf568e2b','爲吳司戶作甕天','項安世','宋','宋诗','song-poetry','','[]','筆端隨意出洪纖，康俗山前自在禪。',64,'全唐诗/poet.song.147000.json','["筆端隨意出洪纖，康俗山前自在禪。", "已把屋來嘲作甕，更將詩去諂爲天。", "蛆浮蠛舞無多子，鵾運鵬遊即大千。", "敢向時人稱萬卷，不妨李渤但如拳。"]'),
('57020d70-6dc3-4555-82ec-f8411da6614f','喜晴','項安世','宋','宋诗','song-poetry','','[]','一年蠶麥九分成，十日雲雷萬感生。',64,'全唐诗/poet.song.147000.json','["一年蠶麥九分成，十日雲雷萬感生。", "雨似梅天聲陸續，浪乘桃月勢崢嶸。", "猛拚歲事真無策，大放春光却有情。", "世故從來多錯料，落花飛絮未須驚。"]'),
('a3c2096d-d497-46a4-a07e-b073f00fa40c','題胡仲方詩編','項安世','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','讀君百二十新篇，句句停勻字字妍。',64,'全唐诗/poet.song.147000.json','["讀君百二十新篇，句句停勻字字妍。", "秀似南風吹竹粉，潤於春水濕花烟。", "斯文貴盛看如此，前路飛騰諒果然。", "東野長江寒到骨，一生憔悴豈關天。"]'),
('0d18ab2f-6543-4581-9bc3-c529dcf467c5','圩田','項安世','宋','宋诗','song-poetry','','[]','港裏高圩圩內田，露苗風影碧芊芊。',64,'全唐诗/poet.song.147000.json','["港裏高圩圩內田，露苗風影碧芊芊。", "家家繞屋栽楊柳，處處通渠種芰蓮。", "老去何年真有此，客中半世尚茫然。", "自憐赤日黄流裏，又買揚州上水船。"]'),
('b0ea6128-c93e-4e23-a759-14a0f8c41f3f','賦曹開府遺事','項安世','宋','宋诗','song-poetry','','[]','大隗山前苦露深，佛狸江上劍成林。',64,'全唐诗/poet.song.147000.json','["大隗山前苦露深，佛狸江上劍成林。", "當時不作一身計，聖主自明方寸心。", "勇去崢嶸都是膽，歸來靜密不聞音。", "平生羞預外庭事，此段當鎸墓石陰。"]'),
('894575bb-c0d5-49fa-a4f3-ae00f26c5c90','江月亭會飲次袁主管韻惱吳鈐轄','項安世','宋','宋诗','song-poetry','','[]','日西移幕看澄江，夜久回屏護燭光。',64,'全唐诗/poet.song.147000.json','["日西移幕看澄江，夜久回屏護燭光。", "暗裏微明認漁火，醉中時醒爲荷香。", "狂翻鸚鵡盃心綠，怒索蒲萄架底凉。", "苦恨重雲隔明月，嫦娥更在月中央。"]'),
('001ea016-1240-4bc1-b70b-66b3a523206d','任至道招飲香海棠下','項安世','宋','宋诗','song-poetry','','[]','眼見名花病已輕，手攀芳樹思如酲。',64,'全唐诗/poet.song.147000.json','["眼見名花病已輕，手攀芳樹思如酲。", "飄零萬片都無恨，點綴殘枝更有情。", "日暮莫辭銀燭照，夜寒誰爲寶瓶生。", "飲闌可怕留連久，滿地香紅忍得行。"]'),
('a9bad8e7-8f51-4c60-af6b-1cb7790ae758','送江陵柳教授歸潭州','項安世','宋','宋诗','song-poetry','','[]','上苑歸來十六年，青山相對各無氈。',64,'全唐诗/poet.song.147000.json','["上苑歸來十六年，青山相對各無氈。", "道林說法非吾坐，絳帳談經覺子賢。", "舉世不爲寒畯地，先生未改腐儒天。", "親朋莫訝知音少，直道傳家自祖先。"]'),
('f2191db1-3380-416c-b777-1fcc7d5603a0','上元','項安世','宋','宋诗','song-poetry','','[]','月華未上鼓聲喧，又向山陰過上元。',64,'全唐诗/poet.song.147000.json','["月華未上鼓聲喧，又向山陰過上元。", "五歲鏡湖纔一熟，今年燈市始應煩。", "留連晝景通三夜，呼吸陽和達九門。", "遊客不知千古意，看人看火漫奔奔。"]'),
('6dbfa8dd-db0e-447e-a491-c118b3b1b311','元日用前韻','項安世','宋','宋诗','song-poetry','','[]','元日今年分外寒，先生堅卧正如山。',64,'全唐诗/poet.song.147000.json','["元日今年分外寒，先生堅卧正如山。", "鄉閭草草兵戈外，雨雪棲棲道路間。", "兒女有情催我起，盃盤無緒笑人慳。", "何因得似江城鴈，未轉東風已北還。"]'),
('dfe64aae-b51c-4760-9b03-fc1550a92e4e','晨起偶成','項安世','宋','宋诗','song-poetry','','[]','清瀼堂中自喜時，行蹤漸少世人知。',64,'全唐诗/poet.song.147000.json','["清瀼堂中自喜時，行蹤漸少世人知。", "角門閉斷無閑客，紙閣糊成教小兒。", "二十道錢充日用，兩三石米了晨炊。", "夜眠一枕庭闈夢，此外都無事可思。"]'),
('7d77b0e5-4ed3-4515-9fc5-73e2d86956a5','送許狀元赴召','項安世','宋','宋诗','song-poetry','','[]','十年門巷斷經過，讀易吟詩長薜蘿。',64,'全唐诗/poet.song.147000.json','["十年門巷斷經過，讀易吟詩長薜蘿。", "始向新春歌伐木，忽逢佳士赴卷阿。", "面如呂叟精神王，身似章公貴氣多。", "既出不應猶爲我，未知賢者意如何。"]'),
('71005115-73ce-4bcb-92b3-a43ca620e99e','五日常州借閘','項安世','宋','宋诗','song-poetry','','[]','踏車如市水如金，守閘如城不放人。',64,'全唐诗/poet.song.147000.json','["踏車如市水如金，守閘如城不放人。", "共倚河渠通北使，可憐膏澤養邊臣。", "平生自計更蓑笠，此日何顔玷搢紳。", "欲換小舟跳堰去，沙邊漁子得相親。"]'),
('804248ac-bee5-4164-bd68-ff6aaae91339','寄題臨江徐氏海棠巢','項安世','宋','宋诗','song-poetry','','[]','紅錦山顛著醉眸，赤欄桿外數花頭。',64,'全唐诗/poet.song.147000.json','["紅錦山顛著醉眸，赤欄桿外數花頭。", "烟中月下看不足，葉裏花間睡即休。", "迷住子規疑蜀國，歸來黄鵠認柯邱。", "他時我與君爲對，蓮葉中間作釣舟。"]'),
('64c4313a-4f78-44e9-81bb-ceebe806c343','答張功甫寺丞','項安世','宋','宋诗','song-poetry','','[]','張叟至今憐項叟，杭州依舊憶荆州。',64,'全唐诗/poet.song.147000.json','["張叟至今憐項叟，杭州依舊憶荆州。", "亥年詩到子年答，十月書來正月收。", "了女了兒多已過，半饑半飽不須愁。", "且圖今日勝前日，一任黑頭成白頭。"]'),
('230c0b25-b6db-4bfe-87d5-17a6be7c7ead','次韻重陽值雨','項安世','宋','宋诗','song-poetry','','[]','莫向西風怨雨寒，登高元自不須乾。',64,'全唐诗/poet.song.147000.json','["莫向西風怨雨寒，登高元自不須乾。", "葛巾漉酒何妨濕，破帽沾泥亦足歡。", "喚醉自應泉灑面，養花兼得露盈盤。", "游人幾許重陽恨，憑仗新詩一笑寬。"]'),
('67a375f2-e4d3-485e-b6ee-cd03acf2c060','送曹提幹歸永嘉兼寄陳君舉舍人  其一','項安世','宋','宋诗','song-poetry','','[]','西船滿載下東州，客子相傳不作羞。',64,'全唐诗/poet.song.147000.json','["西船滿載下東州，客子相傳不作羞。", "官長獨稱今有屬，川人爭誦古無儔。", "捫心但欲全吾寶，行世何嘗異此舟。", "爲報鄉閭看解橐，清永寒露勝琳球。"]'),
('006249bc-6619-4e6a-bc65-ad675a12686d','送曹提幹歸永嘉兼寄陳君舉舍人  其二','項安世','宋','宋诗','song-poetry','','[]','問訊東嘉老紫薇，年來多病世人知。',64,'全唐诗/poet.song.147000.json','["問訊東嘉老紫薇，年來多病世人知。", "坐親紅炭猶觴客，日飯黄芽未廢詩。", "左氏釋經工定了，周官著論夢應衰。", "西清眷眷君王意，欲喚申公草漢儀。"]'),
('b7de6b0d-6635-426a-8e0c-4f281d4618a0','勸醇甫酒','項安世','宋','宋诗','song-poetry','','[]','欲勸臨歧酒一卮，若爲啼笑若爲詞。',64,'全唐诗/poet.song.147000.json','["欲勸臨歧酒一卮，若爲啼笑若爲詞。", "情懷作惡中年後，親友相分久病時。", "少壯豈知人寂寞，庭闈方待子飛馳。", "飲闌百丈牽江去，挂起西川五色旗。"]'),
('fbc4b80d-0dcf-44f9-9acf-58d599ce4d97','二十九日出暗門循城至北關登舟','項安世','宋','宋诗','song-poetry','','[]','籃輿出郭轉牆隈，欲老芙蕖盡意開。',64,'全唐诗/poet.song.147000.json','["籃輿出郭轉牆隈，欲老芙蕖盡意開。", "天氣已凉猶索熱，官身得去未忙回。", "舟行何物非詩句，病後無情是酒盃。", "一笑團欒今在目，細挑燈火話蓬萊。"]'),
('dbaec05b-930c-440b-a7e7-e4e88f6f8c30','不出','項安世','宋','宋诗','song-poetry','','[]','老子年來驚五饋，閉門不出動經旬。',64,'全唐诗/poet.song.147000.json','["老子年來驚五饋，閉門不出動經旬。", "誰家花有傾城色，何處園無持酒人。", "直以故書消遣日，短於佳句柰何春。", "東君似欲相料理，柳外風來絮滿身。"]'),
('bc12e45a-23fa-4161-b9ff-67eca0113c14','寒食道中','項安世','宋','宋诗','song-poetry','','[]','秋千飛去過牆枝，風乙歸來矮屋楣。',64,'全唐诗/poet.song.147000.json','["秋千飛去過牆枝，風乙歸來矮屋楣。", "春色一如前度晚，鬢毛多似去年衰。", "碧雲莫唱愁紅曲，黄鳥休歌代木詩。", "方寸不禁如許思，門前楊柳正開眉。"]'),
('7482460b-da9d-4a10-b1a4-6d5188b0f288','林通判','項安世','宋','宋诗','song-poetry','','[]','東里相君新說似，茶陵軍使美無窮。',64,'全唐诗/poet.song.147000.json','["東里相君新說似，茶陵軍使美無窮。", "誰知楚戶南公口，更說沂康別駕功。", "人借一凉鏖鑠石，天開四莢照垂蓬。", "不爭玉女秋期日，自醉金公生數中。"]'),
('6ca387b6-9f16-4b74-9c07-cd8764b9ba1c','醉歸再用前韻','項安世','宋','宋诗','song-poetry','','[]','車中倒載笑兒童，馬上扶行夾驥熊。',64,'全唐诗/poet.song.147000.json','["車中倒載笑兒童，馬上扶行夾驥熊。", "安得風流如杜甫，偶然日夕似山公。", "幸無風雨成三厄，遇有聖賢須一中。", "數寄短章勞侍史，捲舒時得近春葱。"]'),
('23db8cf8-aed2-43b8-b267-f757934939f6','新茶','項安世','宋','宋诗','song-poetry','','[]','夭夭雀舌變槍旗，旟旆旃旌忽四馳。',64,'全唐诗/poet.song.147000.json','["夭夭雀舌變槍旗，旟旆旃旌忽四馳。", "槐火已登新鼎味，松風猶動故園思。", "森森苦口難追俗，脈脈甘津恐後時。", "何似當初陸鴻漸，莫將名字世人知。"]'),
('9d96bd05-6fc6-4a50-8dc6-7e46be1d38a7','以琴高魚茶芽送范蜀州','項安世','宋','宋诗','song-poetry','','[]','溪上幽人拾舊查，洞中丁戶採新芽。',64,'全唐诗/poet.song.147000.json','["溪上幽人拾舊查，洞中丁戶採新芽。", "欲乘赤鯉慚仙骨，自瀹霜毫愛乳花。", "莋路跨騾勝五馬，郵筒得酒散雙衙。", "武夷道士知君否，正擁風鸞裏月茶。"]'),
('ddb593d1-e71b-4989-aa37-9e492920b95a','還家即事','項安世','宋','宋诗','song-poetry','','[]','丁令歸來故國時，鄉人相見喜兼悲。',64,'全唐诗/poet.song.147000.json','["丁令歸來故國時，鄉人相見喜兼悲。", "鬢毛憔悴精神在，邑里荒殘府寺熙。", "坐處不堪推老大，親旁猶幸作嬰兒。", "莫言破虜前回事，得雨如今即是奇。"]'),
('45b6e986-a818-40d9-b074-7fc4437ea701','謝張直閣示南湖編','項安世','宋','宋诗','song-poetry','','[]','少時機杼入思惟，老去工夫更不疑。',64,'全唐诗/poet.song.147000.json','["少時機杼入思惟，老去工夫更不疑。", "二十卷詩除我讀，一生心事更誰知。", "字逢生處安逾穩，語到平時出轉奇。", "直與誠齋分坐席，定知傳習是宗師。"]'),
('7605ccc3-8fbd-482d-9295-35a1a5955d9f','胡仲方歸自武陵已過賤生尚煩追賀託柑致頌褒擬過情輒次韻爲謝','項安世','宋','宋诗','song-poetry','','[]','老後人間百不堪，形容今似過時柑。',64,'全唐诗/poet.song.147000.json','["老後人間百不堪，形容今似過時柑。", "液枯自斷仙無分，面皺猶宜佛作龕。", "更說吳姬兒女事，且尋湘頌友生談。", "行裝聞逐春風動，商樂無因餽相參。"]'),
('e396d935-f33a-4d6e-af0d-9272884f8d5e','春晴','項安世','宋','宋诗','song-poetry','','[]','東風瀾浪滿人間，小雨禁持故作慳。',64,'全唐诗/poet.song.147000.json','["東風瀾浪滿人間，小雨禁持故作慳。", "宿霧翳妝濃著色，新陽晞沐巧梳鬟。", "桃花落盡春無恙，柳絮飛忙日正閑。", "報答年光無酒伴，盡拈佳句爲江山。"]'),
('0f43909e-9ab8-4b59-9360-a1e741c93004','風水洞','項安世','宋','宋诗','song-poetry','','[]','君言洞好定非虛，只恐詩佳洞不如。',64,'全唐诗/poet.song.147000.json','["君言洞好定非虛，只恐詩佳洞不如。", "兩脚若能隨杖屐，一生何用更軒車。", "聽風聽水縱橫說，隨醉隨醒爛漫書。", "不解九重城裏路，有人塵土化衣裾。"]'),
('d36a6bef-3d8b-448f-8605-42cbccc72308','送敬甫弟赴省試','項安世','宋','宋诗','song-poetry','','[]','阿連明日去觀光，鶴髮今年喜倍常。',64,'全唐诗/poet.song.147000.json','["阿連明日去觀光，鶴髮今年喜倍常。", "船裏萬端須過慮，客中無事不周防。", "三經訓詁勤繙閱，一紙平安數寄將。", "反覆庭闈千萬意，早收名第獻高堂。"]'),
('31b1fed2-3583-4d4b-8248-b126bdf51f1a','和二十六日雪晴','項安世','宋','宋诗','song-poetry','','[]','雪中歡喜看瑶陵，雪後扶輿弄綺晴。',64,'全唐诗/poet.song.147000.json','["雪中歡喜看瑶陵，雪後扶輿弄綺晴。", "造物爲人添眼界，病夫隨處得心傾。", "江南江北融融暖，春草春花日日生。", "凍死窮簷吾不恨，欣欣同宇盡敷榮。"]'),
('2fb97f25-8984-461b-857e-ef1ffa16f741','富陽道中早行','項安世','宋','宋诗','song-poetry','','[]','山腰宿霧遠模糊，水面柔雲近有無。',64,'全唐诗/poet.song.147000.json','["山腰宿霧遠模糊，水面柔雲近有無。", "青女妝成連夜粉，鮫人啼盡一川珠。", "陽光稍稍褰層箔，春色徐徐展畫圖。", "試向東風揩病目，駕天青浪麥平鋪。"]'),
('5389743c-8d06-4cff-8c96-7acc755c9af8','晚晴','項安世','宋','宋诗','song-poetry','','[]','一首新詩轉晚晴，樓臺西畔斷霞明。',64,'全唐诗/poet.song.147000.json','["一首新詩轉晚晴，樓臺西畔斷霞明。", "浮雲過眼元無事，好月於人却有情。", "鵲噪畫簷何太喜，鶑啼綠樹已新聲。", "前村處處聞呼喚，明日沙田趁潤耕。"]'),
('63e89cea-1e0e-443d-ae2f-904f92f7d1b8','三月一日入襄州界先寄吳待制二首  其一','項安世','宋','宋诗','song-poetry','','[]','明德宮中大練衣，風流小阮世人知。',64,'全唐诗/poet.song.147000.json','["明德宮中大練衣，風流小阮世人知。", "斷無流水游龍夢，只有珊瑚碧樹詞。", "天上仙人持紫橐，邊頭武吏簸紅旗。", "男兒自要粗官作，肯被青雲富貴欺。"]'),
('2a3242ab-0ee9-4ba7-886f-4c71ae85177c','三月一日入襄州界先寄吳待制二首  其二','項安世','宋','宋诗','song-poetry','','[]','兒時夢到漢南州，四十頭顱未省遊。',64,'全唐诗/poet.song.147000.json','["兒時夢到漢南州，四十頭顱未省遊。", "此段風流愧人物，今年行役藉君侯。", "仲山甫有遺墟在，諸葛公存舊事不。", "欲借蹇馿馱醉帽，從公一一訪前修。"]'),
('538a079b-5c39-4bd0-bc4e-1968d6acb10d','二十二日入荆門界','項安世','宋','宋诗','song-poetry','','[]','四望亭前粉雉明，百欄橋上竹枝橫。',64,'全唐诗/poet.song.147000.json','["四望亭前粉雉明，百欄橋上竹枝橫。", "荒荒白日春將晚，渺渺黄岡草未生。", "獨客更無楊柳伴，遠村時見李花驚。", "白碑南路翻堪意，不恨衝泥踏水行。"]'),
('fe2697a9-43c0-4569-a7e2-10bf2a676272','送湖南盧提刑赴召三首  其一','項安世','宋','宋诗','song-poetry','','[]','幸甚他鄉識老誠，孰知真意徹幽明。',64,'全唐诗/poet.song.147000.json','["幸甚他鄉識老誠，孰知真意徹幽明。", "通身實地無奇巧，接面春風有至情。", "王事直須窮晝夜，宦途元不計公卿。", "無端自被功名迫，漢節衝寒上玉京。"]'),
('1a91757f-fa33-480b-89e1-5636c3fa8cec','送湖南盧提刑赴召三首  其二','項安世','宋','宋诗','song-poetry','','[]','世間除我更誰窮，老去知心僅有公。',64,'全唐诗/poet.song.147000.json','["世間除我更誰窮，老去知心僅有公。", "玉局當年已無分，星沙今日更愁儂。", "饑烏繞樹啼寒月，獨鴈辭羣叫朔風。", "四斗官醪作供給，先生只此是遭逢。"]'),
('967eb2ee-9004-438a-9b4d-78d39214def8','送湖南盧提刑赴召三首  其三','項安世','宋','宋诗','song-poetry','','[]','先生休嘆不逢時，此地非公已再危。',64,'全唐诗/poet.song.147000.json','["先生休嘆不逢時，此地非公已再危。", "赤立一絲無藉手，青衿二百正張頤。", "千緡兄鏹仍三料，五頃夫田更八池。", "但得門東無叫怒，老身寒餓不須悲。"]'),
('2f118bfa-7bba-4f48-adc0-0503a937478f','送楊制機赴召','項安世','宋','宋诗','song-poetry','','[]','一年兩別故難堪，一世斯人况不凡。',64,'全唐诗/poet.song.147000.json','["一年兩別故難堪，一世斯人况不凡。", "髮共素心明耿耿，骨如脩節瘦蔪蔪。", "日開黄道天三接，夜榜清湘月半帆。", "各自青燈同曉夢，芒鞋踏遍武夷巖。"]'),
('b51555e3-abf5-486e-8fea-ba91c07cd0ac','訪東坡題高風堂屏間','項安世','宋','宋诗','song-poetry','','[]','樊口齊安一水間，少年行役鬢成班。',64,'全唐诗/poet.song.147000.json','["樊口齊安一水間，少年行役鬢成班。", "雲開甲子三秋雨，日射淮南一带山。", "戰血濃時雲夢遠，受恩深處老身閑。", "登臨莫唱綸巾曲，栖鶻危巢再可攀。"]'),
('c1602b7c-669b-432d-b676-139198b3dd13','再到東坡','項安世','宋','宋诗','song-poetry','','[]','江山不用借花輝，滿坂黄泥落葉稀。',64,'全唐诗/poet.song.147000.json','["江山不用借花輝，滿坂黄泥落葉稀。", "四海共知坡下路，昔人猶想夢中歸。", "小橋暗井千年話，秋菊寒泉一縷霏。", "恐被先生浮大白，尊前休說是和非。"]'),
('354a6c09-2617-468a-b8b5-9e17bb1c0515','又賦','項安世','宋','宋诗','song-poetry','','[]','屬玉風前藕葉香，殘蟬聲裏柳枝黄。',64,'全唐诗/poet.song.147000.json','["屬玉風前藕葉香，殘蟬聲裏柳枝黄。", "生前天遣耕雲土，身後人來問雪堂。", "樊口戰船旗似錦，黄坡突騎劍如霜。", "先生儻有歸來夢，更覺春江雨後忙。"]'),
('4998e987-fc4d-4519-96df-fbd0d05fabaa','白蓮','項安世','宋','宋诗','song-poetry','','[]','似雲如月畫圖難，似立如行意象寬。',64,'全唐诗/poet.song.147000.json','["似雲如月畫圖難，似立如行意象寬。", "太華峰頭天欲曉，魏王池上日初殘。", "超超韻出千花外，浩浩香來六月寒。", "正用一夔當大夏，可須浮艷滿春闌。"]'),
('d8352d83-27b4-4666-91f7-00b0766f843e','次韻賀葉運幹改官','項安世','宋','宋诗','song-poetry','','[]','伊人匪□即東如，於我誰何伴退居。',64,'全唐诗/poet.song.147000.json','["伊人匪□即東如，於我誰何伴退居。", "纔到九門催引見，速來平地學追胥。", "雷轟古縣栽穠李，水滿芳塘汎碧渠。", "戲把閑忙問同異，莞然微笑刃之餘。"]'),
('5cad7206-3aa5-45c8-8033-f996a10b1b2f','楊侍郎  其一','項安世','宋','宋诗','song-poetry','','[]','牙帳森森畫戟紅，心源澹澹玉壺空。',64,'全唐诗/poet.song.147000.json','["牙帳森森畫戟紅，心源澹澹玉壺空。", "身如峴首羊太傅，意似鹿門龐德翁。", "一貫精觕千慮到，兩忘真贋萬情融。", "觀公尚得今人愛，始覺東家道未窮。"]'),
('0de321f2-eb61-4b3d-ace1-90d4af0efac6','楊侍郎  其二','項安世','宋','宋诗','song-poetry','','[]','漕河水入漢江流，逆浪吹鄰上比州。',64,'全唐诗/poet.song.147000.json','["漕河水入漢江流，逆浪吹鄰上比州。", "爲送新篇歸峴首，亦知舊蔭滿沙頭。", "每思吾道長城在，常喜斯民命脈留。", "聖宋卜年周十倍，須公同住八千秋。"]'),
('11f1ffbb-ac52-47f0-ad10-312c78096f2c','得桃源丁知縣書','項安世','宋','宋诗','song-poetry','','[]','爲報桃川老令威，病夫三歲不開帷。',64,'全唐诗/poet.song.147000.json','["爲報桃川老令威，病夫三歲不開帷。", "窗中見日知晨暮，瓶裏看花記歲時。", "新讀子書多乙者，舊吟詩藁盡丁之。", "無人肯共閑人語，滿腹閑情獨自知。"]'),
('ccf3f18a-270a-4d20-a16e-36653a33e9b1','寄題吳氏社倉','項安世','宋','宋诗','song-poetry','','[]','淹劇無悰易愴神，社倉新記重關心。',64,'全唐诗/poet.song.147000.json','["淹劇無悰易愴神，社倉新記重關心。", "前朝詔在恩淪骨，遺老書存淚滿襟。", "永念君仁多善稼，肯因師死下喬林。", "皇天老眼明於鏡，勉植書樓萬桂陰。"]'),
('35aff5f3-1ca5-4b5f-b728-4c9152691db5','越昌謠','項安世','宋','宋诗','song-poetry','','[]','夜繫扁舟鸚鵡邊，洲邊人語更堪憐。',64,'全唐诗/poet.song.147000.json','["夜繫扁舟鸚鵡邊，洲邊人語更堪憐。", "烟煨影裏招魂魄，瓦礫堆中立市廛。", "明府到時惟赤地，吾儕今日見青天。", "子孫孫子恩難報，願太夫人壽八千。"]'),
('88e1df95-df7f-4e13-a656-de354def9e61','送范安撫喜雨詩','項安世','宋','宋诗','song-poetry','','[]','一寸甘腴一寸金，只今誰可旱天霖。',64,'全唐诗/poet.song.147000.json','["一寸甘腴一寸金，只今誰可旱天霖。", "贖鍰盡免疲民血，重役新寬戰士心。", "蛇掣電光開九闔，龍呼雲氣出重陰。", "書生不放饑腸歇，纔減憂勞便苦吟。"]'),
('c203a6be-d9cf-4506-9973-e38ddbb88df6','又和毛子和鄭薦玉','項安世','宋','宋诗','song-poetry','','[]','長腰如玉穩如金，千里西城待一霖。',64,'全唐诗/poet.song.147000.json','["長腰如玉穩如金，千里西城待一霖。", "憂國元戎真瀝血，還家倦客更關心。", "卧聽簷吹長疑滴，起看江雲只願陰。", "但得街頭官酒賤，速呼毛鄭與同吟。"]'),
('36fe35e9-8bd1-4da2-8bc9-f1f20181f4f9','重午飲趙園再和','項安世','宋','宋诗','song-poetry','','[]','香玉尊前剝嫩金，已逢佳節又逢霖。',64,'全唐诗/poet.song.147000.json','["香玉尊前剝嫩金，已逢佳節又逢霖。", "從教歲月催華髮，誰識乾坤有賞心。", "家在山林仍近市，手栽花木漸成陰。", "更開石井依桐葉，我欲時來作一吟。"]'),
('e85c1f66-1b54-4eab-b506-710fab4518f7','次韻盧漕木芙蓉二首  其一','項安世','宋','宋诗','song-poetry','','[]','風波久厭水中央，初日精神入檻光。',64,'全唐诗/poet.song.147000.json','["風波久厭水中央，初日精神入檻光。", "木末端來就詞客，牆頭應是誤行郎。", "高花大葉宜圖障，淺綠深紅照豆觴。", "壯觀秋容惟有此，霜邊倒盡雨邊荒。"]'),
('8d423e05-5bd3-4d22-a38b-b0529326aadd','次韻盧漕木芙蓉二首  其二','項安世','宋','宋诗','song-poetry','','[]','吹殘池面旆中央，幻出臺前艷粉光。',64,'全唐诗/poet.song.147000.json','["吹殘池面旆中央，幻出臺前艷粉光。", "衣典欲催愁杜老，鬢霜難拒笑潘郎。", "風來尚恐波生陸，暑退猶疑葉可觴。", "擬種陶朱三百樹，廣文茅屋未應荒。"]'),
('158d7f37-387a-4a3b-aa54-a5600abec409','次韻高秀才木芙蓉','項安世','宋','宋诗','song-poetry','','[]','流落秋江世未知，知心未有子西詩。',64,'全唐诗/poet.song.147000.json','["流落秋江世未知，知心未有子西詩。", "蘇韓句外新相識，孔孟門中許獨窺。", "不怨碧桃真義命，最宜青女好襟期。", "娉婷恥向東風嫁，羞殺邯鄲道上姬。"]'),
('8d0957f9-14c7-4c1f-ba32-7335889e101f','次李校書韻嘲閣下紅梅','項安世','宋','宋诗','song-poetry','','[]','託迹千花冀可曹，冰姿何敢露秋毫。',64,'全唐诗/poet.song.147000.json','["託迹千花冀可曹，冰姿何敢露秋毫。", "祗隨婢子希紅藥，肯信仙家有碧桃。", "照影日華烘玉頰，承恩衢勺醉香醪。", "自拋臈雪茆簷夢，應羨春風畫閣高。"]'),
('b20b49e9-0eae-41ff-9f4e-3acc36ea3a27','已賦四花復得紅因念閣下舊賞遂足五花之韻','項安世','宋','宋诗','song-poetry','','[]','吾衰不復夢蓬瀛，忽見紅梅眼暫驚。',64,'全唐诗/poet.song.147000.json','["吾衰不復夢蓬瀛，忽見紅梅眼暫驚。", "獨樹正當雲閣起，艷妝斜照石渠明。", "懶隨朔雪傳春信，長倚東風詫曉酲。", "歲晚江湖逢驛使，羞多無奈臉霞生。"]'),
('9f2c5f56-d8eb-45c6-a884-747537d5a455','食角黍懷江陵','項安世','宋','宋诗','song-poetry','','[]','經年不食三閭餌，一日相逢似故人。',64,'全唐诗/poet.song.147000.json','["經年不食三閭餌，一日相逢似故人。", "旋剝青菰香滿手，試餐黄顆軟粘脣。", "蔗漿下筯甘無敵，昌本浮盃小作巡。", "正是鄉人行樂處，畫旗鼉鼓隘江津。"]'),
('cce374da-6f6a-446b-9d28-5218901d6829','阻北風簡葉岳州','項安世','宋','宋诗','song-poetry','','[]','風顛下槍刺泥深，水長移船入港頻。',64,'全唐诗/poet.song.147000.json','["風顛下槍刺泥深，水長移船入港頻。", "帝子有情留客子，主人何幸得鄉人。", "星辰相緯周三衛，日月爲常漢九賓。", "公若賜環吾解纜，一般風色兩家春。"]'),
('e74328da-6f04-4760-9d91-e7367a86259c','再送黄醇甫四川制幹二首  其一','項安世','宋','宋诗','song-poetry','','[]','未冠聲名璧水流，已嗔袍笏壯齡收。',64,'全唐诗/poet.song.147000.json','["未冠聲名璧水流，已嗔袍笏壯齡收。", "更堪綠鬢勞烏綬，好去青天上碧油。", "百歲重親誰得似，十年三策未經酬。", "歸來展盡平生話，莫負東陽沈隠侯。"]'),
('08c788b8-dcb4-4aa3-83b4-300a6742ff0b','再送黄醇甫四川制幹二首  其二','項安世','宋','宋诗','song-poetry','','[]','柏氏諸龍我獨蛇，樂翁羣玉子無瑕。',64,'全唐诗/poet.song.147000.json','["柏氏諸龍我獨蛇，樂翁羣玉子無瑕。", "高曾未遠情終在，閩楚相望迹自賒。", "曉鏡雪侵蓮府綠，夜堂風入絳帷紗。", "天將廣厦包全蜀，李監門闌喜可涯。"]'),
('c8d4a011-2c05-44aa-ba83-92647a2918d7','次韻江陵王撫幹送行','項安世','宋','宋诗','song-poetry','','[]','江西回首白雲深，磊石山邊問水程。',64,'全唐诗/poet.song.147000.json','["江西回首白雲深，磊石山邊問水程。", "少日經行嗟老大，壯心零落笑平生。", "官曹無計逃寒冷，書冊惟堪記姓名。", "悔不早師王處士，藥爐琴軫自關情。"]'),
('11215ad7-274c-4b7b-93c3-f45eb57fa709','暑雨','項安世','宋','宋诗','song-poetry','','[]','屋下黄流可榜舟，屋頭青瓦更鳴溝。',64,'全唐诗/poet.song.147000.json','["屋下黄流可榜舟，屋頭青瓦更鳴溝。", "江吞平野魚龍樂，雨閉深林鳥雀愁。", "雲氣守閭圍溽暑，水風排闥薦凉秋。", "小窗一夢平生足，閑著漁蓑伴白鷗。"]'),
('ec4e61a7-c501-4fa1-92cc-7e0da0d72c3f','謝襄陽鄭帥送酒','項安世','宋','宋诗','song-poetry','','[]','有如雍府今方伯，無乃吾家古鄭君。',64,'全唐诗/poet.song.147000.json','["有如雍府今方伯，無乃吾家古鄭君。", "鼻祖向人元不負，耳孫於我尚能勤。", "三更月冷冰如水，五日風調麥似雲。", "更有閑心到閑客，漢江蒲綠兩相分。"]'),
('f5b1c5f7-ab82-47a7-a964-8cea26c4c90c','歸自寸金堤繞城南轉至望涉樓下柳陰扶路草色際天春意融怡不可名狀','項安世','宋','宋诗','song-poetry','','[]','十里河堤接郡城，城邊楊柳密於屏。',64,'全唐诗/poet.song.147000.json','["十里河堤接郡城，城邊楊柳密於屏。", "行人盡日翠陰裏，啼鳥數聲殘酒醒。", "七澤觀前無限草，高沙湖外一時青。", "斜陽極目春如海，只有平菴兩鬢星。"]'),
('86f909e0-a167-47bb-87fb-d9997e0e9f9e','江梅蠟梅同賦','項安世','宋','宋诗','song-poetry','','[]','淡白輕黄著絳跗，截肪蒸栗玉肌膚。',64,'全唐诗/poet.song.147000.json','["淡白輕黄著絳跗，截肪蒸栗玉肌膚。", "品題道骨誰高下，著莫清香似有無。", "野服黄冠離世士，縞裙瑶佩列仙儒。", "春風底處無紅紫，誰肯衝寒到玉湖。"]'),
('4fa8f838-d918-47fb-8773-ddfe707266ef','詠蠟梅','項安世','宋','宋诗','song-poetry','','[]','枯疎寒影變豐龐，的皪冰肌染沁黄。',64,'全唐诗/poet.song.147000.json','["枯疎寒影變豐龐，的皪冰肌染沁黄。", "難免世人梔蠟議，頼憑天骨蕙蘭香。", "情知不作和羹計，老去誰能弄粉妝。", "却笑南枝心未死，壽陽新額小紅裳。"]'),
('fe196e9e-2766-4161-ad6c-b202c0029f9b','次韻張參議送行','項安世','宋','宋诗','song-poetry','','[]','君王菲食繼唐虞，北望中原憶故墟。',64,'全唐诗/poet.song.147000.json','["君王菲食繼唐虞，北望中原憶故墟。", "嗟我懷人無憚遠，參卿軍事且煩渠。", "急須把酒澆天口，早與歸朝說地輿。", "湖水小儒無籍在，十年猶佩兔園書。"]'),
('17fccd3d-2550-46c8-9651-a364607b99bd','次韻陶節推問疾','項安世','宋','宋诗','song-poetry','','[]','酒病詩狂失已多，之人未棄肯來過。',64,'全唐诗/poet.song.147000.json','["酒病詩狂失已多，之人未棄肯來過。", "悔將蟲篆疲鎪刻，旋講熊經學按摩。", "容我力湔盧駱體，與君同赴閔顔科。", "瑶琴一曲春風裏，思遶龍門看洛河。"]'),
('f9774792-696f-4a33-a33c-2477d0759061','紹興孫察推席上','項安世','宋','宋诗','song-poetry','','[]','孫郎覓句有新聲，場屋當年更老成。',64,'全唐诗/poet.song.147000.json','["孫郎覓句有新聲，場屋當年更老成。", "曾草摩空殿前賦，却來晚飯越中行。", "僧廊罷雪窗猶曙，佛塔無風鐸自鳴。", "客到莫嫌花酒少，三從事與兩卿卿。"]'),
('aa67edc8-eb18-47f2-afa2-3f8fb5979a70','過陽羅洑','項安世','宋','宋诗','song-poetry','','[]','陽羅洑外黄陂路，灄口湖邊孝感河。',64,'全唐诗/poet.song.147000.json','["陽羅洑外黄陂路，灄口湖邊孝感河。", "鉦鼓已通南草市，腥羶欲涴大江波。", "家家戶外無驚犬，日日轅門有凱歌。", "端藉聖朝威德厚，亦煩諸將戰功多。"]'),
('30b036e1-4951-4eec-8701-1442a001bc4f','南湖遣興','項安世','宋','宋诗','song-poetry','','[]','朝回日日到南湖，不惜金錢散僕夫。',64,'全唐诗/poet.song.147000.json','["朝回日日到南湖，不惜金錢散僕夫。", "同舍盍簪如有約，吾廬高枕更何殊。", "年華過雨春都盡，草色連天路欲無。", "樂事只今惟有酒，速傾家釀倒金壺。"]'),
('d20ee99f-6b3d-49f9-882e-46a5a122f301','和鄧子及見賀韻','項安世','宋','宋诗','song-poetry','','[]','虛舟不記坎和流，槁木何心春共秋。',64,'全唐诗/poet.song.147000.json','["虛舟不記坎和流，槁木何心春共秋。", "幸自一生甘辟穀，更須萬戶苦封留。", "頗懲吾族騅千里，且學鄉人橘滿洲。", "平生惟良資共理，病夫何以副旁求。"]'),
('1fbb479a-3670-4093-869d-c9d8b320398f','賀周子問得子','項安世','宋','宋诗','song-poetry','','[]','旬時織女渡銀潢，付與天孫紫錦囊。',64,'全唐诗/poet.song.147000.json','["旬時織女渡銀潢，付與天孫紫錦囊。", "又向素娥圓滿後，懸知丹桂異時香。", "金魚玉带傳家舊，犀果銀錢照坐光。", "鶴髮含飴天下樂，百年重慶侍高堂。"]'),
('a42cd277-964e-44ae-b3be-35790f5b14d4','和劉子野見賀韻','項安世','宋','宋诗','song-poetry','','[]','汗青久別如山歷，頭白重分似斗城。',64,'全唐诗/poet.song.147000.json','["汗青久別如山歷，頭白重分似斗城。", "靜著易林師子貢，共評詩品得鍾嶸。", "忽驚蒙水新銜寵，恍憶巴山舊印榮。", "翠幕紅燈莫相問，風流何似十年情。"]'),
('f8e811ed-6df7-48e4-8dec-c1771ca497b2','和揭尉見賀韻','項安世','宋','宋诗','song-poetry','','[]','茸茸弱線初迎復，軋軋陽機已轉坤。',64,'全唐诗/poet.song.147000.json','["茸茸弱線初迎復，軋軋陽機已轉坤。", "梅放小紅明紙帳，竹分寒綠壽藤尊。", "不愁故將逢陵尉，且喜仙官近市門。", "還向陳年作新句，賀人今日拜春恩。"]'),
('90f927a5-7d6c-419d-a5e8-36bd793ef7f7','和彭世昌','項安世','宋','宋诗','song-poetry','','[]','有山有水勝吾閭，非舊非親借屋居。',64,'全唐诗/poet.song.147000.json','["有山有水勝吾閭，非舊非親借屋居。", "醉尉訶人何所恨，老彭於我未全疏。", "右車牙少愁看栗，左目眵多怕讀書。", "比似淵明更窮絕，併無門巷與舟車。"]'),
('59ac3ace-a58c-4dba-ae03-c57ccac2f798','曾宣幹謂余貌似誠齋楊公作此報之','項安世','宋','宋诗','song-poetry','','[]','客來喚我似誠齋，始晤行藏合打乖。',64,'全唐诗/poet.song.147000.json','["客來喚我似誠齋，始晤行藏合打乖。", "雖負江湖真格律，且贏土木僞形骸。", "生來仕宦無多日，老去徉狂只少諧。", "莫怪今朝歡喜極，被人題箇好先牌。"]'),
('b1751c51-71ad-4acb-9196-5d3f95df0f55','讀攖寧詩集效其體寄荆門趙守二首  其一','項安世','宋','宋诗','song-poetry','','[]','玉州政事荆州說，鄰叟讙呼病叟聞。',64,'全唐诗/poet.song.147000.json','["玉州政事荆州說，鄰叟讙呼病叟聞。", "轉地光風芽甲暖，照天寒鑒骨分毛。", "花村犬睡沈抱柝，秧地人歸勸耦耘。", "安得旌旗來北夢，放教恩澤到南雲。"]'),
('b2efccb6-b3d1-4a9c-be43-1e26f1b10caf','讀攖寧詩集效其體寄荆門趙守二首  其二','項安世','宋','宋诗','song-poetry','','[]','多謝君侯尊古德，新開詩集向春風。',64,'全唐诗/poet.song.147000.json','["多謝君侯尊古德，新開詩集向春風。", "隔生始見斯文貴，未死誰鄰此老窮。", "紙上歲時猶可數，句中恩怨已成空。", "若爲喚得攖寧起，看破浮雲合更工。"]'),
('41f6d208-202c-434b-b059-9b2073e42bbb','大雪同官皆不入獨坐道山簡南湖張直閣','項安世','宋','宋诗','song-poetry','','[]','久矣招渠不受催，忽然過我已佳哉。',64,'全唐诗/poet.song.147000.json','["久矣招渠不受催，忽然過我已佳哉。", "更於羣玉峯巒裏，揀得孤吟時節來。", "入竹葉間添茗供，點梅梢上獻詩材。", "箇般清絕今誰有，未必南湖此日開。"]'),
('4a1c1998-8a03-4dcf-a01b-e6a8f7b5718b','和人謝送筆','項安世','宋','宋诗','song-poetry','','[]','詞源浩浩筆渠渠，合珥華簪從屬車。',64,'全唐诗/poet.song.147000.json','["詞源浩浩筆渠渠，合珥華簪從屬車。", "洗眼看題揮月字，驚心猶似仰空書。", "雲林舊截雙鳴管，霜野新蒐八竅居。", "遣送文房慚瘦劣，千軍揮掃正椽如。"]'),
('a2f7f8b8-2ebf-42cc-84fb-3b0da150faa6','偶題','項安世','宋','宋诗','song-poetry','','[]','暗水斜穿橘塢凉，回波直下藕塘香。',64,'全唐诗/poet.song.147000.json','["暗水斜穿橘塢凉，回波直下藕塘香。", "似牙如背白羊岸，已疊又灣青草傍。", "閘裏放船思槜李，石間行酒認天章。", "一時喚起平生夢，江北江南道路長。"]'),
('a2b69215-4ad8-495a-ba88-41ca56e94a69','讀三國志','項安世','宋','宋诗','song-poetry','','[]','曹劉有志混華戎，無奈吳兒兩炬紅。',64,'全唐诗/poet.song.147000.json','["曹劉有志混華戎，無奈吳兒兩炬紅。", "赤壁焰燒雲夢澤，夷陵光照永安宮。", "人間自此鼎三足，天上無由日再中。", "惟有葛公心未死，夜深寒月照孤忠。"]'),
('20b9919b-9db8-4589-b403-93a62a22501e','李校書輪對乞於故相家取上皇退位御筆上喜曰此萬萬年表照也','項安世','宋','宋诗','song-poetry','','[]','校書對罷天顔喜，再拜龍墀出殿來。',64,'全唐诗/poet.song.147000.json','["校書對罷天顔喜，再拜龍墀出殿來。", "勑使傳宣新宰相，驛書馳問舊元台。", "上皇慈筆歸中祕，學士忠名遍九垓。", "榻畔祥風翻諫紙，朝衣收得異香回。"]'),
('75c0c9d3-6fc2-44fb-986c-11b9c996dfba','少保席間道襄州朋舊','項安世','宋','宋诗','song-poetry','','[]','持盃相向各言衰，憶得襄州未老時。',64,'全唐诗/poet.song.147000.json','["持盃相向各言衰，憶得襄州未老時。", "曉踏青山尋秀句，夜簪紅藥聽新詞。", "只言坐上皆豪逸，誰信人間有別離。", "頭白歸來堪自賀，獨依雄楚看題詩。"]'),
('e1d16695-e958-432d-9707-925e911a830c','酴醾牡丹同賦','項安世','宋','宋诗','song-poetry','','[]','小園疎雨挾東風，敗萼殘英一夜空。',64,'全唐诗/poet.song.147000.json','["小園疎雨挾東風，敗萼殘英一夜空。", "世上已無桃與李，箇中方是白和紅。", "綵霞承露嬌如滴，玉雪生香暖不融。", "可使低徊萬花裏，剪裁多少費春工。"]'),
('a2eb1403-6904-4961-9425-334a61cfc2c5','陳宣幹至晐','項安世','宋','宋诗','song-poetry','','[]','十年無事書生病，一日談兵志士忙。',64,'全唐诗/poet.song.147000.json','["十年無事書生病，一日談兵志士忙。", "虜退便收前印綬，秋來仍著戰衣裳。", "天寒白兆腥風起，月黑黄陂燐火光。", "試問蘄州陳大著，幾多流血浸沙場。"]'),
('e69196d3-81a3-46a7-a4c3-6ddcdc3b27e2','次韻曾宣幹','項安世','宋','宋诗','song-poetry','','[]','無鉢無簞曉自齋，一銎一衲晚逾乖。',64,'全唐诗/poet.song.147000.json','["無鉢無簞曉自齋，一銎一衲晚逾乖。", "戰場實事膏兼血，廣坐虛談冢共骸。", "虜事方然人尚爾，世途何者我猶諧。", "道林自有山花鳥，收起棚前傀儡牌。"]'),
('e135640e-5970-4274-a978-5d12a1517105','上泉','項安世','宋','宋诗','song-poetry','','[]','陰崖古木掛藤蘿，下有神龍閲世多。',64,'全唐诗/poet.song.147000.json','["陰崖古木掛藤蘿，下有神龍閲世多。", "荇带水衣閑自舞，鯈魚石蟹戲相過。", "豈知霖雨爲何事，自喜紅塵不到他。", "落葉滿林迷去路，牧童相引到山阿。"]'),
('71362f10-0c95-400d-8e1a-bd5172ec0944','和陳信民除夕','項安世','宋','宋诗','song-poetry','','[]','已知時節到門闌，猶有私情惜舊殘。',64,'全唐诗/poet.song.147000.json','["已知時節到門闌，猶有私情惜舊殘。", "千戶神桃俄已換，一聲鬼竹豈其難。", "癡人星髮愁春鏡，稚子花襦簇曉盤。", "歲歲年年祇此是，且隨流俗賀更端。"]'),
('0e28a1bf-5636-4487-8bf3-71dc91e0d40a','送張司戶','項安世','宋','宋诗','song-poetry','','[]','誰道盧門病客多，先生有藥起沈疴。',64,'全唐诗/poet.song.147000.json','["誰道盧門病客多，先生有藥起沈疴。", "儒家自昔無追拒，賤子經年頼琢磨。", "點鐵成金聊爾耳，絕塵瞠後擬如何。", "他時若謁安昌第，只願論文不願他。"]'),
('16c98bd2-b521-4af3-8fcf-0093aaa51529','八日泊故人亭觀二水合流處','項安世','宋','宋诗','song-poetry','','[]','各自南來共北流，孤亭直下對中洲。',64,'全唐诗/poet.song.147000.json','["各自南來共北流，孤亭直下對中洲。", "湘流幾日發陽朔，瀟水伴吾離永州。", "預戒篙工泊江口，急穿巾子上山頭。", "哦詩未了寒催客，却下篷窗喚解舟。"]'),
('4d8b3a22-af00-437e-afa5-06dcf4fc9502','和鄧子及冬至謝送筆墨韻','項安世','宋','宋诗','song-poetry','','[]','年華添線又浮灰，忽忽窮愁不易裁。',64,'全唐诗/poet.song.147000.json','["年華添線又浮灰，忽忽窮愁不易裁。", "惟有病人知客意，故衝寒雪送詩材。", "昔誇三窟今成縛，少倚千尋老作煤。", "妙用反從窮裏得，一陽端自剝中來。"]'),
('bfd2413d-d445-4163-9fc2-78c766bc3d8a','題谷湖詩','項安世','宋','宋诗','song-poetry','','[]','少年塞上傳書檄，晚歲湖邊結薜蘿。',64,'全唐诗/poet.song.147000.json','["少年塞上傳書檄，晚歲湖邊結薜蘿。", "猶有詩編傳舊夢，更無心事向驚波。", "人生難料君重出，戍務方殷意若何。", "鬢髮浪蒼肝膽在，鐵山涇水待鐃歌。"]'),
('5fb5e5a5-7d1b-45ff-9ea5-0dc940bf6ec1','七夕謝孟漕品味','項安世','宋','宋诗','song-poetry','','[]','金井琅玕戒女功，木桃瓜李奏民風。',64,'全唐诗/poet.song.147000.json','["金井琅玕戒女功，木桃瓜李奏民風。", "天河夜酌尊罍滿，帝子秋盤餠餌豐。", "戢戢玉蓮參藕艇，忻忻火棗會梨宮。", "星軺著意來看客，不與尋常乞巧同。"]'),
('ae88400e-29f7-41a1-843e-11dce3f2a4b6','江梅','項安世','宋','宋诗','song-poetry','','[]','千林憔悴獨含春，笑倚黄昏未識顰。',64,'全唐诗/poet.song.147000.json','["千林憔悴獨含春，笑倚黄昏未識顰。", "紅小粉疎烟冪冪，影低香遠水粼粼。", "從教雪路寧愁冷，遮莫茆簷可怕貧。", "欲問橫枝緣底瘦，似無如有最禁人。"]'),
('b9248877-2aeb-4d25-8234-274a76a18984','午日','項安世','宋','宋诗','song-poetry','','[]','一杯聊解獨醒譁，老眼猶明纏臂花。',64,'全唐诗/poet.song.147000.json','["一杯聊解獨醒譁，老眼猶明纏臂花。", "煮角沈筒隨地俗，賜衣題墨又天涯。", "千年菖本須眉古，九蘂戎葵節纛華。", "景物向人何所欠，明時不用賦懷沙。"]'),
('05db0b21-08d2-4ff3-9651-4c10456e04c3','鄭子仁生日用其去臈見壽韻  其一','項安世','宋','宋诗','song-poetry','','[]','寶璋華芾慶祥羆，又是當年應夢時。',64,'全唐诗/poet.song.147000.json','["寶璋華芾慶祥羆，又是當年應夢時。", "煜煜金芝生五岳，煌煌珠樹出三危。", "賦成鸚鵡凌雲筆，詩到𩢱魚在野思。", "時論同歸家最近，新秋騰上未爲遲。"]'),
('68a84f1b-1f6e-4fe6-a527-1eb7533bdf33','鄭子仁生日用其去臈見壽韻  其二','項安世','宋','宋诗','song-poetry','','[]','月日巧當真四六，風流合是妙詞章。',64,'全唐诗/poet.song.147000.json','["月日巧當真四六，風流合是妙詞章。", "金華洞府神仙骨，麗澤書堂翰墨香。", "隴麥秋時椿自好，林鶑老去鶴偏長。", "綠槐宮闕薰風裏，看引諸儒對殿廊。"]'),
('5272f833-366d-4b84-82bc-b62cfa36980a','任安道生日  其一','項安世','宋','宋诗','song-poetry','','[]','桐川酒正夏王孫，四百遐齡舊德存。',64,'全唐诗/poet.song.147000.json','["桐川酒正夏王孫，四百遐齡舊德存。", "解與狄儀傳釀法，不妨吾祖自昌言。", "三分歷草初除一，百萬春花欲化渾。", "奪得年頭作生日，盡收芳氣入芳罇。"]'),
('a9695413-42af-4038-a8f2-e434449de42d','任安道生日  其二','項安世','宋','宋诗','song-poetry','','[]','豪風橫雨洗新春，掣電驚雷起蟄鱗。',64,'全唐诗/poet.song.147000.json','["豪風橫雨洗新春，掣電驚雷起蟄鱗。", "七百里開雲土潤，八千年慶大椿辰。", "太牢醇酎春臺上，金馬公車要路親。", "凜凜河圖門戶在，穩將才業嗣前人。"]'),
('4427cb86-8c0b-451c-854c-6a0f06af9b56','任安道生日  其三','項安世','宋','宋诗','song-poetry','','[]','九分纔是一分春，從此看春更七旬。',64,'全唐诗/poet.song.147000.json','["九分纔是一分春，從此看春更七旬。", "行世功名初發脚，出門富貴即隨身。", "棋逢要路方高著，馬得亨衢定軼塵。", "伏櫪自憐吾久矣，傍觀甘作爛柯人。"]'),
('5d47f107-706b-43d8-ad19-578f16652e59','任詠道生日','項安世','宋','宋诗','song-poetry','','["\u534e\u5c71"]','月當天上連山易，日占人間閏路棋。',64,'全唐诗/poet.song.147000.json','["月當天上連山易，日占人間閏路棋。", "華嶽金精供爽氣，廣寒銀闕獻高枝。", "鰥魚渴鳳塵緣凈，壽鶴靈龜內景遲。", "好把文章收富貴，却將功行享耆頤。"]'),
('608f70a4-8bcf-4875-b8d2-2c1d60ffc9df','劉武子生日','項安世','宋','宋诗','song-poetry','','[]','封姨吹墮小烏巾，日御橫飛十二辰。',64,'全唐诗/poet.song.147000.json','["封姨吹墮小烏巾，日御橫飛十二辰。", "漢代皇孫中校尉，唐家供奉謫仙人。", "六宮舊唱香奩嫵，諸老爭偷錦段新。", "大小山中千樹桂，壽君千歲轉詩論。"]'),
('adce355f-7706-4cba-a5a1-63598d16000c','葉顯甫生日','項安世','宋','宋诗','song-poetry','','[]','客裏今年慶事新，星香三日兩生辰。',64,'全唐诗/poet.song.147000.json','["客裏今年慶事新，星香三日兩生辰。", "已歌西母如椿壽，又贊東床似玉人。", "卯觀妙傳仙祖訣，霞觴同汎我家春。", "年年紅紫芳菲月，不負功名富貴身。"]'),
('6ecd190d-5bd2-47b3-9eb2-0be119ccc3eb','樂景夔生日','項安世','宋','宋诗','song-poetry','','[]','四十九年蘧伯玉，又從湘水向洮河。',64,'全唐诗/poet.song.147000.json','["四十九年蘧伯玉，又從湘水向洮河。", "還家趁及垂弧燕，闔郡喧傳衣錦過。", "風月平分秋恰半，親朋來祝壽如何。", "亮功人是長生日，預卜他年事業多。"]'),
('e1214681-7bb4-407d-b376-866e85e1d635','叔父生日  其一','項安世','宋','宋诗','song-poetry','','[]','新年一百二十日，此酒年年須共斟。',64,'全唐诗/poet.song.147000.json','["新年一百二十日，此酒年年須共斟。", "竹嶺松溪仙派遠，龍山夢澤壽鄉深。", "戎葵百段纏頭錦，盧橘千丸買酒金。", "造物商量供酒費，怕教一事惱閑心。"]'),
('1293db33-d997-419e-9915-3472c4c83ef9','叔父生日  其二','項安世','宋','宋诗','song-poetry','','[]','黄塵赤日萬家團，中有金莖露一盤。',64,'全唐诗/poet.song.147000.json','["黄塵赤日萬家團，中有金莖露一盤。", "酒氣薰天心獨醒，市聲摇屋鼻方鼾。", "長生只用仁爲藥，至樂惟將靜作歡。", "嘉慶堂前齊指處，鬢毛如雪臉如丹。"]'),
('2f6d2259-1ede-46ba-bcb6-1993e3350300','叔父生日  其三','項安世','宋','宋诗','song-poetry','','[]','一年生日最佳時，三老團欒總秀眉。',64,'全唐诗/poet.song.147000.json','["一年生日最佳時，三老團欒總秀眉。", "北榭空明新眼界，東床消息稱心期。", "竹林風景長宜酒，椒頌年華剩索詩。", "試拂兩弦聽細摘，曲中元是閟宮詞。"]'),
('6345e4c6-2646-4453-a0d9-78697a0b09a0','叔父生日  其四','項安世','宋','宋诗','song-poetry','','[]','蓂花禿盡大椿生，月色昏時壽宿明。',64,'全唐诗/poet.song.147000.json','["蓂花禿盡大椿生，月色昏時壽宿明。", "眼見扶疎都變密，氣鍾和淑更能清。", "弟兄相對談前事，門戶如今儘慰情。", "除却偷閑無善頌，暮年多暇即爲榮。"]'),
('aea62af5-53de-475d-b403-7da2481035a0','大人生日  其一','項安世','宋','宋诗','song-poetry','','[]','明日君開祝壽場，今朝臣捧壽親觴。',64,'全唐诗/poet.song.147000.json','["明日君開祝壽場，今朝臣捧壽親觴。", "願親有俾昌而大，與國無窮祿爾康。", "臺上菊遲今始綻，堂前桂晚後彌芳。", "仙翁作計深長在，待看孫曾笏滿床。"]'),
('ab5d01f2-697b-48df-b920-911f1dedd752','大人生日  其二','項安世','宋','宋诗','song-poetry','','[]','欲繫銀章望日邊，先裁綵服拜親前。',64,'全唐诗/poet.song.147000.json','["欲繫銀章望日邊，先裁綵服拜親前。", "自家及國歡情一，以順移忠喜事連。", "兔管鸞牋松字日，金風玉露菊花天。", "十分領取無窮壽，否極如今合泰然。"]'),
('76fba134-45ed-4ec1-af69-b89c0986cae4','承甫兄生日用去臘見惠之韻','項安世','宋','宋诗','song-poetry','','[]','留住東風一莢蓂，伴他南極老人星。',64,'全唐诗/poet.song.147000.json','["留住東風一莢蓂，伴他南極老人星。", "暫棲鸞鳳官無小，晚插貂蟬夢自靈。", "五十買臣多富貴，八千莊叟定年齡。", "腰間六印都如斗，依舊雙髦帖鬢青。"]'),
('a861d7bb-2b37-4577-a4f3-a2a7d0a78b26','又代作  其一','項安世','宋','宋诗','song-poetry','','[]','風收十四葉堯蓂，雲捧三千歲壽星。',64,'全唐诗/poet.song.147000.json','["風收十四葉堯蓂，雲捧三千歲壽星。", "人訝綉鸞淹彩翼，天教紋鶒效殊靈。", "中書將相無窮考，上古春秋不計齡。", "長見燭花香帕畔，小桃紅嫩柳新青。"]'),
('69db76e7-b831-490a-8b3e-01e1820bca6b','又代作  其二','項安世','宋','宋诗','song-poetry','','[]','羲仲量沙數砌蓂，甘公聚米算周星。',64,'全唐诗/poet.song.147000.json','["羲仲量沙數砌蓂，甘公聚米算周星。", "無邊海福兼山壽，不盡天英與地靈。", "翰苑文章看李白，巖廊風度待張齡。", "春風萬里岷江水，吹作香醪盡意青。"]'),
('42c6bbd6-7a8c-4408-b0c5-c6af3d8d6bb6','十五弟生日','項安世','宋','宋诗','song-poetry','','[]','合宮雷雨下江城，重把賢書舊貢升。',64,'全唐诗/poet.song.147000.json','["合宮雷雨下江城，重把賢書舊貢升。", "入月穿天搜伏兔，摶風擊水化新鵬。", "當年吉夢渾家喜，今日成名望汝能。", "千歲靈龜須自養，朵頤無用酒如澠。"]'),
('b2fb32be-1f6e-4dd4-aadb-8c7470f03ac3','十六弟生日  其一','項安世','宋','宋诗','song-poetry','','[]','長庚飛下祝融墟，瑞入清臺夏五書。',64,'全唐诗/poet.song.147000.json','["長庚飛下祝融墟，瑞入清臺夏五書。", "八莢花開羲叔歷，一枝桂長羿妃居。", "南薰解養秋風鶚，夢澤能生北海魚。", "看上扶摇龍尾道，曼聲傳唱繞周廬。"]'),
('346bf35a-8645-4cb0-a94d-7a0bae543954','十六弟生日  其二','項安世','宋','宋诗','song-poetry','','[]','一弦光上五雲端，恰共乘弧勢一般。',64,'全唐诗/poet.song.147000.json','["一弦光上五雲端，恰共乘弧勢一般。", "疇昔熊羆和夢到，只今鵰鶚待秋摶。", "紅榴色借丹枝重，碧藕香摇翠袖寒。", "堂上雙親雖白髮，情懷偏向試闈懽。"]'),
('9a3b7ab0-ab00-42b0-bd3e-ab3c9fe54df9','十六弟生日  其三','項安世','宋','宋诗','song-poetry','','[]','艾花開過天中節，桂樹飛來月上弦。',64,'全唐诗/poet.song.147000.json','["艾花開過天中節，桂樹飛來月上弦。", "喚起西堂春草思，吟成小雅杖華篇。", "庭闈心事關兒子，場屋聲名有歲年。", "好把文章收富貴，却將功行作神仙。"]'),
('37712545-2233-4dbb-8a02-e40d7dafe747','代作五首  其一','項安世','宋','宋诗','song-poetry','','[]','晝漏如今天共永，壽辰於此數難量。',64,'全唐诗/poet.song.147000.json','["晝漏如今天共永，壽辰於此數難量。", "三千花實桃猶小，五日春秋木未長。", "羲宅巧占堯火正，娥宮新學羿弦張。", "兩輪朝暮無窮照，可怕金烏玉兔忙。"]'),
('ad4d5eec-1cee-4656-bff5-bd4b216dd508','代作五首  其二','項安世','宋','宋诗','song-poetry','','[]','一點陰機初晝遲，十分陽德正開離。',64,'全唐诗/poet.song.147000.json','["一點陰機初晝遲，十分陽德正開離。", "后王誥命章施日，天地文明盛麗時。", "歷草自生蕭相葉，桂花須占郄詵枝。", "千鍾頓止真堪畏，萬石他年更不疑。"]'),
('f384306b-9589-4974-9620-af4359d0a95f','代作五首  其三','項安世','宋','宋诗','song-poetry','','[]','蒼龍元住五雲東，此日黄昏却正中。',64,'全唐诗/poet.song.147000.json','["蒼龍元住五雲東，此日黄昏却正中。", "琴瑟銅壺添水箭，翩翻珠戶記桑蓬。", "上弦月色如銀白，南極星光似燭紅。", "歲歲年年尊酒畔，小荷香霧綠槐風。"]'),
('2f631020-2e13-480b-8b48-e13070c7fbca','代作五首  其四','項安世','宋','宋诗','song-poetry','','[]','流霞元是吾家飲，生日曾供老杜詩。',64,'全唐诗/poet.song.147000.json','["流霞元是吾家飲，生日曾供老杜詩。", "色借榴心芳露重，香分荷氣碧泉滋。", "重闈永夜宜開酌，六禮今年看結褵。", "可但椿長并桂永，靈妃蕭史壽無期。"]'),
('3a506fd0-e383-4529-80a6-e59b42931cb7','代作五首  其五','項安世','宋','宋诗','song-poetry','','[]','孟嘗當戶三千客，鎮惡成名百二關。',64,'全唐诗/poet.song.147000.json','["孟嘗當戶三千客，鎮惡成名百二關。", "天以高名鍾是月，人於季孟得其間。", "八風巡日開雲莢，半壁騰空映霧寰。", "共祝星郎千歲喜，天孫早晚渡銀灣。"]'),
('9a914fd7-be9b-448f-8c50-cfe3c4a7b7cd','十七弟生日用其韻','項安世','宋','宋诗','song-poetry','','[]','壽星合在角亢旁，爲爾來臨翼軫鄉。',64,'全唐诗/poet.song.147000.json','["壽星合在角亢旁，爲爾來臨翼軫鄉。", "日向綉床添永算，雲縱書觀發嘉祥。", "修程九萬開榮路，曲禮三千閲壽觴。", "冬弟春兄同此日，天教鴻雁自成行。"]'),
('1d354a66-e999-4b64-ad99-80ecc30d04aa','十九弟生日  其一','項安世','宋','宋诗','song-poetry','','[]','西堂舊作春池夢，南國今逢小滿天。',64,'全唐诗/poet.song.147000.json','["西堂舊作春池夢，南國今逢小滿天。", "重四巧排黄閣印，百分宜泛紫金船。", "夜聞素月初生桂，曉看丹枝已屬賢。", "萬種春紅都歛避，一庭槐日翠陰圓。"]'),
('865105be-e07c-4685-bfe7-944b378488cf','十九弟生日  其二','項安世','宋','宋诗','song-poetry','','[]','繭絲成綍夏初新，柳色如袍尚带春。',64,'全唐诗/poet.song.147000.json','["繭絲成綍夏初新，柳色如袍尚带春。", "已見出牆添笋稚，即看調鼎長梅人。", "書隨雁序升秋漢，研拂龍旗對晚宸。", "勉爲家門成勝事，六枝仙桂一株椿。"]'),
('111522c3-2e45-4751-ac44-d0aae20bf91c','三弟校尉生日用去臘見壽韻','項安世','宋','宋诗','song-poetry','','[]','八千堯歷畀秋春，萬里嵩高下甫申。',64,'全唐诗/poet.song.147000.json','["八千堯歷畀秋春，萬里嵩高下甫申。", "兒女只今多似櫛，弟兄他日老於親。", "共誇戲綵隨鳩杖，不羨橫撾倚鳳宸。", "看取天台遊觀主，前銜虛作漢朝臣。"]'),
('e5edea8a-cc4b-4f20-a20a-aa49661cb708','敬甫生日','項安世','宋','宋诗','song-poetry','','[]','蘋尾生薰梅作霖，葵心粲笑草明金。',64,'全唐诗/poet.song.147000.json','["蘋尾生薰梅作霖，葵心粲笑草明金。", "杓星指處老人現，弦月升時歡伯臨。", "王母西池逢藥喜，天孫斜漢有嘉音。", "宮槐又報黄消息，早擢丹枝媚綵襟。"]'),
('d397dc39-3b2f-423a-ba62-ae9ae2be0dc4','任□□生日','項安世','宋','宋诗','song-poetry','','[]','盤堆鬰薁粲豳風，鍾汎函林拂嶰筒。',64,'全唐诗/poet.song.147000.json','["盤堆鬰薁粲豳風，鍾汎函林拂嶰筒。", "一朵杖華千里到，六雙蓂莢五雲中。", "初庚恰向今晨足，鼎甲懸知後日崇。", "新息陂頭多赤雁，看排行序上層空。"]'),
('38b23f59-6c37-4c7d-b497-9092c392619e','任司戶生日','項安世','宋','宋诗','song-poetry','','[]','曉殿蓂花一莢飛，晚簷桂樹小些兒。',64,'全唐诗/poet.song.147000.json','["曉殿蓂花一莢飛，晚簷桂樹小些兒。", "人間已過重陽後，天上將開瑞慶時。", "新息陂長鍾世德，嘉陵灘淺報官期。", "待君飲却長生酒，又到江亭賀上卮。"]'),
('5d56687a-a250-45d0-a0eb-59a5d6926669','任以道總幹生日轆轤體','項安世','宋','宋诗','song-poetry','','[]','身長如玉臉如童，抱朴存真道氣沖。',64,'全唐诗/poet.song.147000.json','["身長如玉臉如童，抱朴存真道氣沖。", "隴上木牛新拄頰，篋中芸蠹舊蟠胸。", "周正已報初陽匝，商歷方開遠算洪。", "不競紅塵桃李月，雪中松檜自舂容。"]'),
('dedeb20d-2f40-4844-bb89-45ed5b3be838','四伯父生日  其一','項安世','宋','宋诗','song-poetry','','[]','春入芳蘭喜氣濃，天風吹下慶重重。',64,'全唐诗/poet.song.147000.json','["春入芳蘭喜氣濃，天風吹下慶重重。", "大兒穩護梁州罽，小女登高監宅龍。", "南畝新年付熊驥，北窗長日慕喬松。", "阿咸多病宜偕隠，自洗山罍勸嗣宗。"]'),
('3727c83e-8912-49ba-9254-dcd3545e931c','四伯父生日  其二','項安世','宋','宋诗','song-poetry','','[]','三月三日天氣新，蘭亭飲散鷄呼晨。',64,'全唐诗/poet.song.147000.json','["三月三日天氣新，蘭亭飲散鷄呼晨。", "酴醾影裏看月姊，翼軫星中占老人。", "千二百歲廣成壽，六十四日東皇春。", "請誦古人詩一句，五枝芳桂一枝椿。"]'),
('1c244ec1-1dbc-4747-8cee-4972a7bd74fd','代宜孫','項安世','宋','宋诗','song-poetry','','[]','潭潭厦屋照春天，初作生申第一筵。',64,'全唐诗/poet.song.147000.json','["潭潭厦屋照春天，初作生申第一筵。", "清暢惠和三月四，熾昌耆艾萬年千。", "竇郎植桂枝枝茂，荀里生龍箇箇賢。", "汲井餐葵同此潤，捧觴來賦從孫篇。"]'),
('ecae6094-2c19-4b23-a7be-9071f7f84745','吳給事挽詞  其一','項安世','宋','宋诗','song-poetry','','[]','我來鏡水問遺民，想見堂堂報國身。',64,'全唐诗/poet.song.147000.json','["我來鏡水問遺民，想見堂堂報國身。", "五月陂塘三百里，千年廟學一番新。", "世傳風烈今無數，自許經行得最親。", "一讀金陵補天議，始知高處更驚人。"]'),
('04a820e0-017c-49d2-99d9-c0bd4913bce1','吳給事挽詞  其二','項安世','宋','宋诗','song-poetry','','[]','少年胸次已吞秦，暮日肝腸獨許陳。',64,'全唐诗/poet.song.147000.json','["少年胸次已吞秦，暮日肝腸獨許陳。", "正笏于今無此傑，垂車在昔有先民。", "傷心歲晚逢諸老，屈指才難更幾人。", "壽樂哀榮公不恨，年來於此自酸辛。"]'),
('f1f66c1e-da99-4699-ab3f-c18de3e58368','寒食哭承甫兄墓','項安世','宋','宋诗','song-poetry','','[]','半世驅馳未白頭，無窮心事等閑休。',64,'全唐诗/poet.song.147000.json','["半世驅馳未白頭，無窮心事等閑休。", "生前可是門闌盛，身後寧知禍患稠。", "雄鳳已將凰共隠，靈椿仍與桂同秋。", "茫茫三海連東漕，不盡重雲片雁愁。"]'),
('3a19e4ab-8d3c-45e5-aaa5-28240b52fa49','用韻哭葉運幹','項安世','宋','宋诗','song-poetry','','[]','蘭薰玉膩掌中雛，霅凈苕深鏡裏居。',64,'全唐诗/poet.song.147000.json','["蘭薰玉膩掌中雛，霅凈苕深鏡裏居。", "忍向芳洲愛鸚鵡，便隨清夢化扶胥。", "病多正要人扶杖，年少翻令我哭渠。", "江漢西風吹老眼，一襟寒淚苦無餘。"]'),
('5ef586c7-18d1-4fd6-83f6-2dec5951fde4','荆□范侍郎挽詞三首  其一','項安世','宋','宋诗','song-poetry','','[]','布韋得路如公幾，少壯登朝至老衰。',64,'全唐诗/poet.song.147000.json','["布韋得路如公幾，少壯登朝至老衰。", "東觀西雍盈記石，南宮北省徧絇絲。", "童童戟纛開淮楚，奕奕圖書冠馬龜。", "回首人間心事足，去尋天上玉樓期。"]'),
('2bf1976b-660a-4195-a19e-d9ce6bf0fada','荆□范侍郎挽詞三首  其二','項安世','宋','宋诗','song-poetry','','[]','功畏人知不遣聞，雙雙榮國孝曾孫。',64,'全唐诗/poet.song.147000.json','["功畏人知不遣聞，雙雙榮國孝曾孫。", "果州汲綆無遺力，荆府調胹有德言。", "此日美人俱厭代，何時病士得開門。", "西風一掬涪翁淚，滴向公家兩鬰尊。"]'),
('065ba876-75b1-414d-a266-2bc194678cca','荆□范侍郎挽詞三首  其三','項安世','宋','宋诗','song-poetry','','[]','歲戊戌秋傾魯蓋，公楊勳甫共吳船。',64,'全唐诗/poet.song.147000.json','["歲戊戌秋傾魯蓋，公楊勳甫共吳船。", "攀蘿自此門闌密，寓茇經年里閈連。", "二十六番新火變，四千石帥舊情堅。", "萬間忽作堂堂壞，杜屋無茅始可憐。"]'),
('b3f47891-c004-4122-aa81-1a3f5502e1be','挽程尚書詞','項安世','宋','宋诗','song-poetry','','[]','人間一日履聲藏，天上文昌落正芒。',64,'全唐诗/poet.song.147000.json','["人間一日履聲藏，天上文昌落正芒。", "直諒無朋今魏汲，師承有法古韋康。", "思陵冊府嚴招聘，孝廟經帷盛表章。", "歲晚山林誰得似，十年高卧樂羲皇。"]'),
('3d1e9635-1638-4b2e-9062-1396214d46ad','程樞密父待制挽詞二首  其一','項安世','宋','宋诗','song-poetry','','[]','憶送雙旌帝北門，豈知此別是終身。',64,'全唐诗/poet.song.147000.json','["憶送雙旌帝北門，豈知此別是終身。", "項亭詩到鮮於錦，羊峴書來暖似春。", "只有死當封晉魏，不令生得定燕秦。", "世間榮事翻成屈，獨抱功名向古人。"]'),
('3aead9c3-6e4c-4860-ba91-4d00c14a5624','程樞密父待制挽詞二首  其二','項安世','宋','宋诗','song-poetry','','[]','阜陵按射殿南闈，同執彫弓侍赭衣。',64,'全唐诗/poet.song.147000.json','["阜陵按射殿南闈，同執彫弓侍赭衣。", "病我已逢明主賜，失公彌覺舊人稀。", "旌旗北伐心徒在，香火西清夢已非。", "不只隻鷄無路去，亦知身世漸同歸。"]'),
('64d45214-c845-46dc-b773-adc47f70ddac','七日呂城守閘','項安世','宋','宋诗','song-poetry','','[]','官閘嶒𡵓晝閉塗，商舡嘈囐夜銜艫。',64,'全唐诗/poet.song.147000.json','["官閘嶒𡵓晝閉塗，商舡嘈囐夜銜艫。", "卧聽篙子灣灣月，坐待州家急急符。", "石罅漏泉鳴錦瑟，篷窗篩雨落玭珠。", "夢魂不受重門隔，自著斑衣過練湖。"]'),
('6bb2b22c-06c3-45d6-a855-b06b77ca42ce','二十四日省宿次楊文公集賢宿直韻兼擬其體','項安世','宋','宋诗','song-poetry','','[]','雲氣陰陰繞殿廬，雨聲摵摵響階除。',160,'全唐诗/poet.song.147000.json','["雲氣陰陰繞殿廬，雨聲摵摵響階除。", "薰爐翠被延周蝶，黄墨朱缸訂魯魚。", "野性登朝常蹙踖，親年須祿向躊躇。", "叨陪大典論疑信，濫等諸儒課密疏。", "漢殿修文開白虎，海邦張樂享爰居。", "綺寮蕙草青霏入，瑶圃梅梢玉雪初。", "史藁堆牀殊未已，詩材滿地欲焉如。", "倦投東觀中郎筆，起讀西崑病監書。", "節想清忠侔汲直，詞欽雅麗出唐餘。", "高情炯炯軒裳外，長向金門憶飯蔬。"]'),
('790ae544-5840-43dd-acab-ef2addb9ad67','題屏風墨梅二首  其一','項安世','宋','宋诗','song-poetry','','[]','一段西山雪，中含太古梅。',24,'全唐诗/poet.song.147000.json','["一段西山雪，中含太古梅。", "無香亦無色，免被百花猜。"]'),
('07648fdf-0607-48b7-a5f0-83115d605945','題屏風墨梅二首  其二','項安世','宋','宋诗','song-poetry','','[]','天上和羹事，巢由不忍聞。',24,'全唐诗/poet.song.147000.json','["天上和羹事，巢由不忍聞。", "疎花將瘦影，閒卧一溪雲。"]'),
('1df7ac6d-1dd9-4f7b-b681-6c51f3c3d64a','菱浦謠','項安世','宋','宋诗','song-poetry','','[]','綿綿千丈絲，就此一寸的。',24,'全唐诗/poet.song.147000.json','["綿綿千丈絲，就此一寸的。", "但願的成蓮，莫教蓮蒂薏。"]'),
